import os
import json
import re
import base64
from cryptography.fernet import Fernet, InvalidToken
from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2HMAC
from cryptography.hazmat.primitives import hashes
from dataclasses import dataclass, field
from typing import Any, Optional
from pathlib import Path


@dataclass
class ConfigField:
    name: str
    value_type: type
    required: bool = True
    sensitive: bool = False        # Encrypt this field at rest
    pattern: Optional[str] = None  # Regex validation pattern
    min_val: Optional[float] = None
    max_val: Optional[float] = None
    default: Any = None


class ConfigValidationError(Exception):
    pass


SECURE_CONFIG_SCHEMA = [
    ConfigField('database_host', str, required=True, pattern=r'^[\w.-]+$'),
    ConfigField('database_port', int, required=True, min_val=1, max_val=65535, default=5432),
    ConfigField('database_password', str, required=True, sensitive=True),
    ConfigField('api_key', str, required=True, sensitive=True, pattern=r'^[A-Za-z0-9_-]{20,}$'),
    ConfigField('jwt_secret', str, required=True, sensitive=True),
    ConfigField('debug_mode', bool, required=False, default=False),
    ConfigField('max_connections', int, required=False, min_val=1, max_val=1000, default=100),
    ConfigField('log_level', str, required=False, default='INFO',
                pattern=r'^(DEBUG|INFO|WARNING|ERROR|CRITICAL)$'),
]


class SecureConfigManager:
    """
    Manages application configuration with:
    - Schema-based validation
    - AES-128 encryption of sensitive fields (via Fernet/PBKDF2)
    - Protection against common misconfigurations
    - Safe serialization (never logs sensitive values)
    """

    def __init__(self, schema: list[ConfigField], master_password: Optional[str] = None):
        self.schema = {f.name: f for f in schema}
        self._config: dict[str, Any] = {}
        self._encrypted_fields: set[str] = {f.name for f in schema if f.sensitive}
        self._fernet: Optional[Fernet] = None

        if master_password:
            self._fernet = self._derive_key(master_password)

    def _derive_key(self, password: str, salt: Optional[bytes] = None) -> Fernet:
        if salt is None:
            salt = os.urandom(16)
        self._salt = salt
        kdf = PBKDF2HMAC(
            algorithm=hashes.SHA256(),
            length=32,
            salt=salt,
            iterations=480000,  # OWASP 2023 recommendation
        )
        key = base64.urlsafe_b64encode(kdf.derive(password.encode()))
        return Fernet(key)

    def _validate_field(self, field: ConfigField, value: Any) -> Any:
        if value is None:
            if field.required and field.default is None:
                raise ConfigValidationError(f'Required field missing: {field.name}')
            return field.default

        # Type coercion
        try:
            if field.value_type is bool and isinstance(value, str):
                value = value.lower() in ('true', '1', 'yes')
            elif field.value_type is not type(value):
                value = field.value_type(value)
        except (ValueError, TypeError) as e:
            raise ConfigValidationError(f'Type error for {field.name}: {e}')

        # Range validation
        if field.min_val is not None and value < field.min_val:
            raise ConfigValidationError(
                f'{field.name} value {value} below minimum {field.min_val}'
            )
        if field.max_val is not None and value > field.max_val:
            raise ConfigValidationError(
                f'{field.name} value {value} above maximum {field.max_val}'
            )

        # Pattern validation
        if field.pattern and isinstance(value, str):
            if not re.fullmatch(field.pattern, value):
                raise ConfigValidationError(
                    f'{field.name} value does not match required pattern'
                )

        return value

    def load(self, config_dict: dict[str, Any]) -> None:
        for name, field in self.schema.items():
            raw = config_dict.get(name)
            validated = self._validate_field(field, raw)
            self._config[name] = validated

    def get(self, key: str) -> Any:
        if key not in self._config:
            raise KeyError(f'Unknown config key: {key}')
        return self._config[key]

    def to_safe_dict(self) -> dict[str, Any]:
        result = {}
        for key, value in self._config.items():
            if key in self._encrypted_fields:
                result[key] = '***REDACTED***'
            else:
                result[key] = value
        return result

    def save_encrypted(self, filepath: str) -> None:
        if not self._fernet:
            raise RuntimeError('No master password — cannot encrypt config')
        serializable = {}
        for key, value in self._config.items():
            if key in self._encrypted_fields:
                encrypted = self._fernet.encrypt(str(value).encode()).decode()
                serializable[key] = {'encrypted': True, 'value': encrypted}
            else:
                serializable[key] = {'encrypted': False, 'value': value}
        payload = {'salt': base64.b64encode(self._salt).decode(), 'config': serializable}
        with open(filepath, 'w') as f:
            json.dump(payload, f, indent=2)

    def load_encrypted(self, filepath: str, master_password: str) -> None:
        with open(filepath) as f:
            payload = json.load(f)
        salt = base64.b64decode(payload['salt'])
        self._fernet = self._derive_key(master_password, salt=salt)
        config_dict = {}
        for key, meta in payload['config'].items():
            if meta['encrypted']:
                try:
                    decrypted = self._fernet.decrypt(meta['value'].encode()).decode()
                    config_dict[key] = decrypted
                except InvalidToken:
                    raise ConfigValidationError(f'Decryption failed for {key}: bad password or tampered file')
            else:
                config_dict[key] = meta['value']
        self.load(config_dict)
