import re
import hashlib
import struct
from dataclasses import dataclass, field
from typing import Optional
from enum import Enum


class StringType(Enum):
    TEXT = 'text'
    HEX = 'hex'
    REGEX = 'regex'


@dataclass
class YaraString:
    identifier: str
    pattern: str
    string_type: StringType
    nocase: bool = False
    wide: bool = False      # UTF-16LE encoding
    fullword: bool = False   # Must be a word boundary match
    compiled_pattern: Optional[re.Pattern] = field(default=None, repr=False)

    def compile(self):
        if self.string_type == StringType.TEXT:
            pattern = re.escape(self.pattern)
            if self.fullword:
                pattern = r'(?<![\w])' + pattern + r'(?![\w])'
            flags = re.IGNORECASE if self.nocase else 0
            if self.wide:
                # UTF-16LE: interleave null bytes
                wide_pattern = ''.join(c + '\x00' for c in self.pattern)
                self.compiled_pattern = re.compile(
                    re.escape(wide_pattern).encode('latin-1'), flags | re.DOTALL
                )
            else:
                self.compiled_pattern = re.compile(pattern.encode('latin-1'), flags | re.DOTALL)

        elif self.string_type == StringType.HEX:
            # Parse hex pattern with wildcards: AA BB ?? CC
            hex_regex = ''
            tokens = self.pattern.split()
            for tok in tokens:
                if tok == '??':
                    hex_regex += '.'
                elif '?' in tok:
                    # Partial wildcard like A? or ?B
                    t = tok.replace('?', '.')
                    hex_regex += f'(?:[{t[0]}][{t[1]}])' if '.' not in t[:1] else f'.[{t[1]}]'
                else:
                    byte_val = int(tok, 16)
                    hex_regex += re.escape(bytes([byte_val]).decode('latin-1'))
            self.compiled_pattern = re.compile(hex_regex.encode('latin-1'), re.DOTALL)

        elif self.string_type == StringType.REGEX:
            flags = re.IGNORECASE if self.nocase else 0
            self.compiled_pattern = re.compile(self.pattern.encode('latin-1'), flags | re.DOTALL)

    def find_matches(self, data: bytes) -> list[tuple[int, int]]:
        if self.compiled_pattern is None:
            self.compile()
        matches = []
        for m in self.compiled_pattern.finditer(data):
            matches.append((m.start(), m.end()))
        return matches


@dataclass
class YaraCondition:
    rule_text: str   # e.g., 'any of them', 'all of them', '$a and $b', '2 of ($a, $b, $c)'

    def evaluate(
        self,
        string_matches: dict[str, list[tuple[int, int]]],
        file_size: int,
        file_hash_md5: str,
    ) -> bool:
        rule = self.rule_text.strip().lower()

        def has_match(ident):
            return bool(string_matches.get(ident))

        if rule == 'any of them':
            return any(has_match(k) for k in string_matches)

        if rule == 'all of them':
            return all(has_match(k) for k in string_matches)

        # N of ($a, $b, ...) pattern
        n_of_match = re.match(r'(\d+) of \((.+)\)', rule)
        if n_of_match:
            n = int(n_of_match.group(1))
            idents = [i.strip().lstrip('$') for i in n_of_match.group(2).split(',')]
            matched = sum(1 for i in idents if has_match(i))
            return matched >= n

        # AND/OR combination
        if ' and ' in rule:
            parts = rule.split(' and ')
            return all(has_match(p.strip().lstrip('$')) for p in parts)
        if ' or ' in rule:
            parts = rule.split(' or ')
            return any(has_match(p.strip().lstrip('$')) for p in parts)

        # Single string
        return has_match(rule.lstrip('$'))


@dataclass
class YaraRule:
    name: str
    tags: list[str]
    meta: dict
    strings: list[YaraString]
    condition: YaraCondition
    severity: str = 'MEDIUM'


@dataclass
class ScanResult:
    file_path: str
    file_size: int
    md5: str
    sha256: str
    matched_rules: list[str]
    string_hits: dict[str, list[tuple[int, int]]]
    is_malicious: bool


class MalwareScanner:
    def __init__(self):
        self.rules: list[YaraRule] = []
        self._load_default_rules()

    def _load_default_rules(self):
        self.rules = [
            YaraRule(
                name='Mimikatz_Strings',
                tags=['credential_dumping', 'windows'],
                meta={'description': 'Detects Mimikatz credential dumper strings',
                      'mitre': 'T1003'},
                strings=[
                    YaraString('a', 'mimikatz', StringType.TEXT, nocase=True),
                    YaraString('b', 'sekurlsa::logonpasswords', StringType.TEXT, nocase=True),
                    YaraString('c', 'lsadump::sam', StringType.TEXT, nocase=True),
                ],
                condition=YaraCondition('any of them'),
                severity='CRITICAL'
            ),
            YaraRule(
                name='PowerShell_Encoded_Execution',
                tags=['powershell', 'obfuscation'],
                meta={'description': 'Detects Base64-encoded PowerShell execution'},
                strings=[
                    YaraString('a', r'-[Ee]nc(?:odedCommand)?\s+[A-Za-z0-9+/=]{20,}',
                               StringType.REGEX),
                    YaraString('b', 'powershell', StringType.TEXT, nocase=True),
                ],
                condition=YaraCondition('$a and $b'),
                severity='HIGH'
            ),
            YaraRule(
                name='PE_Header',
                tags=['executable'],
                meta={'description': 'Detects PE executable magic bytes'},
                strings=[
                    YaraString('mz', '4D 5A', StringType.HEX),
                ],
                condition=YaraCondition('$mz'),
                severity='LOW'
            ),
        ]
        for rule in self.rules:
            for s in rule.strings:
                s.compile()

    def scan_bytes(self, data: bytes, filepath: str = '<buffer>') -> ScanResult:
        md5 = hashlib.md5(data).hexdigest()
        sha256 = hashlib.sha256(data).hexdigest()
        matched_rules = []
        all_hits = {}

        for rule in self.rules:
            string_matches = {}
            for s in rule.strings:
                hits = s.find_matches(data)
                if hits:
                    string_matches[s.identifier] = hits

            if rule.condition.evaluate(string_matches, len(data), md5):
                matched_rules.append(rule.name)
                all_hits.update(string_matches)

        return ScanResult(
            file_path=filepath,
            file_size=len(data),
            md5=md5,
            sha256=sha256,
            matched_rules=matched_rules,
            string_hits={k: v[:10] for k, v in all_hits.items()},
            is_malicious=len(matched_rules) > 0,
        )
