import json
import re
import hashlib
from dataclasses import dataclass, field
from typing import Optional
from pathlib import Path
import urllib.request
import urllib.error


@dataclass
class PackageInfo:
    name: str
    version: str
    source: str          # 'requirements.txt', 'pyproject.toml', 'setup.cfg'
    is_pinned: bool      # True if exact version specified (==)
    normalized_name: str = ''

    def __post_init__(self):
        self.normalized_name = re.sub(r'[-_.]+', '-', self.name).lower()


@dataclass
class VulnerabilityInfo:
    cve_id: str
    severity: str
    cvss_score: float
    description: str
    affected_versions: str
    fixed_in: Optional[str]
    published: str


@dataclass
class PackageScanResult:
    package: PackageInfo
    vulnerabilities: list[VulnerabilityInfo]
    is_vulnerable: bool
    has_newer_version: bool
    latest_version: Optional[str]
    supply_chain_issues: list[str]  # e.g., typosquatting risk, unpinned, etc.


PYPI_API_URL = 'https://pypi.org/pypi/{package}/json'
OSV_API_URL = 'https://api.osv.dev/v1/query'

# Known typosquatting patterns (simplified)
TYPOSQUAT_PATTERNS = [
    (r'^reque[s5]ts$', 'requests'),
    (r'^djang[o0]$', 'django'),
    (r'^numpy[s]?$', 'numpy'),
    (r'^pand[a4]s$', 'pandas'),
    (r'^boto[s3]+$', 'boto3'),
]


def parse_requirements(filepath: str) -> list[PackageInfo]:
    packages = []
    source = Path(filepath).name
    with open(filepath) as f:
        for line in f:
            line = line.strip()
            if not line or line.startswith('#') or line.startswith('-'):
                continue
            # Remove inline comments
            line = line.split('#')[0].strip()

            # Parse version spec
            match = re.match(
                r'^([A-Za-z0-9_.-]+)\s*([=!<>~^]+)\s*([A-Za-z0-9._*]+)?',
                line
            )
            if match:
                name = match.group(1)
                op = match.group(2) or ''
                version = match.group(3) or 'unknown'
                is_pinned = op == '=='
                packages.append(PackageInfo(
                    name=name, version=version,
                    source=source, is_pinned=is_pinned
                ))
    return packages


def check_typosquatting(package_name: str) -> Optional[str]:
    normalized = re.sub(r'[-_.]+', '-', package_name).lower()
    for pattern, legitimate in TYPOSQUAT_PATTERNS:
        if re.fullmatch(pattern, normalized) and normalized != legitimate:
            return f'Possible typosquatting of "{legitimate}"'
    return None


def fetch_pypi_info(package_name: str) -> Optional[dict]:
    url = PYPI_API_URL.format(package=package_name)
    try:
        with urllib.request.urlopen(url, timeout=5) as resp:
            return json.load(resp)
    except (urllib.error.URLError, json.JSONDecodeError):
        return None


def query_osv_vulnerabilities(package_name: str, version: str) -> list[dict]:
    payload = json.dumps({
        'version': version,
        'package': {'name': package_name, 'ecosystem': 'PyPI'}
    }).encode()
    req = urllib.request.Request(
        OSV_API_URL,
        data=payload,
        headers={'Content-Type': 'application/json'},
        method='POST'
    )
    try:
        with urllib.request.urlopen(req, timeout=8) as resp:
            data = json.load(resp)
            return data.get('vulns', [])
    except (urllib.error.URLError, json.JSONDecodeError):
        return []


def parse_osv_vuln(vuln: dict) -> VulnerabilityInfo:
    aliases = vuln.get('aliases', [])
    cve = next((a for a in aliases if a.startswith('CVE-')), vuln.get('id', 'UNKNOWN'))
    severity = 'UNKNOWN'
    cvss_score = 0.0
    for sev in vuln.get('severity', []):
        if sev.get('type') == 'CVSS_V3':
            cvss_text = sev.get('score', '')
            try:
                cvss_score = float(cvss_text.split(':')[-1]) if ':' in cvss_text else 0.0
            except ValueError:
                pass
            if cvss_score >= 9.0: severity = 'CRITICAL'
            elif cvss_score >= 7.0: severity = 'HIGH'
            elif cvss_score >= 4.0: severity = 'MEDIUM'
            else: severity = 'LOW'

    affected_ranges = []
    for aff in vuln.get('affected', []):
        for r in aff.get('ranges', []):
            for ev in r.get('events', []):
                if 'introduced' in ev:
                    affected_ranges.append(f'>={ev["introduced"]}')
                if 'fixed' in ev:
                    affected_ranges.append(f'<{ev["fixed"]}')

    fixed_in = None
    for aff in vuln.get('affected', []):
        for r in aff.get('ranges', []):
            for ev in r.get('events', []):
                if 'fixed' in ev:
                    fixed_in = ev['fixed']

    return VulnerabilityInfo(
        cve_id=cve, severity=severity, cvss_score=cvss_score,
        description=vuln.get('summary', '')[:200],
        affected_versions=', '.join(affected_ranges),
        fixed_in=fixed_in,
        published=vuln.get('published', ''),
    )


class SupplyChainScanner:
    def scan_package(self, pkg: PackageInfo) -> PackageScanResult:
        supply_chain_issues = []

        # Typosquatting check
        typo = check_typosquatting(pkg.name)
        if typo:
            supply_chain_issues.append(typo)

        if not pkg.is_pinned:
            supply_chain_issues.append(
                f'Version not pinned (uses "{pkg.version}") - dependency confusion risk'
            )

        # PyPI metadata
        pypi_data = fetch_pypi_info(pkg.name)
        latest_version = None
        has_newer = False
        if pypi_data:
            latest_version = pypi_data.get('info', {}).get('version')
            if latest_version and latest_version != pkg.version:
                has_newer = True

        # OSV vulnerability check
        raw_vulns = query_osv_vulnerabilities(pkg.name, pkg.version)
        vulns = [parse_osv_vuln(v) for v in raw_vulns]

        return PackageScanResult(
            package=pkg,
            vulnerabilities=vulns,
            is_vulnerable=len(vulns) > 0,
            has_newer_version=has_newer,
            latest_version=latest_version,
            supply_chain_issues=supply_chain_issues,
        )

    def scan_requirements(self, filepath: str) -> list[PackageScanResult]:
        packages = parse_requirements(filepath)
        results = []
        for pkg in packages:
            result = self.scan_package(pkg)
            results.append(result)
        results.sort(key=lambda r: (not r.is_vulnerable, not r.supply_chain_issues))
        return results

    def print_report(self, results: list[PackageScanResult]):
        vuln_count = sum(1 for r in results if r.is_vulnerable)
        issue_count = sum(1 for r in results if r.supply_chain_issues)
        print(f'Supply Chain Scan: {len(results)} packages, {vuln_count} vulnerable, {issue_count} supply chain issues')
        for r in results:
            if r.is_vulnerable or r.supply_chain_issues:
                print(f'  {r.package.name}=={r.package.version}')
                for v in r.vulnerabilities:
                    print(f'    [VULN] {v.cve_id} {v.severity} CVSS:{v.cvss_score} - {v.description[:80]}')
                for issue in r.supply_chain_issues:
                    print(f'    [RISK] {issue}')
