class SecurityReActAgent:
    """
    ReAct (Reasoning + Acting) agent for security incident investigation.
    Interleaves LLM reasoning with tool calls to iteratively investigate alerts.
    Pattern:
      Thought: what do I know and what should I check next?
      Action: call a specific investigation tool
      Observation: parse tool result
      ... repeat ...
      Final Answer: TRUE_POSITIVE / FALSE_POSITIVE / ESCALATE
    """

    SYSTEM_PROMPT = """
You are a security analyst AI investigating security alerts using the ReAct pattern.
Available tools: ip_lookup, process_analysis, file_hash_check, log_search

Respond ONLY in this JSON format:
{
  "thought": "<your reasoning>",
  "action": "<tool_name or FINAL_ANSWER>",
  "action_input": {"<param>": "<value>"},
  "final_answer": "<if action is FINAL_ANSWER: TRUE_POSITIVE|FALSE_POSITIVE|ESCALATE>",
  "confidence": <0.0 to 1.0 if FINAL_ANSWER>
}
"""

    def __init__(self, ollama_model: str = 'llama3.2', max_steps: int = 8):
        self.model = ollama_model
        self.max_steps = max_steps
        self.ollama_url = 'http://localhost:11434/api/chat'

    def _call_llm(self, messages: list[dict]) -> str:
        payload = json.dumps({
            'model': self.model,
            'messages': messages,
            'stream': False,
        }).encode()
        req = urllib.request.Request(
            self.ollama_url,
            data=payload,
            headers={'Content-Type': 'application/json'}
        )
        with urllib.request.urlopen(req, timeout=60) as resp:
            data = json.load(resp)
            return data['message']['content']

    def _parse_response(self, text: str) -> dict:
        json_match = re.search(r'\{.*\}', text, re.DOTALL)
        if json_match:
            try:
                return json.loads(json_match.group())
            except json.JSONDecodeError:
                pass
        return {'thought': text, 'action': 'FINAL_ANSWER', 'action_input': {},
                'final_answer': 'ESCALATE', 'confidence': 0.3}

    def _execute_tool(self, action: str, action_input: dict) -> str:
        tool_fn = TOOL_REGISTRY.get(action)
        if not tool_fn:
            return json.dumps({'error': f'Unknown tool: {action}'})
        try:
            result = tool_fn(**action_input)
            return json.dumps(result)
        except Exception as e:
            return json.dumps({'error': str(e)})

    def investigate(self, alert: str, incident_id: str = 'INC-001') -> IncidentInvestigation:
        messages = [
            {'role': 'system', 'content': self.SYSTEM_PROMPT},
            {'role': 'user', 'content': f'Investigate this security alert: {alert}'}
        ]
        steps = []
        final_answer = None
        verdict = None
        confidence = 0.0

        for step_num in range(1, self.max_steps + 1):
            llm_response = self._call_llm(messages)
            parsed = self._parse_response(llm_response)

            action = parsed.get('action', 'FINAL_ANSWER')
            action_input = parsed.get('action_input', {})
            thought = parsed.get('thought', '')

            if action == 'FINAL_ANSWER':
                final_answer = parsed.get('final_answer', 'ESCALATE')
                verdict = final_answer
                confidence = float(parsed.get('confidence', 0.5))
                steps.append(ReActStep(step_num, thought, action, action_input, 'Investigation complete'))
                break

            observation = self._execute_tool(action, action_input)
            steps.append(ReActStep(step_num, thought, action, action_input, observation))

            messages.append({'role': 'assistant', 'content': llm_response})
            messages.append({'role': 'user', 'content': f'Observation: {observation}\nContinue investigation.'})

        return IncidentInvestigation(
            incident_id=incident_id,
            initial_alert=alert,
            steps=steps,
            final_answer=final_answer,
            verdict=verdict,
            confidence=confidence,
            total_steps=len(steps),
            completed=verdict is not None
        )
