import json
from dataclasses import dataclass, field
from typing import Optional
from collections import defaultdict
import hashlib


@dataclass
class KGNode:
    node_id: str
    node_type: str    # 'threat-actor', 'malware', 'attack-pattern', 'tool', 'indicator', 'vulnerability'
    label: str
    properties: dict
    stix_id: Optional[str] = None


@dataclass
class KGEdge:
    edge_id: str
    source_id: str
    target_id: str
    relationship_type: str  # 'uses', 'targets', 'attributed-to', 'indicates', 'mitigates'
    properties: dict = field(default_factory=dict)
    stix_ref_id: Optional[str] = None


@dataclass
class SecurityKnowledgeGraph:
    graph_id: str
    nodes: dict[str, KGNode]
    edges: list[KGEdge]
    n_nodes: int
    n_edges: int
    node_type_counts: dict
    edge_type_counts: dict


def normalize_stix_id(stix_id: str) -> str:
    return stix_id.replace('--', '-').replace(' ', '-').lower()


STIX_TYPE_TO_KG_TYPE = {
    'threat-actor': 'threat-actor',
    'malware': 'malware',
    'attack-pattern': 'attack-pattern',
    'tool': 'tool',
    'indicator': 'indicator',
    'vulnerability': 'vulnerability',
    'campaign': 'campaign',
    'intrusion-set': 'intrusion-set',
    'course-of-action': 'mitigation',
    'identity': 'identity',
    'infrastructure': 'infrastructure',
}


def stix_object_to_node(stix_obj: dict) -> Optional[KGNode]:
    stix_type = stix_obj.get('type', '')
    kg_type = STIX_TYPE_TO_KG_TYPE.get(stix_type)
    if not kg_type:
        return None

    node_id = normalize_stix_id(stix_obj.get('id', ''))
    label = (
        stix_obj.get('name') or
        stix_obj.get('value') or
        stix_obj.get('pattern') or
        stix_id_short(stix_obj.get('id', ''))
    )

    properties = {
        'created': stix_obj.get('created', ''),
        'modified': stix_obj.get('modified', ''),
        'description': stix_obj.get('description', '')[:500],
        'confidence': stix_obj.get('confidence', 0),
        'tlp': _extract_tlp(stix_obj),
    }

    # Type-specific properties
    if stix_type == 'malware':
        properties['malware_types'] = stix_obj.get('malware_types', [])
        properties['is_family'] = stix_obj.get('is_family', False)
    elif stix_type == 'attack-pattern':
        # Extract MITRE ATT&CK technique ID from external references
        for ref in stix_obj.get('external_references', []):
            if ref.get('source_name') == 'mitre-attack':
                properties['mitre_id'] = ref.get('external_id', '')
                break
    elif stix_type == 'vulnerability':
        for ref in stix_obj.get('external_references', []):
            if ref.get('source_name') == 'cve':
                properties['cve_id'] = ref.get('external_id', '')
    elif stix_type == 'indicator':
        properties['indicator_types'] = stix_obj.get('indicator_types', [])
        properties['pattern'] = stix_obj.get('pattern', '')
        properties['valid_from'] = stix_obj.get('valid_from', '')

    return KGNode(
        node_id=node_id,
        node_type=kg_type,
        label=str(label),
        properties=properties,
        stix_id=stix_obj.get('id')
    )


def stix_id_short(stix_id: str) -> str:
    parts = stix_id.split('--')
    return parts[-1][:8] if parts else stix_id[:8]


def _extract_tlp(stix_obj: dict) -> str:
    for marking in stix_obj.get('object_marking_refs', []):
        if 'tlp' in marking.lower():
            if 'red' in marking: return 'TLP:RED'
            if 'amber' in marking: return 'TLP:AMBER'
            if 'green' in marking: return 'TLP:GREEN'
    return 'TLP:WHITE'


class STIXKnowledgeGraphBuilder:
    """
    Builds a security knowledge graph from STIX 2.1 bundles.
    The graph connects threat actors, malware, TTPs, indicators,
    and mitigations for:
    - Attack path analysis
    - Threat actor profiling
    - Automated threat hunting queries
    - IOC correlation
    """

    def __init__(self):
        self.nodes: dict[str, KGNode] = {}
        self.edges: list[KGEdge] = []
        self._edge_counter = 0

    def ingest_bundle(self, stix_bundle: dict) -> dict:
        objects = stix_bundle.get('objects', [])
        added_nodes = 0
        added_edges = 0

        for obj in objects:
            if obj.get('type') == 'relationship':
                edge = self._parse_relationship(obj)
                if edge:
                    self.edges.append(edge)
                    added_edges += 1
            else:
                node = stix_object_to_node(obj)
                if node:
                    self.nodes[node.node_id] = node
                    added_nodes += 1

        return {'added_nodes': added_nodes, 'added_edges': added_edges}

    def _parse_relationship(self, rel: dict) -> Optional[KGEdge]:
        source_ref = normalize_stix_id(rel.get('source_ref', ''))
        target_ref = normalize_stix_id(rel.get('target_ref', ''))
        rel_type = rel.get('relationship_type', 'related-to')

        if not source_ref or not target_ref:
            return None

        self._edge_counter += 1
        return KGEdge(
            edge_id=f'E{self._edge_counter:05d}',
            source_id=source_ref,
            target_id=target_ref,
            relationship_type=rel_type,
            properties={
                'description': rel.get('description', ''),
                'created': rel.get('created', ''),
            },
            stix_ref_id=rel.get('id')
        )

    def query_actor_ttps(self, actor_name: str) -> list[KGNode]:
        actor_nodes = [
            n for n in self.nodes.values()
            if n.node_type == 'threat-actor' and actor_name.lower() in n.label.lower()
        ]
        ttp_nodes = []
        actor_ids = {n.node_id for n in actor_nodes}
        for edge in self.edges:
            if edge.source_id in actor_ids and edge.relationship_type == 'uses':
                target = self.nodes.get(edge.target_id)
                if target and target.node_type == 'attack-pattern':
                    ttp_nodes.append(target)
        return ttp_nodes

    def find_paths(self, source_id: str, target_id: str, max_depth: int = 4) -> list[list[str]]:
        """BFS to find paths between two nodes in the knowledge graph."""
        adj = defaultdict(list)
        for edge in self.edges:
            adj[edge.source_id].append((edge.target_id, edge.relationship_type))

        from collections import deque
        queue = deque([(source_id, [source_id])])
        visited = set()
        paths = []

        while queue and len(paths) < 10:
            node, path = queue.popleft()
            if node == target_id:
                paths.append(path)
                continue
            if len(path) >= max_depth or node in visited:
                continue
            visited.add(node)
            for neighbor, _ in adj[node]:
                if neighbor not in path:
                    queue.append((neighbor, path + [neighbor]))
        return paths

    def build(self) -> SecurityKnowledgeGraph:
        from collections import Counter
        node_types = Counter(n.node_type for n in self.nodes.values())
        edge_types = Counter(e.relationship_type for e in self.edges)
        return SecurityKnowledgeGraph(
            graph_id=f'KG-{len(self.nodes)}-{len(self.edges)}',
            nodes=dict(self.nodes),
            edges=list(self.edges),
            n_nodes=len(self.nodes),
            n_edges=len(self.edges),
            node_type_counts=dict(node_types),
            edge_type_counts=dict(edge_types)
        )
