import numpy as np
from dataclasses import dataclass, field
from typing import Optional
from abc import ABC, abstractmethod


@dataclass
class AlertArm:
    arm_id: str
    threshold: float         # Alert firing threshold
    n_pulls: int = 0
    n_true_positive: int = 0
    n_false_positive: int = 0
    reward_history: list[float] = field(default_factory=list)

    @property
    def precision(self) -> float:
        total = self.n_true_positive + self.n_false_positive
        return self.n_true_positive / total if total > 0 else 0.5

    @property
    def estimated_reward(self) -> float:
        if not self.reward_history:
            return 0.5
        return sum(self.reward_history) / len(self.reward_history)


@dataclass
class ThresholdDecision:
    selected_arm_id: str
    selected_threshold: float
    selection_method: str
    exploration_score: float
    exploitation_score: float


class BanditStrategy(ABC):
    @abstractmethod
    def select_arm(self, arms: list[AlertArm]) -> int:
        pass


class UCB1Strategy(BanditStrategy):
    """
    Upper Confidence Bound (UCB1) strategy.
    Balances exploration (trying underused thresholds) vs
    exploitation (using best-performing thresholds).
    UCB1: select arm with highest mean_reward + sqrt(2*ln(N)/n_i)
    """

    def __init__(self, c: float = 2.0):
        self.c = c
        self.total_pulls = 0

    def select_arm(self, arms: list[AlertArm]) -> int:
        self.total_pulls = sum(a.n_pulls for a in arms)
        # Explore arms with no pulls first
        for i, arm in enumerate(arms):
            if arm.n_pulls == 0:
                return i
        ucb_scores = [
            arm.estimated_reward + self.c * np.sqrt(
                np.log(self.total_pulls) / arm.n_pulls
            )
            for arm in arms
        ]
        return int(np.argmax(ucb_scores))


class ThompsonSamplingStrategy(BanditStrategy):
    """
    Thompson Sampling with Beta distribution.
    Models precision as Beta(alpha=TP+1, beta=FP+1) per arm.
    Samples from posterior and picks arm with highest sample.
    Excellent for sparse reward signals (security alerts can be rare).
    """

    def select_arm(self, arms: list[AlertArm]) -> int:
        samples = [
            np.random.beta(
                arm.n_true_positive + 1,
                arm.n_false_positive + 1
            )
            for arm in arms
        ]
        return int(np.argmax(samples))


class EpsilonGreedyStrategy(BanditStrategy):
    def __init__(self, epsilon: float = 0.1):
        self.epsilon = epsilon

    def select_arm(self, arms: list[AlertArm]) -> int:
        if np.random.random() < self.epsilon:
            return np.random.randint(len(arms))
        return int(np.argmax([a.estimated_reward for a in arms]))


class AdaptiveAlertThresholdBandit:
    """
    Multi-armed bandit for adaptive security alert threshold optimization.
    Problem: Fixed thresholds generate too many false positives (analyst fatigue)
    or too many false negatives (missed threats).
    Solution: Treat each threshold candidate as a bandit arm.
    Reward signal: analyst feedback (TP=1, FP=0, FN=-1).
    The bandit continuously adapts thresholds to maximize detection precision
    while minimizing alert fatigue.
    """

    def __init__(
        self,
        alert_type: str,
        threshold_candidates: list[float],
        strategy: str = 'thompson',
        tp_reward: float = 1.0,
        fp_reward: float = -0.5,
        fn_reward: float = -1.0
    ):
        self.alert_type = alert_type
        self.tp_reward = tp_reward
        self.fp_reward = fp_reward
        self.fn_reward = fn_reward
        self.arms = [
            AlertArm(arm_id=f'threshold_{t:.3f}', threshold=t)
            for t in sorted(threshold_candidates)
        ]

        if strategy == 'ucb1':
            self.strategy = UCB1Strategy()
        elif strategy == 'epsilon_greedy':
            self.strategy = EpsilonGreedyStrategy()
        else:
            self.strategy = ThompsonSamplingStrategy()

        self._history: list[dict] = []
        self._round = 0

    def select_threshold(self) -> ThresholdDecision:
        """Select the next threshold to use for alert firing."""
        arm_idx = self.strategy.select_arm(self.arms)
        selected = self.arms[arm_idx]

        # Compute scores for transparency
        total_n = sum(a.n_pulls for a in self.arms) + 1
        exploit_score = selected.estimated_reward
        explore_score = (
            np.sqrt(np.log(total_n) / (selected.n_pulls + 1))
            if isinstance(self.strategy, UCB1Strategy)
            else 1.0 / (selected.n_pulls + 1)
        )

        return ThresholdDecision(
            selected_arm_id=selected.arm_id,
            selected_threshold=selected.threshold,
            selection_method=type(self.strategy).__name__,
            exploitation_score=round(exploit_score, 4),
            exploration_score=round(explore_score, 4)
        )

    def update(
        self,
        arm_id: str,
        outcome: str  # 'true_positive', 'false_positive', 'false_negative', 'true_negative'
    ):
        """Update bandit arm statistics based on analyst feedback."""
        arm = next((a for a in self.arms if a.arm_id == arm_id), None)
        if arm is None:
            return

        arm.n_pulls += 1
        if outcome == 'true_positive':
            arm.n_true_positive += 1
            reward = self.tp_reward
        elif outcome == 'false_positive':
            arm.n_false_positive += 1
            reward = self.fp_reward
        elif outcome == 'false_negative':
            reward = self.fn_reward
        else:  # true_negative
            reward = 0.0

        arm.reward_history.append(reward)
        if len(arm.reward_history) > 1000:
            arm.reward_history = arm.reward_history[-1000:]

        self._round += 1
        self._history.append({
            'round': self._round, 'arm': arm_id,
            'outcome': outcome, 'reward': reward,
            'arm_precision': arm.precision
        })

    def get_best_threshold(self) -> Optional[float]:
        """Return the current best-performing threshold."""
        pulled_arms = [a for a in self.arms if a.n_pulls > 0]
        if not pulled_arms:
            return None
        best = max(pulled_arms, key=lambda a: a.estimated_reward)
        return best.threshold

    def summary(self) -> dict:
        total_tp = sum(a.n_true_positive for a in self.arms)
        total_fp = sum(a.n_false_positive for a in self.arms)
        return {
            'alert_type': self.alert_type,
            'total_rounds': self._round,
            'n_arms': len(self.arms),
            'best_threshold': self.get_best_threshold(),
            'overall_precision': total_tp / max(total_tp + total_fp, 1),
            'arm_stats': [
                {
                    'arm': a.arm_id, 'threshold': a.threshold,
                    'pulls': a.n_pulls, 'precision': round(a.precision, 4),
                    'estimated_reward': round(a.estimated_reward, 4)
                }
                for a in sorted(self.arms, key=lambda x: x.estimated_reward, reverse=True)
            ]
        }
