class SlidingWindowRateLimiter:
    """Thread-safe sliding window rate limiter."""

    def __init__(self, max_requests: int, window_seconds: int):
        self.max_requests = max_requests
        self.window = window_seconds
        self._windows: dict[str, deque] = defaultdict(deque)
        self._lock = threading.Lock()

    def is_allowed(self, key: str) -> tuple[bool, int]:
        now = time.time()
        cutoff = now - self.window
        with self._lock:
            dq = self._windows[key]
            while dq and dq[0] < cutoff:
                dq.popleft()
            if len(dq) >= self.max_requests:
                return False, len(dq)
            dq.append(now)
            return True, len(dq)


class InputValidator:
    """
    Validates model inputs for security and sanity.
    Catches: adversarial inputs exceeding bounds, NaN/Inf injection,
    shape mismatches, prompt injection in text inputs.
    """
    PROMPT_INJECTION_PATTERNS = [
        'ignore previous instructions',
        'disregard all prior',
        'you are now',
        'system: ',
        '<|im_start|>',
        '[INST]',
    ]

    def validate_numeric(
        self,
        data: Any,
        expected_shape: Optional[tuple] = None,
        value_range: Optional[tuple[float, float]] = None
    ) -> tuple[bool, list[str]]:
        issues = []
        try:
            arr = np.array(data, dtype=np.float32)
        except (ValueError, TypeError) as e:
            return False, [f'Cannot convert to numeric array: {e}']

        if expected_shape and arr.shape != expected_shape:
            issues.append(f'Shape mismatch: got {arr.shape}, expected {expected_shape}')

        if not np.isfinite(arr).all():
            n_nan = int(np.isnan(arr).sum())
            n_inf = int(np.isinf(arr).sum())
            issues.append(f'NaN/Inf detected: {n_nan} NaN, {n_inf} Inf values')

        if value_range:
            lo, hi = value_range
            out_of_range = int(((arr < lo) | (arr > hi)).sum())
            if out_of_range > 0:
                issues.append(f'{out_of_range} values outside [{lo}, {hi}]')

        return len(issues) == 0, issues

    def validate_text(
        self,
        text: str,
        max_length: int = 4096
    ) -> tuple[bool, list[str]]:
        issues = []
        if len(text) > max_length:
            issues.append(f'Text too long: {len(text)} > {max_length}')

        lower = text.lower()
        for pattern in self.PROMPT_INJECTION_PATTERNS:
            if pattern in lower:
                issues.append(f'Prompt injection pattern detected: "{pattern}"')

        # Null bytes / control chars
        if any(ord(c) < 9 or (10 < ord(c) < 32) for c in text):
            issues.append('Control characters detected in text input')

        return len(issues) == 0, issues


@dataclass
class EndpointConfig:
    name: str
    rate_limit_rpm: int
    input_type: str  # 'numeric', 'text', 'json'
    expected_shape: Optional[tuple] = None
    value_range: Optional[tuple[float, float]] = None
    max_text_length: int = 4096
    requires_auth: bool = True


class MLServingGateway:
    """
    Security gateway for ML model serving APIs.
    Sits in front of model inference endpoints and enforces:
    - API key authentication
    - Per-key rate limiting (sliding window)
    - Input validation (shape, range, NaN, prompt injection)
    - Request logging and anomaly alerting
    - Payload size limits
    """
    MAX_PAYLOAD_BYTES = 5 * 1024 * 1024  # 5MB

    def __init__(
        self,
        valid_api_key_hashes: set[str],
        endpoint_configs: list[EndpointConfig]
    ):
        self.valid_key_hashes = valid_api_key_hashes
        self.endpoints: dict[str, EndpointConfig] = {e.name: e for e in endpoint_configs}
        self.rate_limiters: dict[str, SlidingWindowRateLimiter] = {
            e.name: SlidingWindowRateLimiter(e.rate_limit_rpm, 60)
            for e in endpoint_configs
        }
        self.validator = InputValidator()
        self._request_log: list[dict] = []
        self._lock = threading.Lock()

    def _authenticate(self, api_key: str) -> Optional[str]:
        key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        return key_hash if key_hash in self.valid_key_hashes else None

    def _validate_input(
        self,
        endpoint_config: EndpointConfig,
        input_data: Any
    ) -> tuple[bool, list[str]]:
        if endpoint_config.input_type == 'numeric':
            return self.validator.validate_numeric(
                input_data, endpoint_config.expected_shape, endpoint_config.value_range
            )
        elif endpoint_config.input_type == 'text':
            if not isinstance(input_data, str):
                return False, ['Expected string input']
            return self.validator.validate_text(input_data, endpoint_config.max_text_length)
        elif endpoint_config.input_type == 'json':
            if not isinstance(input_data, dict):
                return False, ['Expected JSON object input']
            return True, []
        return True, []

    def process(
        self,
        request: ModelRequest,
        model_fn: Callable,
        api_key: str
    ) -> GatewayResponse:
        start = time.perf_counter()
        warnings = []

        # Auth
        key_hash = self._authenticate(api_key)
        if not key_hash:
            return GatewayResponse(
                request_id=request.request_id, decision=GatewayDecision.INPUT_REJECTED,
                model_output=None, latency_ms=0,
                rejection_reason='Invalid API key', warnings=[]
            )

        # Endpoint check
        endpoint = self.endpoints.get(request.endpoint)
        if not endpoint:
            return GatewayResponse(
                request_id=request.request_id, decision=GatewayDecision.INPUT_REJECTED,
                model_output=None, latency_ms=0,
                rejection_reason=f'Unknown endpoint: {request.endpoint}', warnings=[]
            )

        # Rate limit
        allowed, count = self.rate_limiters[request.endpoint].is_allowed(key_hash)
        if not allowed:
            return GatewayResponse(
                request_id=request.request_id, decision=GatewayDecision.RATE_LIMITED,
                model_output=None, latency_ms=round((time.perf_counter() - start) * 1000, 2),
                rejection_reason=f'Rate limit exceeded: {count} requests in last 60s', warnings=[]
            )

        # Payload size
        if request.payload_size > self.MAX_PAYLOAD_BYTES:
            return GatewayResponse(
                request_id=request.request_id, decision=GatewayDecision.INPUT_REJECTED,
                model_output=None, latency_ms=0,
                rejection_reason=f'Payload too large: {request.payload_size} bytes', warnings=[]
            )

        # Input validation
        valid, issues = self._validate_input(endpoint, request.input_data)
        if not valid:
            return GatewayResponse(
                request_id=request.request_id, decision=GatewayDecision.INPUT_REJECTED,
                model_output=None, latency_ms=round((time.perf_counter() - start) * 1000, 2),
                rejection_reason='; '.join(issues), warnings=[]
            )

        if issues:  # Non-blocking warnings
            warnings.extend(issues)

        # Inference
        try:
            output = model_fn(request.input_data)
        except Exception as e:
            return GatewayResponse(
                request_id=request.request_id, decision=GatewayDecision.INPUT_REJECTED,
                model_output=None, latency_ms=round((time.perf_counter() - start) * 1000, 2),
                rejection_reason=f'Model inference error: {e}', warnings=warnings
            )

        latency = round((time.perf_counter() - start) * 1000, 2)
        with self._lock:
            self._request_log.append({
                'request_id': request.request_id,
                'endpoint': request.endpoint,
                'latency_ms': latency,
                'decision': 'allow',
                'timestamp': datetime.utcnow().isoformat()
            })

        return GatewayResponse(
            request_id=request.request_id,
            decision=GatewayDecision.ALLOW,
            model_output=output,
            latency_ms=latency,
            rejection_reason=None,
            warnings=warnings
        )
