import os
import json
import hashlib
import platform
import subprocess
from dataclasses import dataclass, field
from datetime import datetime
from typing import Optional
from pathlib import Path
from enum import Enum


class ArtifactType(Enum):
    PROCESS_LIST = 'process_list'
    NETWORK_CONNECTIONS = 'network_connections'
    REGISTRY_KEY = 'registry_key'
    FILE_HASH = 'file_hash'
    PREFETCH = 'prefetch'
    EVENT_LOG = 'event_log'
    SCHEDULED_TASK = 'scheduled_task'
    STARTUP_ITEM = 'startup_item'
    USER_ACCOUNT = 'user_account'
    SERVICE = 'service'


@dataclass
class ForensicArtifact:
    artifact_type: ArtifactType
    source: str           # File path, registry key, or tool name
    collected_at: str
    data: dict
    integrity_hash: str   # SHA-256 of JSON-serialized data
    collector_version: str = '1.0'
    errors: list[str] = field(default_factory=list)


@dataclass
class ForensicCollection:
    case_id: str
    hostname: str
    os_info: str
    investigator: str
    collection_start: str
    collection_end: Optional[str]
    artifacts: list[ForensicArtifact]
    chain_of_custody_hash: str  # Hash of all artifact hashes
    total_artifacts: int


def compute_artifact_hash(data: dict) -> str:
    return hashlib.sha256(json.dumps(data, sort_keys=True, default=str).encode()).hexdigest()


class WindowsForensicCollector:
    """
    Forensic artifact collector for Windows security investigations.
    Collects: running processes, network connections, startup items,
    scheduled tasks, user accounts, services, and recent event logs.
    All artifacts are integrity-hashed for chain of custody.
    Note: Requires appropriate privileges for some collections.
    """

    COLLECTOR_VERSION = '1.0'
    IS_WINDOWS = platform.system() == 'Windows'

    def _run_cmd(self, cmd: list[str]) -> tuple[str, Optional[str]]:
        try:
            result = subprocess.run(
                cmd, capture_output=True, text=True, timeout=30
            )
            return result.stdout, result.stderr or None
        except subprocess.TimeoutExpired:
            return '', f'Command timed out: {cmd}'
        except FileNotFoundError as e:
            return '', f'Command not found: {e}'
        except Exception as e:
            return '', str(e)

    def collect_process_list(self) -> ForensicArtifact:
        errors = []
        data: dict = {'processes': []}

        if self.IS_WINDOWS:
            out, err = self._run_cmd(['tasklist', '/fo', 'csv', '/v'])
            if err:
                errors.append(err)
            else:
                lines = out.strip().split('\n')
                headers = lines[0].replace('"', '').split(',')
                for line in lines[1:]:
                    if line.strip():
                        values = line.replace('"', '').split(',')
                        if len(values) == len(headers):
                            data['processes'].append(dict(zip(headers, values)))
        else:
            # Linux/Mac fallback for testing
            out, err = self._run_cmd(['ps', 'aux'])
            if err:
                errors.append(err)
            else:
                for line in out.strip().split('\n')[1:]:
                    parts = line.split(None, 10)
                    if len(parts) >= 11:
                        data['processes'].append({
                            'USER': parts[0], 'PID': parts[1],
                            'CPU': parts[2], 'MEM': parts[3],
                            'COMMAND': parts[10]
                        })

        return ForensicArtifact(
            artifact_type=ArtifactType.PROCESS_LIST,
            source='tasklist' if self.IS_WINDOWS else 'ps',
            collected_at=datetime.utcnow().isoformat(),
            data=data,
            integrity_hash=compute_artifact_hash(data),
            errors=errors
        )

    def collect_network_connections(self) -> ForensicArtifact:
        errors = []
        data: dict = {'connections': []}

        cmd = ['netstat', '-ano'] if self.IS_WINDOWS else ['netstat', '-tlnp']
        out, err = self._run_cmd(cmd)
        if err:
            errors.append(err)
        else:
            for line in out.strip().split('\n'):
                line = line.strip()
                if not line or line.startswith('Active') or line.startswith('Proto'):
                    continue
                parts = line.split()
                if len(parts) >= 4:
                    data['connections'].append({
                        'protocol': parts[0],
                        'local_address': parts[1],
                        'foreign_address': parts[2],
                        'state': parts[3] if len(parts) > 3 else '',
                        'pid': parts[4] if len(parts) > 4 else ''
                    })

        return ForensicArtifact(
            artifact_type=ArtifactType.NETWORK_CONNECTIONS,
            source='netstat',
            collected_at=datetime.utcnow().isoformat(),
            data=data,
            integrity_hash=compute_artifact_hash(data),
            errors=errors
        )

    def collect_scheduled_tasks(self) -> ForensicArtifact:
        errors = []
        data: dict = {'tasks': []}

        if self.IS_WINDOWS:
            out, err = self._run_cmd(['schtasks', '/query', '/fo', 'csv', '/v'])
            if err:
                errors.append(err)
            else:
                lines = out.strip().split('\n')
                if lines:
                    headers = lines[0].replace('"', '').split(',')
                    for line in lines[1:]:
                        if line.strip():
                            values = line.replace('"', '').split(',')
                            if len(values) >= len(headers):
                                task = dict(zip(headers, values[:len(headers)]))
                                data['tasks'].append(task)
        else:
            out, err = self._run_cmd(['crontab', '-l'])
            data['tasks'] = [{'line': l} for l in out.strip().split('\n') if l and not l.startswith('#')]
            if err:
                errors.append(err)

        return ForensicArtifact(
            artifact_type=ArtifactType.SCHEDULED_TASK,
            source='schtasks',
            collected_at=datetime.utcnow().isoformat(),
            data=data,
            integrity_hash=compute_artifact_hash(data),
            errors=errors
        )

    def collect_services(self) -> ForensicArtifact:
        errors = []
        data: dict = {'services': []}

        if self.IS_WINDOWS:
            out, err = self._run_cmd(['sc', 'query', 'type=', 'all', 'state=', 'all'])
            if err:
                errors.append(err)
            else:
                current: dict = {}
                for line in out.strip().split('\n'):
                    line = line.strip()
                    if line.startswith('SERVICE_NAME:'):
                        if current:
                            data['services'].append(current)
                        current = {'name': line.split(':', 1)[1].strip()}
                    elif ':' in line and current:
                        k, v = line.split(':', 1)
                        current[k.strip().lower()] = v.strip()
                if current:
                    data['services'].append(current)
        else:
            out, err = self._run_cmd(['systemctl', 'list-units', '--type=service', '--all', '--no-pager'])
            for line in out.strip().split('\n')[1:]:
                parts = line.split(None, 4)
                if len(parts) >= 4:
                    data['services'].append({'unit': parts[0], 'load': parts[1], 'active': parts[2], 'sub': parts[3]})

        return ForensicArtifact(
            artifact_type=ArtifactType.SERVICE,
            source='sc query' if self.IS_WINDOWS else 'systemctl',
            collected_at=datetime.utcnow().isoformat(),
            data=data,
            integrity_hash=compute_artifact_hash(data),
            errors=errors
        )

    def collect_file_hashes(
        self,
        paths: list[str]
    ) -> ForensicArtifact:
        data: dict = {'files': []}
        errors = []

        for path_str in paths:
            path = Path(path_str)
            if not path.exists():
                errors.append(f'File not found: {path_str}')
                continue
            try:
                stat = path.stat()
                sha256 = hashlib.sha256(path.read_bytes()).hexdigest()
                data['files'].append({
                    'path': str(path),
                    'sha256': sha256,
                    'size': stat.st_size,
                    'modified': datetime.fromtimestamp(stat.st_mtime).isoformat(),
                    'created': datetime.fromtimestamp(stat.st_ctime).isoformat()
                })
            except (PermissionError, OSError) as e:
                errors.append(f'Cannot hash {path_str}: {e}')

        return ForensicArtifact(
            artifact_type=ArtifactType.FILE_HASH,
            source='filesystem',
            collected_at=datetime.utcnow().isoformat(),
            data=data,
            integrity_hash=compute_artifact_hash(data),
            errors=errors
        )

    def collect_all(
        self,
        case_id: str,
        investigator: str,
        file_paths_to_hash: Optional[list[str]] = None
    ) -> ForensicCollection:
        start = datetime.utcnow().isoformat()
        artifacts = [
            self.collect_process_list(),
            self.collect_network_connections(),
            self.collect_scheduled_tasks(),
            self.collect_services(),
        ]
        if file_paths_to_hash:
            artifacts.append(self.collect_file_hashes(file_paths_to_hash))

        chain_input = ''.join(a.integrity_hash for a in artifacts)
        chain_hash = hashlib.sha256(chain_input.encode()).hexdigest()

        return ForensicCollection(
            case_id=case_id,
            hostname=platform.node(),
            os_info=platform.platform(),
            investigator=investigator,
            collection_start=start,
            collection_end=datetime.utcnow().isoformat(),
            artifacts=artifacts,
            chain_of_custody_hash=chain_hash,
            total_artifacts=len(artifacts)
        )
