import numpy as np
from dataclasses import dataclass, field
from datetime import datetime
from typing import Optional
from collections import defaultdict


@dataclass
class NetworkConnection:
    conn_id: str
    timestamp: datetime
    src_host: str
    dst_host: str
    protocol: str
    dst_port: int
    bytes_sent: int
    success: bool
    username: Optional[str] = None


@dataclass
class LateralMovementPath:
    path: list[str]            # Ordered list of hosts
    connections: list[NetworkConnection]
    total_hops: int
    time_span_minutes: float
    involved_users: list[str]
    risk_score: float
    mitre_technique: str
    description: str


class LateralMovementDetector:
    """
    Graph-based lateral movement detector.
    Builds a directed graph of host-to-host connections.
    Detects suspicious traversal chains:
    - Sequential connections from a single source across multiple internal hosts
    - SMB/RDP/WMI connections between workstations (unusual)
    - High fan-out from a single host (potential worm)
    - Shortest-path anomalies (unexpected routes between hosts)
    """

    ADMIN_PROTOCOLS = {22, 3389, 445, 5985, 5986, 135}  # SSH, RDP, SMB, WinRM, RPC
    WORKSTATION_RANGE = '192.168.'
    SERVER_RANGE = '10.'

    def __init__(self, internal_subnets: Optional[list[str]] = None):
        self.internal_subnets = internal_subnets or ['192.168.', '10.', '172.16.']
        self._adjacency: dict[str, dict[str, list[NetworkConnection]]] = defaultdict(
            lambda: defaultdict(list)
        )
        self._host_connections: dict[str, list[NetworkConnection]] = defaultdict(list)

    def _is_internal(self, host: str) -> bool:
        return any(host.startswith(s) for s in self.internal_subnets)

    def add_connection(self, conn: NetworkConnection):
        if conn.success and self._is_internal(conn.src_host) and self._is_internal(conn.dst_host):
            self._adjacency[conn.src_host][conn.dst_host].append(conn)
            self._host_connections[conn.src_host].append(conn)

    def _find_chains(
        self, start_host: str, max_depth: int = 5, min_hops: int = 3
    ) -> list[list[str]]:
        """DFS to find all paths of at least min_hops from start_host."""
        chains = []
        stack = [(start_host, [start_host])]
        while stack:
            node, path = stack.pop()
            if len(path) >= min_hops:
                chains.append(path[:])
            if len(path) < max_depth:
                for neighbor in self._adjacency.get(node, {}):
                    if neighbor not in path:  # No cycles
                        stack.append((neighbor, path + [neighbor]))
        return chains

    def _score_chain(
        self, path: list[str], conns: list[NetworkConnection]
    ) -> float:
        score = len(path) * 2.0
        admin_conns = sum(1 for c in conns if c.dst_port in self.ADMIN_PROTOCOLS)
        score += admin_conns * 1.5
        users = {c.username for c in conns if c.username}
        if len(users) > 1:
            score += 3.0  # Multiple users in chain = suspicious
        ws_to_ws = sum(
            1 for c in conns
            if c.src_host.startswith(self.WORKSTATION_RANGE)
            and c.dst_host.startswith(self.WORKSTATION_RANGE)
        )
        score += ws_to_ws * 2.0  # Workstation-to-workstation = very suspicious
        return round(score, 2)

    def _get_chain_conns(
        self, path: list[str]
    ) -> list[NetworkConnection]:
        conns = []
        for i in range(len(path) - 1):
            src, dst = path[i], path[i+1]
            conns.extend(self._adjacency.get(src, {}).get(dst, []))
        return sorted(conns, key=lambda c: c.timestamp)

    def detect_high_fanout(
        self, threshold: int = 10
    ) -> list[dict]:
        """Hosts connecting to many unique internal destinations (worm pattern)."""
        alerts = []
        for host, neighbors in self._adjacency.items():
            n_unique = len(neighbors)
            if n_unique >= threshold:
                alerts.append({
                    'host': host,
                    'unique_destinations': n_unique,
                    'risk': 'HIGH',
                    'mitre': 'T1570',
                    'description': f'{host} connected to {n_unique} unique internal hosts — possible worm/scanner'
                })
        return alerts

    def detect_lateral_movement(
        self, min_hops: int = 3, score_threshold: float = 6.0
    ) -> list[LateralMovementPath]:
        all_paths = []
        seen_paths = set()
        for start_host in self._adjacency:
            chains = self._find_chains(start_host, min_hops=min_hops)
            for path in chains:
                path_key = '->'.join(path)
                if path_key in seen_paths:
                    continue
                seen_paths.add(path_key)
                conns = self._get_chain_conns(path)
                if not conns:
                    continue
                score = self._score_chain(path, conns)
                if score < score_threshold:
                    continue
                users = list({c.username for c in conns if c.username})
                admin_ports = [c.dst_port for c in conns if c.dst_port in self.ADMIN_PROTOCOLS]
                mitre = 'T1021.002' if 445 in admin_ports else 'T1021.001' if 3389 in admin_ports else 'T1021'
                span = (conns[-1].timestamp - conns[0].timestamp).total_seconds() / 60
                all_paths.append(LateralMovementPath(
                    path=path,
                    connections=conns,
                    total_hops=len(path) - 1,
                    time_span_minutes=round(span, 2),
                    involved_users=users,
                    risk_score=score,
                    mitre_technique=mitre,
                    description=(
                        f'Lateral movement: {" -> ".join(path)} '
                        f'({len(path)-1} hops, {span:.1f}min, score={score})'
                    )
                ))
        return sorted(all_paths, key=lambda p: p.risk_score, reverse=True)
