import json
import hashlib
from dataclasses import dataclass, field
from datetime import datetime
from typing import Optional, Callable
from enum import Enum


class ControlStatus(Enum):
    PASS = 'PASS'
    FAIL = 'FAIL'
    PARTIAL = 'PARTIAL'
    NOT_APPLICABLE = 'N/A'
    NOT_TESTED = 'NOT_TESTED'
    ERROR = 'ERROR'


@dataclass
class ControlTest:
    control_id: str       # e.g. 'AC-2', 'AU-6', 'SI-3'
    family: str           # e.g. 'Access Control', 'Audit'
    title: str
    description: str
    test_fn: Callable     # Returns (ControlStatus, str, dict)
    priority: str         # 'P1' through 'P3'
    baseline: list[str]   # ['LOW', 'MODERATE', 'HIGH']


@dataclass
class ControlTestResult:
    control_id: str
    family: str
    title: str
    status: ControlStatus
    findings: str
    evidence: dict
    tested_at: str
    remediation: Optional[str]
    priority: str


@dataclass
class ComplianceReport:
    framework: str
    baseline: str
    assessed_at: str
    total_controls: int
    passed: int
    failed: int
    partial: int
    not_applicable: int
    pass_rate: float
    results: list[ControlTestResult]
    high_priority_failures: list[str]
    overall_status: str


# --- Simulated control test implementations ---
def test_ac2_account_management(env: dict) -> tuple[ControlStatus, str, dict]:
    """AC-2: Account Management — check for disabled account cleanup."""
    stale_accounts = env.get('stale_accounts', [])
    orphan_accounts = env.get('orphan_accounts', [])
    if stale_accounts or orphan_accounts:
        return ControlStatus.FAIL, (
            f'{len(stale_accounts)} stale accounts, '
            f'{len(orphan_accounts)} orphaned accounts found.'
        ), {'stale': stale_accounts, 'orphan': orphan_accounts}
    return ControlStatus.PASS, 'No stale or orphaned accounts found.', {}


def test_ac3_access_enforcement(env: dict) -> tuple[ControlStatus, str, dict]:
    """AC-3: Access Enforcement — RBAC implementation check."""
    has_rbac = env.get('rbac_enabled', False)
    has_mfa = env.get('mfa_enforced', False)
    if not has_rbac:
        return ControlStatus.FAIL, 'RBAC not implemented.', {'rbac_enabled': False}
    if not has_mfa:
        return ControlStatus.PARTIAL, 'RBAC implemented but MFA not enforced.', {'mfa_enforced': False}
    return ControlStatus.PASS, 'RBAC and MFA enforced.', {'rbac': True, 'mfa': True}


def test_au6_audit_review(env: dict) -> tuple[ControlStatus, str, dict]:
    """AU-6: Audit Review, Analysis, Reporting."""
    has_siem = env.get('siem_deployed', False)
    log_retention_days = env.get('log_retention_days', 0)
    review_frequency = env.get('audit_review_frequency', 'none')
    issues = []
    if not has_siem:
        issues.append('No SIEM deployed')
    if log_retention_days < 90:
        issues.append(f'Log retention {log_retention_days} days < 90 days minimum')
    if review_frequency not in ('daily', 'weekly'):
        issues.append(f'Audit reviews not frequent enough: {review_frequency}')
    if issues:
        return ControlStatus.FAIL, '; '.join(issues), {'issues': issues}
    return ControlStatus.PASS, 'Audit logging and review controls in place.', {}


def test_si3_malware_protection(env: dict) -> tuple[ControlStatus, str, dict]:
    """SI-3: Malware Protection."""
    edr_deployed = env.get('edr_deployed', False)
    av_signatures_updated = env.get('av_signatures_current', False)
    scanning_frequency = env.get('malware_scan_frequency', 'none')
    issues = []
    if not edr_deployed:
        issues.append('EDR/AV not deployed on all endpoints')
    if not av_signatures_updated:
        issues.append('AV signatures not current')
    if scanning_frequency == 'none':
        issues.append('No scheduled malware scanning')
    if issues:
        return (ControlStatus.PARTIAL if edr_deployed else ControlStatus.FAIL,
                '; '.join(issues), {'issues': issues})
    return ControlStatus.PASS, 'Malware protection controls operational.', {}


def test_sc8_transmission_confidentiality(env: dict) -> tuple[ControlStatus, str, dict]:
    """SC-8: Transmission Confidentiality and Integrity."""
    tls_enforced = env.get('tls_enforced', False)
    weak_protocols = env.get('weak_tls_protocols', [])
    if not tls_enforced:
        return ControlStatus.FAIL, 'TLS not enforced for data in transit.', {}
    if weak_protocols:
        return ControlStatus.PARTIAL, (
            f'TLS enforced but weak protocols enabled: {weak_protocols}'
        ), {'weak_protocols': weak_protocols}
    return ControlStatus.PASS, 'TLS 1.2+ enforced, no weak protocols.', {}


def test_ia5_authenticator_management(env: dict) -> tuple[ControlStatus, str, dict]:
    """IA-5: Authenticator Management — password policy check."""
    min_length = env.get('password_min_length', 0)
    complexity = env.get('password_complexity', False)
    max_age_days = env.get('password_max_age_days', 9999)
    history_count = env.get('password_history_count', 0)
    issues = []
    if min_length < 12:
        issues.append(f'Min password length {min_length} < 12')
    if not complexity:
        issues.append('Password complexity not enforced')
    if max_age_days > 365:
        issues.append(f'Password max age {max_age_days} days too long')
    if history_count < 12:
        issues.append(f'Password history {history_count} < 12')
    if issues:
        return ControlStatus.FAIL, '; '.join(issues), {'issues': issues}
    return ControlStatus.PASS, 'Password policy meets NIST 800-53 requirements.', {}


NIST_800_53_TESTS = [
    ControlTest('AC-2', 'Access Control', 'Account Management',
                'Manage information system accounts', test_ac2_account_management, 'P1', ['LOW', 'MODERATE', 'HIGH']),
    ControlTest('AC-3', 'Access Control', 'Access Enforcement',
                'Enforce RBAC and least privilege', test_ac3_access_enforcement, 'P1', ['LOW', 'MODERATE', 'HIGH']),
    ControlTest('AU-6', 'Audit', 'Audit Review and Analysis',
                'Review and analyze audit records', test_au6_audit_review, 'P1', ['MODERATE', 'HIGH']),
    ControlTest('SI-3', 'System Integrity', 'Malware Protection',
                'Detect and eradicate malware', test_si3_malware_protection, 'P1', ['LOW', 'MODERATE', 'HIGH']),
    ControlTest('SC-8', 'System Communications', 'Transmission Confidentiality',
                'Encrypt data in transit', test_sc8_transmission_confidentiality, 'P1', ['MODERATE', 'HIGH']),
    ControlTest('IA-5', 'Identification & Auth', 'Authenticator Management',
                'Enforce password policies', test_ia5_authenticator_management, 'P1', ['LOW', 'MODERATE', 'HIGH']),
]


class NIST80053ComplianceTester:
    """
    Automated NIST 800-53 security control testing framework.
    Runs a battery of control tests against an environment configuration
    and produces a compliance report with pass/fail status and remediation.
    """

    REMEDIATION_MAP = {
        'AC-2': 'Implement automated account lifecycle management (provisioning, deprovisioning).',
        'AC-3': 'Deploy RBAC and enforce MFA for all privileged and remote access.',
        'AU-6': 'Deploy SIEM with 90+ day retention and automated daily review workflows.',
        'SI-3': 'Deploy EDR on all endpoints; enforce real-time scanning and daily signature updates.',
        'SC-8': 'Enforce TLS 1.2+; disable SSLv3, TLS 1.0, TLS 1.1 on all services.',
        'IA-5': 'Enforce 12+ char passwords, complexity, 90-day rotation, 12-password history.',
    }

    def run(
        self,
        environment: dict,
        baseline: str = 'MODERATE',
        test_ids: Optional[list[str]] = None
    ) -> ComplianceReport:
        results = []
        for test in NIST_800_53_TESTS:
            if test_ids and test.control_id not in test_ids:
                continue
            if baseline not in test.baseline:
                results.append(ControlTestResult(
                    control_id=test.control_id, family=test.family, title=test.title,
                    status=ControlStatus.NOT_APPLICABLE, findings='Not required for this baseline.',
                    evidence={}, tested_at=datetime.utcnow().isoformat(),
                    remediation=None, priority=test.priority
                ))
                continue
            try:
                status, findings, evidence = test.test_fn(environment)
            except Exception as e:
                status, findings, evidence = ControlStatus.ERROR, str(e), {}
            results.append(ControlTestResult(
                control_id=test.control_id, family=test.family, title=test.title,
                status=status, findings=findings, evidence=evidence,
                tested_at=datetime.utcnow().isoformat(),
                remediation=self.REMEDIATION_MAP.get(test.control_id) if status != ControlStatus.PASS else None,
                priority=test.priority
            ))
        passed = sum(1 for r in results if r.status == ControlStatus.PASS)
        failed = sum(1 for r in results if r.status == ControlStatus.FAIL)
        partial = sum(1 for r in results if r.status == ControlStatus.PARTIAL)
        na = sum(1 for r in results if r.status == ControlStatus.NOT_APPLICABLE)
        tested = len(results) - na
        pass_rate = round(passed / max(tested, 1), 4)
        high_prio_failures = [
            r.control_id for r in results
            if r.status == ControlStatus.FAIL and r.priority == 'P1'
        ]
        overall = 'COMPLIANT' if failed == 0 and partial == 0 else 'NON-COMPLIANT'
        return ComplianceReport(
            framework='NIST SP 800-53 Rev 5',
            baseline=baseline,
            assessed_at=datetime.utcnow().isoformat(),
            total_controls=len(results),
            passed=passed, failed=failed, partial=partial, not_applicable=na,
            pass_rate=pass_rate, results=results,
            high_priority_failures=high_prio_failures,
            overall_status=overall
        )
