import numpy as np
from dataclasses import dataclass
from typing import Optional
from enum import Enum


class ColumnType(Enum):
    NUMERIC = 'numeric'
    CATEGORICAL = 'categorical'
    BINARY = 'binary'
    TIMESTAMP = 'timestamp'


@dataclass
class ColumnSpec:
    name: str
    col_type: ColumnType
    sensitivity: float = 1.0   # L1 sensitivity for numeric columns
    categories: Optional[list] = None  # For categorical columns
    min_val: Optional[float] = None
    max_val: Optional[float] = None


@dataclass
class SyntheticDataResult:
    data: list[dict]
    n_original: int
    n_synthetic: int
    epsilon_used: float
    delta_used: float
    per_column_noise: dict
    utility_report: dict


class DPSyntheticLogGenerator:
    """
    Differentially private synthetic data generator for security logs.
    Approach:
    1. Compute DP histograms/marginals for categorical columns using Laplace mechanism
    2. Compute DP mean/std for numeric columns using Laplace mechanism
    3. Sample synthetic records from the DP-noised distributions
    4. Uses basic composition for epsilon budget across columns
    """

    def __init__(
        self,
        epsilon: float = 1.0,
        delta: float = 1e-5,
        random_state: int = 42
    ):
        if epsilon <= 0:
            raise ValueError('Epsilon must be positive')
        self.epsilon = epsilon
        self.delta = delta
        self._rng = np.random.default_rng(random_state)

    def _laplace_noise(self, sensitivity: float, epsilon_per_col: float) -> float:
        scale = sensitivity / epsilon_per_col
        return float(self._rng.laplace(0, scale))

    def _dp_numeric_stats(
        self, values: np.ndarray, spec: ColumnSpec, epsilon_col: float
    ) -> tuple[float, float]:
        """Compute DP mean and std for a numeric column."""
        n = len(values)
        true_mean = float(np.mean(values))
        true_std = float(np.std(values))
        sensitivity = (spec.max_val - spec.min_val) / n if spec.max_val and spec.min_val else spec.sensitivity
        dp_mean = true_mean + self._laplace_noise(sensitivity, epsilon_col / 2)
        dp_std = max(0.01, true_std + self._laplace_noise(sensitivity, epsilon_col / 2))
        if spec.min_val is not None:
            dp_mean = max(spec.min_val, dp_mean)
        if spec.max_val is not None:
            dp_mean = min(spec.max_val, dp_mean)
        return dp_mean, dp_std

    def _dp_histogram(
        self, values: list, categories: list, epsilon_col: float
    ) -> dict[str, float]:
        """Compute DP histogram for a categorical column."""
        n = len(values)
        counts = {str(c): 0 for c in categories}
        for v in values:
            key = str(v)
            if key in counts:
                counts[key] += 1
        # Add Laplace noise to each bin (sensitivity=1 per bin)
        noisy = {}
        for cat, cnt in counts.items():
            noisy_cnt = cnt + self._laplace_noise(1.0, epsilon_col / len(categories))
            noisy[cat] = max(0.0, noisy_cnt)
        total = sum(noisy.values()) or 1.0
        return {k: v / total for k, v in noisy.items()}

    def fit_and_generate(
        self,
        records: list[dict],
        column_specs: list[ColumnSpec],
        n_synthetic: Optional[int] = None
    ) -> SyntheticDataResult:
        if not records:
            raise ValueError('No input records')

        n_orig = len(records)
        n_synth = n_synthetic or n_orig
        epsilon_per_col = self.epsilon / len(column_specs)
        per_col_noise = {}
        col_distributions: dict[str, dict] = {}

        for spec in column_specs:
            col_vals = [r.get(spec.name) for r in records if r.get(spec.name) is not None]
            if spec.col_type == ColumnType.NUMERIC:
                arr = np.array([float(v) for v in col_vals])
                dp_mean, dp_std = self._dp_numeric_stats(arr, spec, epsilon_per_col)
                col_distributions[spec.name] = {'type': 'normal', 'mean': dp_mean, 'std': dp_std,
                                                 'min': spec.min_val, 'max': spec.max_val}
                per_col_noise[spec.name] = {
                    'mechanism': 'Laplace',
                    'epsilon': round(epsilon_per_col, 6),
                    'dp_mean': round(dp_mean, 4),
                    'dp_std': round(dp_std, 4)
                }
            elif spec.col_type == ColumnType.BINARY:
                pos_rate = sum(1 for v in col_vals if v) / max(len(col_vals), 1)
                noisy_rate = pos_rate + self._laplace_noise(1.0 / n_orig, epsilon_per_col)
                noisy_rate = max(0.0, min(1.0, noisy_rate))
                col_distributions[spec.name] = {'type': 'bernoulli', 'p': noisy_rate}
                per_col_noise[spec.name] = {'mechanism': 'Laplace', 'epsilon': round(epsilon_per_col, 6), 'dp_rate': round(noisy_rate, 4)}
            elif spec.col_type == ColumnType.CATEGORICAL:
                cats = spec.categories or list({str(v) for v in col_vals})
                dp_hist = self._dp_histogram([str(v) for v in col_vals], cats, epsilon_per_col)
                col_distributions[spec.name] = {'type': 'categorical', 'probs': dp_hist}
                per_col_noise[spec.name] = {'mechanism': 'Laplace', 'epsilon': round(epsilon_per_col, 6),
                                             'n_categories': len(cats)}
            elif spec.col_type == ColumnType.TIMESTAMP:
                # Treat as numeric epoch seconds
                arr = np.array([float(v) for v in col_vals])
                dp_mean, dp_std = self._dp_numeric_stats(arr, spec, epsilon_per_col)
                col_distributions[spec.name] = {'type': 'normal', 'mean': dp_mean, 'std': dp_std,
                                                 'min': spec.min_val, 'max': spec.max_val}
                per_col_noise[spec.name] = {'mechanism': 'Laplace', 'epsilon': round(epsilon_per_col, 6)}

        # Sample synthetic records
        synthetic = []
        for _ in range(n_synth):
            record = {}
            for spec in column_specs:
                dist = col_distributions[spec.name]
                if dist['type'] == 'normal':
                    val = float(self._rng.normal(dist['mean'], dist['std']))
                    if dist.get('min') is not None:
                        val = max(dist['min'], val)
                    if dist.get('max') is not None:
                        val = min(dist['max'], val)
                    record[spec.name] = round(val, 4)
                elif dist['type'] == 'bernoulli':
                    record[spec.name] = bool(self._rng.random() < dist['p'])
                elif dist['type'] == 'categorical':
                    cats = list(dist['probs'].keys())
                    probs = list(dist['probs'].values())
                    total = sum(probs)
                    probs = [p / total for p in probs]
                    record[spec.name] = str(self._rng.choice(cats, p=probs))
            synthetic.append(record)

        # Utility report: compare marginals (no privacy cost, post-hoc)
        utility = {}
        for spec in column_specs:
            orig_vals = [r.get(spec.name) for r in records if r.get(spec.name) is not None]
            syn_vals = [r.get(spec.name) for r in synthetic if r.get(spec.name) is not None]
            if spec.col_type in (ColumnType.NUMERIC, ColumnType.TIMESTAMP):
                orig_mean = float(np.mean([float(v) for v in orig_vals]))
                syn_mean = float(np.mean([float(v) for v in syn_vals]))
                utility[spec.name] = {'mean_error': round(abs(orig_mean - syn_mean), 4)}
            elif spec.col_type == ColumnType.BINARY:
                orig_rate = sum(1 for v in orig_vals if v) / max(len(orig_vals), 1)
                syn_rate = sum(1 for v in syn_vals if v) / max(len(syn_vals), 1)
                utility[spec.name] = {'rate_error': round(abs(orig_rate - syn_rate), 4)}

        return SyntheticDataResult(
            data=synthetic,
            n_original=n_orig,
            n_synthetic=n_synth,
            epsilon_used=self.epsilon,
            delta_used=self.delta,
            per_column_noise=per_col_noise,
            utility_report=utility
        )
