import os
import hmac
import hashlib
import base64
import json
import time
from dataclasses import dataclass, field
from typing import Optional
from enum import Enum
from cryptography.hazmat.primitives.asymmetric import rsa, ec, padding
from cryptography.hazmat.primitives import hashes, serialization
from cryptography.hazmat.primitives.ciphers.aead import AESGCM
from cryptography.hazmat.backends import default_backend


class KeyType(Enum):
    AES_256 = 'AES-256'
    RSA_2048 = 'RSA-2048'
    RSA_4096 = 'RSA-4096'
    EC_P256 = 'EC-P256'
    EC_P384 = 'EC-P384'
    HMAC_SHA256 = 'HMAC-SHA256'


class KeyUsage(Enum):
    ENCRYPT_DECRYPT = 'encrypt_decrypt'
    SIGN_VERIFY = 'sign_verify'
    KEY_WRAP = 'key_wrap'
    DERIVE = 'derive'


class HSMError(Exception):
    pass


@dataclass
class KeyMetadata:
    key_id: str
    key_type: KeyType
    key_usage: KeyUsage
    label: str
    created_at: float
    expires_at: Optional[float]
    extractable: bool
    active: bool
    use_count: int
    owner: str
    tags: dict


@dataclass
class HSMAuditEntry:
    entry_id: str
    timestamp: float
    operation: str
    key_id: Optional[str]
    caller: str
    success: bool
    detail: str
    session_token: str


class HSMSession:
    """Authenticated HSM session with role-based operation permissions."""
    ROLE_PERMISSIONS = {
        'crypto_officer': {'generate_key', 'destroy_key', 'activate_key', 'deactivate_key'},
        'crypto_user': {'encrypt', 'decrypt', 'sign', 'verify', 'wrap_key', 'unwrap_key'},
        'auditor': {'list_keys', 'get_audit_log', 'get_key_metadata'},
    }

    def __init__(self, session_id: str, caller: str, roles: list[str], expires_in: int = 3600):
        self.session_id = session_id
        self.caller = caller
        self.roles = set(roles)
        self.created_at = time.time()
        self.expires_at = self.created_at + expires_in
        self.token = base64.urlsafe_b64encode(os.urandom(32)).decode()

    def is_valid(self) -> bool:
        return time.time() < self.expires_at

    def can_perform(self, operation: str) -> bool:
        for role in self.roles:
            if operation in self.ROLE_PERMISSIONS.get(role, set()):
                return True
        return False


class SoftHSM:
    """
    Software HSM simulation with:
    - RSA, EC, AES-256-GCM, HMAC key generation
    - Role-based session management (crypto_officer, crypto_user, auditor)
    - Cryptographic operations: encrypt/decrypt, sign/verify, wrap/unwrap
    - Non-extractable keys (key material never leaves HSM boundary)
    - Tamper-evident audit log
    - Key lifecycle management (activation, expiry, destruction)
    """

    def __init__(self):
        self._key_store: dict[str, dict] = {}  # key_id -> {metadata, key_material}
        self._metadata: dict[str, KeyMetadata] = {}
        self._sessions: dict[str, HSMSession] = {}
        self._audit_log: list[HSMAuditEntry] = []
        self._audit_counter = 0
        self._key_counter = 0

    # --- Session management ---
    def open_session(
        self, caller: str, roles: list[str], auth_token: str
    ) -> HSMSession:
        # In production: verify auth_token against credential store
        if not auth_token or len(auth_token) < 8:
            raise HSMError('Invalid authentication token')
        session = HSMSession(
            session_id=base64.urlsafe_b64encode(os.urandom(16)).decode(),
            caller=caller, roles=roles
        )
        self._sessions[session.session_id] = session
        self._audit('open_session', None, caller, True, f'Roles: {roles}', session.token)
        return session

    def _check_session(self, session: HSMSession, operation: str):
        if not session.is_valid():
            raise HSMError('Session expired')
        if not session.can_perform(operation):
            self._audit(operation, None, session.caller, False, f'Permission denied for {operation}', session.token)
            raise HSMError(f'Permission denied: {session.caller} cannot perform {operation}')

    def _audit(
        self, operation: str, key_id: Optional[str], caller: str,
        success: bool, detail: str, session_token: str = ''
    ):
        self._audit_counter += 1
        entry = HSMAuditEntry(
            entry_id=f'AUD-{self._audit_counter:08d}',
            timestamp=time.time(),
            operation=operation,
            key_id=key_id,
            caller=caller,
            success=success,
            detail=detail,
            session_token=session_token[:8] + '...' if session_token else ''
        )
        self._audit_log.append(entry)

    # --- Key management ---
    def generate_key(
        self,
        session: HSMSession,
        key_type: KeyType,
        key_usage: KeyUsage,
        label: str,
        owner: str,
        extractable: bool = False,
        expires_in_days: Optional[int] = None,
        tags: Optional[dict] = None
    ) -> str:
        self._check_session(session, 'generate_key')
        self._key_counter += 1
        key_id = f'KSM-{self._key_counter:06d}-{base64.urlsafe_b64encode(os.urandom(4)).decode()[:6]}'

        if key_type == KeyType.AES_256:
            key_material = {'symmetric_key': os.urandom(32)}
        elif key_type == KeyType.RSA_2048:
            private_key = rsa.generate_private_key(65537, 2048, default_backend())
            key_material = {'private_key': private_key, 'public_key': private_key.public_key()}
        elif key_type == KeyType.RSA_4096:
            private_key = rsa.generate_private_key(65537, 4096, default_backend())
            key_material = {'private_key': private_key, 'public_key': private_key.public_key()}
        elif key_type == KeyType.EC_P256:
            private_key = ec.generate_private_key(ec.SECP256R1(), default_backend())
            key_material = {'private_key': private_key, 'public_key': private_key.public_key()}
        elif key_type == KeyType.EC_P384:
            private_key = ec.generate_private_key(ec.SECP384R1(), default_backend())
            key_material = {'private_key': private_key, 'public_key': private_key.public_key()}
        elif key_type == KeyType.HMAC_SHA256:
            key_material = {'symmetric_key': os.urandom(32)}
        else:
            raise HSMError(f'Unsupported key type: {key_type}')

        expires_at = (time.time() + expires_in_days * 86400) if expires_in_days else None
        metadata = KeyMetadata(
            key_id=key_id, key_type=key_type, key_usage=key_usage,
            label=label, created_at=time.time(), expires_at=expires_at,
            extractable=extractable, active=True, use_count=0, owner=owner, tags=tags or {}
        )
        self._key_store[key_id] = key_material
        self._metadata[key_id] = metadata
        self._audit('generate_key', key_id, session.caller, True,
                    f'type={key_type.value} usage={key_usage.value} extractable={extractable}', session.token)
        return key_id

    def _get_key(self, key_id: str) -> tuple[dict, KeyMetadata]:
        if key_id not in self._metadata:
            raise HSMError(f'Key not found: {key_id}')
        meta = self._metadata[key_id]
        if not meta.active:
            raise HSMError(f'Key {key_id} is deactivated')
        if meta.expires_at and time.time() > meta.expires_at:
            raise HSMError(f'Key {key_id} has expired')
        return self._key_store[key_id], meta

    # --- Crypto operations ---
    def encrypt(
        self, session: HSMSession, key_id: str, plaintext: bytes
    ) -> tuple[bytes, bytes]:
        self._check_session(session, 'encrypt')
        key_mat, meta = self._get_key(key_id)
        if meta.key_type not in (KeyType.AES_256,):
            raise HSMError('Key not suitable for encryption')
        nonce = os.urandom(12)
        aesgcm = AESGCM(key_mat['symmetric_key'])
        ciphertext = aesgcm.encrypt(nonce, plaintext, None)
        meta.use_count += 1
        self._audit('encrypt', key_id, session.caller, True, f'{len(plaintext)} bytes', session.token)
        return nonce, ciphertext

    def decrypt(
        self, session: HSMSession, key_id: str, nonce: bytes, ciphertext: bytes
    ) -> bytes:
        self._check_session(session, 'decrypt')
        key_mat, meta = self._get_key(key_id)
        aesgcm = AESGCM(key_mat['symmetric_key'])
        try:
            plaintext = aesgcm.decrypt(nonce, ciphertext, None)
        except Exception:
            self._audit('decrypt', key_id, session.caller, False, 'Decryption failed — tampered ciphertext?', session.token)
            raise HSMError('Decryption failed — authentication tag mismatch')
        meta.use_count += 1
        self._audit('decrypt', key_id, session.caller, True, f'{len(plaintext)} bytes', session.token)
        return plaintext

    def sign(
        self, session: HSMSession, key_id: str, message: bytes
    ) -> bytes:
        self._check_session(session, 'sign')
        key_mat, meta = self._get_key(key_id)
        if meta.key_type.value.startswith('RSA'):
            sig = key_mat['private_key'].sign(message, padding.PSS(
                padding.MGF1(hashes.SHA256()), padding.PSS.MAX_LENGTH
            ), hashes.SHA256())
        elif meta.key_type.value.startswith('EC'):
            sig = key_mat['private_key'].sign(message, ec.ECDSA(hashes.SHA256()))
        elif meta.key_type == KeyType.HMAC_SHA256:
            sig = hmac.new(key_mat['symmetric_key'], message, hashlib.sha256).digest()
        else:
            raise HSMError('Key not suitable for signing')
        meta.use_count += 1
        self._audit('sign', key_id, session.caller, True, f'{len(message)} bytes', session.token)
        return sig

    def get_public_key_pem(
        self, key_id: str
    ) -> str:
        if key_id not in self._key_store:
            raise HSMError(f'Key not found: {key_id}')
        key_mat = self._key_store[key_id]
        if 'public_key' not in key_mat:
            raise HSMError('Key is symmetric — no public key')
        return key_mat['public_key'].public_bytes(
            serialization.Encoding.PEM, serialization.PublicFormat.SubjectPublicKeyInfo
        ).decode()

    def destroy_key(self, session: HSMSession, key_id: str):
        self._check_session(session, 'destroy_key')
        if key_id not in self._key_store:
            raise HSMError(f'Key not found: {key_id}')
        del self._key_store[key_id]
        self._metadata[key_id].active = False
        self._audit('destroy_key', key_id, session.caller, True, 'Key material destroyed', session.token)

    def get_audit_log(
        self, session: HSMSession, limit: int = 100
    ) -> list[HSMAuditEntry]:
        self._check_session(session, 'get_audit_log')
        return self._audit_log[-limit:]
