import numpy as np
from dataclasses import dataclass, field
from typing import Optional
from collections import defaultdict


@dataclass
class KeystrokeEvent:
    key: str
    press_time: float   # Unix timestamp milliseconds
    release_time: float


@dataclass
class MouseEvent:
    timestamp: float
    x: int
    y: int
    event_type: str   # 'move', 'click', 'scroll'


@dataclass
class BiometricSession:
    session_id: str
    user_id: str
    keystroke_events: list[KeystrokeEvent]
    mouse_events: list[MouseEvent]
    login_text: str   # Text typed during authentication


@dataclass
class BiometricProfile:
    user_id: str
    n_samples: int
    # Keystroke features (means and stds)
    mean_dwell_times: dict[str, float]       # Per-key dwell time (press-to-release)
    std_dwell_times: dict[str, float]
    mean_flight_times: dict[str, float]      # Digraph flight times (key_a -> key_b)
    std_flight_times: dict[str, float]
    mean_wpm: float                          # Words per minute
    std_wpm: float
    # Mouse features
    mean_mouse_velocity: float
    std_mouse_velocity: float
    mean_click_interval: float
    std_click_interval: float
    mean_path_curvature: float
    std_path_curvature: float


@dataclass
class AuthResult:
    session_id: str
    user_id: str
    claimed_user_id: str
    keystroke_score: float    # 0-1, lower=more similar
    mouse_score: float
    combined_score: float
    decision: str             # 'ACCEPT', 'CHALLENGE', 'REJECT'
    confidence: float
    anomalies: list[str]


def extract_keystroke_features(events: list[KeystrokeEvent]) -> dict:
    if len(events) < 3:
        return {}
    dwell_times = {}
    flight_times = {}
    for ev in events:
        dwell = ev.release_time - ev.press_time
        if dwell > 0:
            dwell_times[ev.key] = dwell_times.get(ev.key, []) + [dwell]
    for i in range(len(events) - 1):
        digraph = f'{events[i].key}:{events[i+1].key}'
        flight = events[i+1].press_time - events[i].release_time
        if -50 < flight < 1000:  # Filter outliers
            flight_times[digraph] = flight_times.get(digraph, []) + [flight]
    # WPM: assuming 5 chars per word
    total_time_sec = (events[-1].release_time - events[0].press_time) / 1000.0
    wpm = (len(events) / 5.0) / max(total_time_sec / 60.0, 0.001)
    return {
        'dwell_means': {k: float(np.mean(v)) for k, v in dwell_times.items()},
        'dwell_stds': {k: float(np.std(v)) if len(v) > 1 else 20.0 for k, v in dwell_times.items()},
        'flight_means': {k: float(np.mean(v)) for k, v in flight_times.items()},
        'flight_stds': {k: float(np.std(v)) if len(v) > 1 else 30.0 for k, v in flight_times.items()},
        'wpm': wpm
    }


def extract_mouse_features(events: list[MouseEvent]) -> dict:
    if len(events) < 5:
        return {}
    velocities = []
    click_times = []
    for i in range(1, len(events)):
        dt = events[i].timestamp - events[i-1].timestamp
        if dt > 0:
            dist = np.sqrt((events[i].x - events[i-1].x)**2 + (events[i].y - events[i-1].y)**2)
            velocities.append(dist / dt)
        if events[i].event_type == 'click' and events[i-1].event_type == 'click':
            click_times.append(events[i].timestamp - events[i-1].timestamp)
    # Path curvature (angular change)
    curvatures = []
    for i in range(1, len(events) - 1):
        dx1 = events[i].x - events[i-1].x
        dy1 = events[i].y - events[i-1].y
        dx2 = events[i+1].x - events[i].x
        dy2 = events[i+1].y - events[i].y
        angle = abs(np.arctan2(dy2, dx2) - np.arctan2(dy1, dx1))
        curvatures.append(float(angle))
    return {
        'mean_velocity': float(np.mean(velocities)) if velocities else 0.0,
        'std_velocity': float(np.std(velocities)) if velocities else 1.0,
        'mean_click_interval': float(np.mean(click_times)) if click_times else 0.0,
        'std_click_interval': float(np.std(click_times)) if click_times else 100.0,
        'mean_curvature': float(np.mean(curvatures)) if curvatures else 0.0,
        'std_curvature': float(np.std(curvatures)) if curvatures else 0.5,
    }


class BehavioralBiometricsAuth:
    """
    Behavioral biometrics authentication system.
    Enrollment: build per-user profiles from multiple typing sessions.
    Verification: compute dissimilarity score between current session
    features and enrolled profile using Manhattan distance normalized
    by standard deviation (z-score distance).
    Combines keystroke dynamics and mouse movement signatures.
    """

    def __init__(
        self,
        accept_threshold: float = 1.5,
        challenge_threshold: float = 3.0,
        min_sessions_for_enrollment: int = 5
    ):
        self.accept_threshold = accept_threshold
        self.challenge_threshold = challenge_threshold
        self.min_sessions = min_sessions_for_enrollment
        self._enrollment_data: dict[str, list[dict]] = defaultdict(list)
        self._profiles: dict[str, BiometricProfile] = {}

    def enroll_session(
        self, session: BiometricSession
    ) -> dict:
        ks_features = extract_keystroke_features(session.keystroke_events)
        mouse_features = extract_mouse_features(session.mouse_events)
        if not ks_features:
            return {'enrolled': False, 'reason': 'Insufficient keystroke data'}
        self._enrollment_data[session.user_id].append({
            'keystroke': ks_features, 'mouse': mouse_features
        })
        n = len(self._enrollment_data[session.user_id])
        if n >= self.min_sessions:
            self._profiles[session.user_id] = self._build_profile(session.user_id)
            return {'enrolled': True, 'profile_built': True, 'n_sessions': n}
        return {'enrolled': True, 'profile_built': False,
                'n_sessions': n, 'sessions_needed': self.min_sessions - n}

    def _build_profile(self, user_id: str) -> BiometricProfile:
        sessions = self._enrollment_data[user_id]
        # Aggregate keystroke stats
        all_dwell: dict[str, list] = defaultdict(list)
        all_flight: dict[str, list] = defaultdict(list)
        all_wpm = []
        all_vel, all_click_int, all_curve = [], [], []
        for s in sessions:
            ks = s['keystroke']
            for k, v in ks.get('dwell_means', {}).items():
                all_dwell[k].append(v)
            for k, v in ks.get('flight_means', {}).items():
                all_flight[k].append(v)
            if 'wpm' in ks:
                all_wpm.append(ks['wpm'])
            m = s['mouse']
            if m:
                all_vel.append(m.get('mean_velocity', 0))
                all_click_int.append(m.get('mean_click_interval', 0))
                all_curve.append(m.get('mean_curvature', 0))
        return BiometricProfile(
            user_id=user_id,
            n_samples=len(sessions),
            mean_dwell_times={k: float(np.mean(v)) for k, v in all_dwell.items()},
            std_dwell_times={k: float(max(np.std(v), 10.0)) for k, v in all_dwell.items()},
            mean_flight_times={k: float(np.mean(v)) for k, v in all_flight.items()},
            std_flight_times={k: float(max(np.std(v), 15.0)) for k, v in all_flight.items()},
            mean_wpm=float(np.mean(all_wpm)) if all_wpm else 60.0,
            std_wpm=float(max(np.std(all_wpm), 5.0)) if len(all_wpm) > 1 else 10.0,
            mean_mouse_velocity=float(np.mean(all_vel)) if all_vel else 0.0,
            std_mouse_velocity=float(max(np.std(all_vel), 0.1)) if len(all_vel) > 1 else 1.0,
            mean_click_interval=float(np.mean(all_click_int)) if all_click_int else 0.0,
            std_click_interval=float(max(np.std(all_click_int), 50.0)) if len(all_click_int) > 1 else 100.0,
            mean_path_curvature=float(np.mean(all_curve)) if all_curve else 0.0,
            std_path_curvature=float(max(np.std(all_curve), 0.05)) if len(all_curve) > 1 else 0.3,
        )

    def _keystroke_distance(
        self, features: dict, profile: BiometricProfile
    ) -> tuple[float, list[str]]:
        distances = []
        anomalies = []
        for key, mean_dwell in features.get('dwell_means', {}).items():
            if key in profile.mean_dwell_times:
                z = abs(mean_dwell - profile.mean_dwell_times[key]) / profile.std_dwell_times[key]
                distances.append(z)
                if z > 3.0:
                    anomalies.append(f'Dwell time anomaly on key {key!r} (z={z:.1f})')
        for digraph, mean_flight in features.get('flight_means', {}).items():
            if digraph in profile.mean_flight_times:
                z = abs(mean_flight - profile.mean_flight_times[digraph]) / profile.std_flight_times[digraph]
                distances.append(z)
        if 'wpm' in features:
            z_wpm = abs(features['wpm'] - profile.mean_wpm) / profile.std_wpm
            distances.append(z_wpm)
            if z_wpm > 3.0:
                anomalies.append(f'Typing speed anomaly (z={z_wpm:.1f})')
        score = float(np.mean(distances)) if distances else 2.0
        return score, anomalies

    def _mouse_distance(
        self, features: dict, profile: BiometricProfile
    ) -> float:
        if not features:
            return 0.0
        z_vel = abs(features.get('mean_velocity', profile.mean_mouse_velocity) - profile.mean_mouse_velocity) / profile.std_mouse_velocity
        z_curve = abs(features.get('mean_curvature', profile.mean_path_curvature) - profile.mean_path_curvature) / profile.std_path_curvature
        return float(np.mean([z_vel, z_curve]))

    def verify(
        self, session: BiometricSession, claimed_user_id: str
    ) -> AuthResult:
        profile = self._profiles.get(claimed_user_id)
        if profile is None:
            return AuthResult(
                session_id=session.session_id, user_id=session.user_id,
                claimed_user_id=claimed_user_id, keystroke_score=99.0,
                mouse_score=99.0, combined_score=99.0, decision='REJECT',
                confidence=0.0, anomalies=['No enrolled profile for this user']
            )
        ks_features = extract_keystroke_features(session.keystroke_events)
        mouse_features = extract_mouse_features(session.mouse_events)
        ks_score, anomalies = self._keystroke_distance(ks_features, profile)
        mouse_score = self._mouse_distance(mouse_features, profile)
        combined = 0.7 * ks_score + 0.3 * mouse_score
        if combined <= self.accept_threshold:
            decision = 'ACCEPT'
            confidence = 1.0 - combined / self.accept_threshold
        elif combined <= self.challenge_threshold:
            decision = 'CHALLENGE'
            confidence = 0.5 - (combined - self.accept_threshold) / (self.challenge_threshold - self.accept_threshold) * 0.5
        else:
            decision = 'REJECT'
            confidence = 0.0
        return AuthResult(
            session_id=session.session_id, user_id=session.user_id,
            claimed_user_id=claimed_user_id,
            keystroke_score=round(ks_score, 4),
            mouse_score=round(mouse_score, 4),
            combined_score=round(combined, 4),
            decision=decision,
            confidence=round(max(0.0, confidence), 4),
            anomalies=anomalies
        )
