class SimpleQueryParser:
    """
    Parses simplified KQL-style query strings into filter predicates.
    Supported syntax:
      field == 'value'          field != 'value'
      field contains 'text'     field startswith 'text'
      field > 10                field in ('a', 'b', 'c')
      field matches 'regex'
    Compound: expr1 and expr2, expr1 or expr2
    """

    OP_RE = re.compile(
        r'(\w+(?:\.\w+)*)\s+(==|!=|>=|<=|>|<|contains|startswith|endswith|matches|in|not in)\s+'
        r'([^\s].*?)(?=\s+(?:and|or)\s+|$)',
        re.IGNORECASE
    )
    VALUE_RE = re.compile(r"[\'\"](.+?)[\'\"]|\((.+?)\)|([\d\.]+)")

    def _parse_value(self, raw: str) -> Any:
        raw = raw.strip()
        # Tuple/list
        if raw.startswith('('):
            items = raw[1:-1].split(',')
            return [self._parse_value(i) for i in items]
        # Quoted string
        if (raw.startswith("'") and raw.endswith("'")) or (raw.startswith('"') and raw.endswith('"')):
            return raw[1:-1]
        # Number
        try:
            return float(raw) if '.' in raw else int(raw)
        except ValueError:
            return raw

    def _get_field(self, record: LogRecord, field_path: str) -> Any:
        if hasattr(record, field_path):
            val = getattr(record, field_path)
            if isinstance(val, datetime):
                return val.isoformat()
            return val
        # Check in fields dict
        return record.fields.get(field_path)

    def _make_predicate(
        self, field: str, op: str, value: Any
    ) -> Callable[[LogRecord], bool]:
        op_lower = op.lower()

        def predicate(record: LogRecord) -> bool:
            field_val = self._get_field(record, field)
            if field_val is None:
                return False
            try:
                if op_lower == '==':
                    return str(field_val).lower() == str(value).lower()
                elif op_lower == '!=':
                    return str(field_val).lower() != str(value).lower()
                elif op_lower == 'contains':
                    return str(value).lower() in str(field_val).lower()
                elif op_lower == 'startswith':
                    return str(field_val).lower().startswith(str(value).lower())
                elif op_lower == 'endswith':
                    return str(field_val).lower().endswith(str(value).lower())
                elif op_lower == '>':
                    return float(field_val) > float(value)
                elif op_lower == '<':
                    return float(field_val) < float(value)
                elif op_lower == '>=':
                    return float(field_val) >= float(value)
                elif op_lower == '<=':
                    return float(field_val) <= float(value)
                elif op_lower == 'in':
                    return str(field_val).lower() in [str(v).lower() for v in value]
                elif op_lower == 'not in':
                    return str(field_val).lower() not in [str(v).lower() for v in value]
                elif op_lower == 'matches':
                    return bool(re.search(str(value), str(field_val), re.IGNORECASE))
            except (ValueError, TypeError):
                return False
            return False

        return predicate

    def parse(self, query: str) -> Callable[[LogRecord], bool]:
        # Split on 'and'/'or' — simple left-to-right evaluation
        and_parts = re.split(r'\s+and\s+', query, flags=re.IGNORECASE)
        or_groups = [re.split(r'\s+or\s+', part, flags=re.IGNORECASE) for part in and_parts]

        # Flatten to get all atomic conditions
        all_predicates = []
        for or_group in or_groups:
            group_preds = []
            for atom in or_group:
                m = self.OP_RE.match(atom.strip())
                if m:
                    field, op, val_raw = m.group(1), m.group(2), m.group(3).strip()
                    value = self._parse_value(val_raw)
                    group_preds.append(self._make_predicate(field, op, value))
            if group_preds:
                # OR within group
                def make_or(preds):
                    return lambda r: any(p(r) for p in preds)
                all_predicates.append(make_or(group_preds))

        # AND across groups
        def make_and(preds):
            return lambda r: all(p(r) for p in preds)

        return make_and(all_predicates) if all_predicates else (lambda r: True)


