class ThreatHuntingEngine:
    """
    Threat hunting automation framework.
    Ingests log records, executes hunting rules with KQL-style queries
    against a time-windowed log buffer, groups results by field,
    and generates hunting hits when match thresholds are exceeded.
    Designed for proactive threat hunting in SIEM-like environments.
    """

    def __init__(
        self,
        rules: Optional[list[HuntingRule]] = None,
        max_buffer_size: int = 100_000
    ):
        self.rules = rules or DEFAULT_HUNTING_RULES
        self._query_parser = SimpleQueryParser()
        self._log_buffer: list[LogRecord] = []
        self._max_buffer = max_buffer_size
        self._hits: list[HuntingHit] = []
        self._compiled_queries: dict[str, Callable] = {}
        self._precompile_rules()

    def _precompile_rules(self):
        for rule in self.rules:
            try:
                self._compiled_queries[rule.rule_id] = self._query_parser.parse(rule.query)
            except Exception as e:
                self._compiled_queries[rule.rule_id] = lambda r: False

    def ingest(
        self, records: list[LogRecord]
    ) -> list[HuntingHit]:
        self._log_buffer.extend(records)
        if len(self._log_buffer) > self._max_buffer:
            self._log_buffer = self._log_buffer[-self._max_buffer:]
        new_hits = []
        for rule in self.rules:
            hits = self._evaluate_rule(rule)
            new_hits.extend(hits)
        self._hits.extend(new_hits)
        return new_hits

    def _evaluate_rule(
        self, rule: HuntingRule
    ) -> list[HuntingHit]:
        now = max((r.timestamp for r in self._log_buffer), default=datetime.utcnow())
        cutoff = now - timedelta(minutes=rule.time_window_minutes)
        recent = [r for r in self._log_buffer if r.timestamp >= cutoff]
        predicate = self._compiled_queries.get(rule.rule_id, lambda r: True)
        matched = [r for r in recent if predicate(r)]
        if not matched:
            return []
        hits = []
        if rule.group_by:
            groups: dict[str, list[LogRecord]] = defaultdict(list)
            for r in matched:
                key = r.fields.get(rule.group_by) or getattr(r, rule.group_by, 'unknown')
                groups[str(key)].append(r)
            for group_key, group_records in groups.items():
                if len(group_records) >= rule.threshold_per_group:
                    hits.append(self._make_hit(rule, group_records, group_key))
        else:
            if len(matched) >= rule.min_match_count:
                hits.append(self._make_hit(rule, matched, None))
        return hits

    def _make_hit(
        self,
        rule: HuntingRule,
        records: list[LogRecord],
        group_key: Optional[str]
    ) -> HuntingHit:
        sorted_records = sorted(records, key=lambda r: r.timestamp)
        summary = (
            f'[{rule.severity}] {rule.name}: {len(records)} events '
            f'in {rule.time_window_minutes}min window'
            + (f' for {rule.group_by}={group_key}' if group_key else '')
        )
        return HuntingHit(
            rule_id=rule.rule_id,
            rule_name=rule.name,
            mitre_technique=rule.mitre_technique,
            severity=rule.severity,
            matched_records=records[:20],
            group_key=group_key,
            match_count=len(records),
            first_seen=sorted_records[0].timestamp,
            last_seen=sorted_records[-1].timestamp,
            summary=summary
        )

    def run_scheduled_hunt(
        self, time_range_hours: int = 24
    ) -> list[HuntingHit]:
        """Re-evaluate all rules over the current buffer."""
        all_hits = []
        for rule in self.rules:
            hits = self._evaluate_rule(rule)
            all_hits.extend(hits)
        self._hits.extend(all_hits)
        return all_hits

    def get_hits(
        self, severity: Optional[str] = None, limit: int = 100
    ) -> list[HuntingHit]:
        hits = self._hits
        if severity:
            hits = [h for h in hits if h.severity == severity]
        return hits[-limit:]

    def generate_hunt_report(self) -> dict:
        severity_counts: dict[str, int] = defaultdict(int)
        technique_counts: dict[str, int] = defaultdict(int)
        for hit in self._hits:
            severity_counts[hit.severity] += 1
            technique_counts[hit.mitre_technique] += 1
        return {
            'total_hits': len(self._hits),
            'by_severity': dict(severity_counts),
            'by_technique': dict(technique_counts),
            'buffer_size': len(self._log_buffer),
            'rules_active': len(self.rules),
            'top_techniques': sorted(
                technique_counts.items(), key=lambda x: -x[1]
            )[:5]
        }
