class BayesianRiskNetwork:
    """
    Bayesian network for enterprise security risk assessment.
    Models probabilistic relationships between:
    - Threat environment (known_threat_active, attacker_capability)
    - Vulnerability state (has_unpatched_critical, exposed_to_internet)
    - Control effectiveness (has_edr, has_mfa, has_dlp)
    - Business impact (data_sensitivity, asset_criticality)
    - Outcome (compromise_risk, data_breach_risk)
    Supports exact inference via variable elimination on small networks.
    """

    def __init__(self):
        self._nodes: dict[str, BayesNode] = {}
        self._evidence: dict[str, str] = {}

    def add_node(self, node: BayesNode):
        # Normalize CPT probabilities
        for key, probs in node.cpt.items():
            total = sum(probs)
            node.cpt[key] = [p / max(total, 1e-10) for p in probs]
        self._nodes[node.name] = node

    def set_evidence(self, evidence: dict[str, str]):
        """Set observed evidence: {node_name: observed_state}."""
        for node_name, state in evidence.items():
            if node_name in self._nodes:
                if state in self._nodes[node_name].states:
                    self._evidence[node_name] = state

    def clear_evidence(self):
        self._evidence.clear()

    def _get_prior(self, node: BayesNode) -> dict[str, float]:
        """Get prior probabilities for a root node."""
        return {state: node.cpt[()][i] for i, state in enumerate(node.states)}

    def _get_conditional(
        self, node: BayesNode, parent_states: dict[str, str]
    ) -> dict[str, float]:
        """Get conditional probabilities given parent states."""
        parent_state_tuple = tuple(parent_states.get(p, '') for p in node.parents)
        probs = node.cpt.get(parent_state_tuple, node.cpt.get((), [1.0 / len(node.states)] * len(node.states)))
        return {state: probs[i] for i, state in enumerate(node.states)}

    def _topological_sort(self) -> list[str]:
        """Kahn's algorithm for topological ordering."""
        in_degree = {n: 0 for n in self._nodes}
        for node in self._nodes.values():
            for parent in node.parents:
                in_degree[node.name] = in_degree.get(node.name, 0) + 1
        queue = [n for n, d in in_degree.items() if d == 0]
        sorted_nodes = []
        while queue:
            node = queue.pop(0)
            sorted_nodes.append(node)
            for other in self._nodes.values():
                if node in other.parents:
                    in_degree[other.name] -= 1
                    if in_degree[other.name] == 0:
                        queue.append(other.name)
        return sorted_nodes

    def infer(
        self, target_node: str, n_samples: int = 10000
    ) -> dict[str, float]:
        """
        Forward sampling inference with rejection for evidence.
        Approximate but handles arbitrary network structures.
        """
        if target_node not in self._nodes:
            raise ValueError(f'Unknown node: {target_node}')
        rng = np.random.default_rng(42)
        sorted_nodes = self._topological_sort()
        target_counts = defaultdict(int)
        accepted = 0

        for _ in range(n_samples):
            sample = {}
            consistent = True
            for node_name in sorted_nodes:
                node = self._nodes[node_name]
                if not node.parents:
                    probs = list(self._get_prior(node).values())
                else:
                    parent_states = {p: sample.get(p, node.states[0]) for p in node.parents}
                    probs = list(self._get_conditional(node, parent_states).values())
                probs_arr = np.array(probs)
                probs_arr = probs_arr / probs_arr.sum()
                sampled_state = rng.choice(node.states, p=probs_arr)
                sample[node_name] = sampled_state
                # Reject if inconsistent with evidence
                if node_name in self._evidence and sampled_state != self._evidence[node_name]:
                    consistent = False
                    break
            if consistent:
                target_counts[sample[target_node]] += 1
                accepted += 1

        if accepted == 0:
            n_states = len(self._nodes[target_node].states)
            return {s: 1.0 / n_states for s in self._nodes[target_node].states}

        return {state: count / accepted for state, count in target_counts.items()}

    def assess_risk(
        self, target_node: str, risk_state_weights: Optional[dict[str, float]] = None
    ) -> RiskAssessment:
        if risk_state_weights is None:
            risk_state_weights = {'low': 0, 'medium': 33, 'high': 67, 'critical': 100}
        state_probs = self.infer(target_node)
        most_likely = max(state_probs, key=lambda s: state_probs[s])
        confidence = state_probs[most_likely]
        risk_score = sum(
            state_probs.get(state, 0) * weight
            for state, weight in risk_state_weights.items()
        )
        # Identify top contributing evidence
        contributing = [
            {'node': k, 'state': v, 'type': 'evidence'}
            for k, v in self._evidence.items()
        ]
        if risk_score >= 75:
            rec = 'CRITICAL: Immediate incident response required. Activate IR plan.'
        elif risk_score >= 50:
            rec = 'HIGH: Prioritize remediation. Apply compensating controls immediately.'
        elif risk_score >= 25:
            rec = 'MEDIUM: Schedule remediation in next sprint. Review access controls.'
        else:
            rec = 'LOW: Continue monitoring. Maintain current security controls.'
        return RiskAssessment(
            target_node=target_node,
            state_probabilities={k: round(v, 4) for k, v in state_probs.items()},
            most_likely_state=most_likely,
            confidence=round(confidence, 4),
            risk_score=round(risk_score, 2),
            contributing_factors=contributing,
            recommendation=rec
        )


def build_security_risk_network() -> BayesianRiskNetwork:
    """
    Build a security risk Bayesian network for enterprise assessment.
    Nodes and their conditional probability tables (CPTs) encode
    expert knowledge about how security factors interact.
    """
    net = BayesianRiskNetwork()

    # Root nodes (priors)
    net.add_node(BayesNode('threat_active', ['no', 'yes'], [],
                           {(): [0.7, 0.3]}))
    net.add_node(BayesNode('attacker_skill', ['low', 'high'], [],
                           {(): [0.6, 0.4]}))
    net.add_node(BayesNode('unpatched_critical', ['no', 'yes'], [],
                           {(): [0.55, 0.45]}))
    net.add_node(BayesNode('internet_exposed', ['no', 'yes'], [],
                           {(): [0.4, 0.6]}))
    net.add_node(BayesNode('has_mfa', ['no', 'yes'], [],
                           {(): [0.3, 0.7]}))
    net.add_node(BayesNode('has_edr', ['no', 'yes'], [],
                           {(): [0.35, 0.65]}))
    net.add_node(BayesNode('data_sensitivity', ['low', 'high'], [],
                           {(): [0.5, 0.5]}))

    # Intermediate: exploitation_success depends on threat, vulnerability, exposure
    net.add_node(BayesNode(
        'exploitation_success',
        ['no', 'yes'],
        ['threat_active', 'unpatched_critical', 'internet_exposed'],
        {
            ('no', 'no', 'no'): [0.99, 0.01],
            ('no', 'no', 'yes'): [0.97, 0.03],
            ('no', 'yes', 'no'): [0.95, 0.05],
            ('no', 'yes', 'yes'): [0.85, 0.15],
            ('yes', 'no', 'no'): [0.90, 0.10],
            ('yes', 'no', 'yes'): [0.70, 0.30],
            ('yes', 'yes', 'no'): [0.60, 0.40],
            ('yes', 'yes', 'yes'): [0.20, 0.80],
        }
    ))

    # Endpoint compromise depends on exploitation success and EDR
    net.add_node(BayesNode(
        'endpoint_compromise',
        ['no', 'yes'],
        ['exploitation_success', 'has_edr'],
        {
            ('no', 'no'): [0.99, 0.01],
            ('no', 'yes'): [0.995, 0.005],
            ('yes', 'no'): [0.30, 0.70],
            ('yes', 'yes'): [0.70, 0.30],  # EDR reduces risk
        }
    ))

    # Account takeover depends on exploitation and MFA
    net.add_node(BayesNode(
        'account_takeover',
        ['no', 'yes'],
        ['exploitation_success', 'has_mfa'],
        {
            ('no', 'no'): [0.98, 0.02],
            ('no', 'yes'): [0.99, 0.01],
            ('yes', 'no'): [0.35, 0.65],
            ('yes', 'yes'): [0.80, 0.20],  # MFA significantly reduces risk
        }
    ))

    # Data breach depends on compromise, account takeover, and data sensitivity
    net.add_node(BayesNode(
        'data_breach',
        ['low', 'medium', 'high'],
        ['endpoint_compromise', 'account_takeover', 'data_sensitivity'],
        {
            ('no', 'no', 'low'): [0.98, 0.015, 0.005],
            ('no', 'no', 'high'): [0.95, 0.04, 0.01],
            ('no', 'yes', 'low'): [0.70, 0.25, 0.05],
            ('no', 'yes', 'high'): [0.40, 0.40, 0.20],
            ('yes', 'no', 'low'): [0.60, 0.30, 0.10],
            ('yes', 'no', 'high'): [0.30, 0.40, 0.30],
            ('yes', 'yes', 'low'): [0.25, 0.45, 0.30],
            ('yes', 'yes', 'high'): [0.05, 0.25, 0.70],
        }
    ))

    return net
