class IntegrationRegistry:
    """
    Registry of SOAR integration actions.
    Each integration provides a dict of {action_name: callable}.
    Callables accept a context dict and parameters dict,
    and return a result dict.
    """

    def __init__(self):
        self._integrations: dict[str, dict[str, Callable]] = {}
        self._register_builtin_integrations()

    def register(
        self, integration_name: str, actions: dict[str, Callable]
    ):
        self._integrations[integration_name] = actions

    def execute(
        self, integration: str, action: str,
        context: dict, parameters: dict
    ) -> dict:
        if integration not in self._integrations:
            raise ValueError(f'Unknown integration: {integration}')
        if action not in self._integrations[integration]:
            raise ValueError(f'Unknown action: {integration}.{action}')
        # Resolve context references in parameters
        resolved = {}
        for k, v in parameters.items():
            if isinstance(v, str) and v.startswith('{{') and v.endswith('}}'):
                key = v[2:-2].strip()
                resolved[k] = context.get(key, v)
            else:
                resolved[k] = v
        return self._integrations[integration][action](context, resolved)

    def _register_builtin_integrations(self):
        # Simulated VirusTotal integration
        def vt_lookup_ip(ctx, params):
            ip = params.get('ip', '')
            # Simulate: known malicious IPs
            malicious_ips = {'185.220.101.1', '91.108.4.0', '45.142.212.0'}
            is_malicious = ip in malicious_ips
            return {
                'ip': ip, 'malicious': is_malicious,
                'detection_count': 45 if is_malicious else 0,
                'categories': ['C2'] if is_malicious else [],
                'country': 'RU' if is_malicious else 'US'
            }

        def vt_lookup_hash(ctx, params):
            file_hash = params.get('hash', '')
            return {
                'hash': file_hash, 'malicious': len(file_hash) > 10,
                'malware_family': 'Emotet' if len(file_hash) > 10 else None,
                'threat_label': 'trojan.emotet' if len(file_hash) > 10 else 'clean'
            }

        # Simulated CrowdStrike integration
        def cs_isolate_host(ctx, params):
            host = params.get('host', '')
            return {'host': host, 'isolated': True, 'action': 'contain', 'status': 'success'}

        def cs_get_process_tree(ctx, params):
            host = params.get('host', '')
            return {'host': host, 'processes': [{'pid': 1234, 'name': 'powershell.exe', 'parent': 'winword.exe'}]}

        def cs_kill_process(ctx, params):
            pid = params.get('pid', 0)
            return {'pid': pid, 'killed': True, 'status': 'success'}

        # Simulated Jira integration
        def jira_create_ticket(ctx, params):
            title = params.get('title', 'Security Alert')
            ticket_id = 'SEC-' + hashlib.md5(title.encode()).hexdigest()[:6].upper()
            return {'ticket_id': ticket_id, 'url': f'https://jira.example.com/browse/{ticket_id}', 'status': 'created'}

        # Simulated email/Slack notification
        def notify_email(ctx, params):
            to = params.get('to', 'soc@example.com')
            subject = params.get('subject', 'Security Alert')
            return {'sent': True, 'to': to, 'subject': subject}

        # Simulated Active Directory integration
        def ad_disable_account(ctx, params):
            user = params.get('user', '')
            return {'user': user, 'disabled': True, 'status': 'success'}

        def ad_reset_password(ctx, params):
            user = params.get('user', '')
            return {'user': user, 'reset': True, 'temp_password': 'Tmp$' + hashlib.md5(user.encode()).hexdigest()[:8]}

        # Simulated firewall/WAF integration
        def firewall_block_ip(ctx, params):
            ip = params.get('ip', '')
            return {'ip': ip, 'blocked': True, 'rule_id': 'AUTO-' + ip.replace('.', '-')}

        # Simulated DNS sinkhole
        def dns_sinkhole(ctx, params):
            domain = params.get('domain', '')
            return {'domain': domain, 'sinkholed': True, 'sinkhole_ip': '127.0.0.1'}

        self.register('virustotal', {'lookup_ip': vt_lookup_ip, 'lookup_hash': vt_lookup_hash})
        self.register('crowdstrike', {'isolate_host': cs_isolate_host, 'get_process_tree': cs_get_process_tree, 'kill_process': cs_kill_process})
        self.register('jira', {'create_ticket': jira_create_ticket})
        self.register('email', {'send': notify_email})
        self.register('activedirectory', {'disable_account': ad_disable_account, 'reset_password': ad_reset_password})
        self.register('firewall', {'block_ip': firewall_block_ip})
        self.register('dns', {'sinkhole': dns_sinkhole})


class PlaybookEngine:
    """
    SOAR playbook execution engine.
    Executes playbooks step-by-step, maintaining a shared context dict.
    Supports: action steps, conditional branching, approval gates,
    timeout handling, and logging of all actions for audit.
    """

    def __init__(
        self,
        registry: Optional[IntegrationRegistry] = None,
        approval_callback: Optional[Callable[[str, str], bool]] = None
    ):
        self._registry = registry or IntegrationRegistry()
        self._approval_callback = approval_callback or (lambda execution_id, step_name: True)  # Auto-approve
        self._executions: dict[str, PlaybookExecution] = {}
        self._playbooks: dict[str, Playbook] = {}

    def register_playbook(self, playbook: Playbook):
        self._playbooks[playbook.playbook_id] = playbook

    def _evaluate_condition(
        self, condition: str, context: dict
    ) -> bool:
        try:
            # Safe evaluation — only allow simple comparisons
            safe_context = {k: v for k, v in context.items() if isinstance(v, (str, int, float, bool, list, dict))}
            return bool(eval(condition, {'__builtins__': {}}, safe_context))
        except Exception:
            return False

    def _execute_step(
        self,
        step: PlaybookStep,
        context: dict,
        execution_id: str
    ) -> tuple[StepStatus, Any]:
        start_time = time.time()
        try:
            if step.requires_approval:
                approved = self._approval_callback(execution_id, step.name)
                if not approved:
                    return StepStatus.SKIPPED, {'reason': 'Approval denied'}

            if step.step_type == PlaybookStepType.WAIT:
                wait_secs = step.parameters.get('seconds', 1)
                time.sleep(min(wait_secs, 2))  # Cap at 2s in simulation
                result = {'waited_seconds': wait_secs}

            elif step.step_type in (PlaybookStepType.ACTION, PlaybookStepType.ENRICH,
                                     PlaybookStepType.REMEDIATE):
                result = self._registry.execute(
                    step.integration, step.action, context, step.parameters
                )

            elif step.step_type == PlaybookStepType.NOTIFY:
                result = self._registry.execute(
                    step.integration or 'email', step.action, context, step.parameters
                )

            elif step.step_type == PlaybookStepType.ESCALATE:
                result = {'escalated': True, 'reason': step.parameters.get('reason', 'Manual review required')}

            elif step.step_type == PlaybookStepType.CONDITION:
                # Condition step just evaluates — routing is handled by caller
                result = {'condition_result': self._evaluate_condition(
                    step.condition or 'True', context
                )}
            else:
                result = {}

            elapsed = time.time() - start_time
            if elapsed > step.timeout_seconds:
                return StepStatus.FAILED, {'error': f'Timeout after {elapsed:.1f}s'}

            if step.output_key and result:
                context[step.output_key] = result

            return StepStatus.COMPLETED, result

        except Exception as e:
            return StepStatus.FAILED, {'error': str(e)}

    def execute_playbook(
        self,
        playbook_id: str,
        alert: Alert
    ) -> PlaybookExecution:
        playbook = self._playbooks.get(playbook_id)
        if not playbook:
            raise ValueError(f'Playbook {playbook_id} not found')

        # Check severity filter
        if playbook.severity_filter and alert.severity not in playbook.severity_filter:
            execution_id = hashlib.md5(f'{playbook_id}{alert.alert_id}'.encode()).hexdigest()[:12]
            return PlaybookExecution(
                execution_id=execution_id, playbook_id=playbook_id,
                playbook_name=playbook.name, alert=alert,
                status=PlaybookStatus.COMPLETED,
                started_at=datetime.utcnow(), completed_at=datetime.utcnow(),
                context={}, step_logs=[],
                actions_taken=['Skipped: severity filter mismatch'],
                outcome_summary='Skipped due to severity filter',
                sla_breached=False
            )

        execution_id = hashlib.md5(f'{playbook_id}{alert.alert_id}{time.time()}'.encode()).hexdigest()[:12]
        context = {
            'alert': alert.__dict__,
            'alert_id': alert.alert_id,
            'source_ip': alert.source_ip,
            'destination_ip': alert.destination_ip,
            'user': alert.user,
            'host': alert.host,
            'severity': alert.severity,
            'iocs': alert.iocs
        }
        step_logs = []
        actions_taken = []
        started_at = datetime.utcnow()
        status = PlaybookStatus.RUNNING

        steps_by_id = {s.step_id: s for s in playbook.steps}
        current_step_id = playbook.entry_step_id
        executed_steps = set()

        while current_step_id and current_step_id not in executed_steps:
            step = steps_by_id.get(current_step_id)
            if not step:
                break
            executed_steps.add(current_step_id)
            step_status, result = self._execute_step(step, context, execution_id)
            log_entry = {
                'step_id': step.step_id,
                'name': step.name,
                'status': step_status.value,
                'result': str(result)[:500],
                'timestamp': datetime.utcnow().isoformat()
            }
            step_logs.append(log_entry)
            actions_taken.append(f'{step.name}: {step_status.value}')

            if step.step_type == PlaybookStepType.ESCALATE:
                status = PlaybookStatus.ESCALATED
                break

            if step_status == StepStatus.COMPLETED:
                # Check condition branching
                if step.step_type == PlaybookStepType.CONDITION:
                    cond_result = context.get(step.output_key, {}).get('condition_result', False)
                    if cond_result:
                        current_step_id = step.on_success
                    else:
                        current_step_id = step.on_failure
                else:
                    current_step_id = step.on_success
            elif step_status == StepStatus.FAILED:
                current_step_id = step.on_failure
            else:
                current_step_id = step.on_success

        if status == PlaybookStatus.RUNNING:
            status = PlaybookStatus.COMPLETED

        completed_at = datetime.utcnow()
        duration_min = (completed_at - started_at).total_seconds() / 60
        sla_breached = duration_min > playbook.sla_minutes
        summary = (
            f'Playbook {playbook.name} {status.value} in {duration_min:.1f}min '
            f'({len(step_logs)} steps executed). '
            f'{"SLA BREACHED" if sla_breached else "SLA met"}.'
        )
        execution = PlaybookExecution(
            execution_id=execution_id, playbook_id=playbook_id,
            playbook_name=playbook.name, alert=alert,
            status=status, started_at=started_at, completed_at=completed_at,
            context=context, step_logs=step_logs,
            actions_taken=actions_taken, outcome_summary=summary,
            sla_breached=sla_breached
        )
        self._executions[execution_id] = execution
        return execution
