class LaplacePrivacyMechanism:
    """
    Laplace mechanism for differential privacy.
    Adds Laplace noise calibrated to sensitivity/epsilon.
    Satisfies (epsilon, 0)-differential privacy.
    For counting queries: sensitivity = 1 (changing one record
    changes count by at most 1).
    """

    def __init__(self, epsilon: float, sensitivity: float = 1.0):
        if epsilon <= 0:
            raise ValueError('Epsilon must be positive')
        self.epsilon = epsilon
        self.sensitivity = sensitivity
        self._scale = sensitivity / epsilon

    def add_noise(
        self, true_value: float
    ) -> float:
        """Add Laplace noise with scale = sensitivity/epsilon."""
        u = secrets.SystemRandom().uniform(-0.5, 0.5)
        noise = -self._scale * math.copysign(1, u) * math.log(1 - 2 * abs(u))
        return true_value + noise

    def add_noise_to_dict(
        self, d: dict[str, int]
    ) -> dict[str, float]:
        return {k: self.add_noise(v) for k, v in d.items()}

    def noise_std(self) -> float:
        """Standard deviation of Laplace noise = sqrt(2) * scale."""
        return math.sqrt(2) * self._scale


class BloomFilterSketch:
    """
    Count-Min Sketch using multiple hash functions for
    privacy-preserving IOC frequency estimation.
    Each client contributes a sketch instead of raw IOCs.
    """

    def __init__(self, width: int = 256, depth: int = 4, seed: int = 42):
        self.width = width
        self.depth = depth
        self.seed = seed
        self.table = [[0] * width for _ in range(depth)]

    def _hash(self, item: str, row: int) -> int:
        digest = hashlib.sha256(f'{self.seed}:{row}:{item}'.encode()).digest()
        return struct.unpack('>I', digest[:4])[0] % self.width

    def add(self, item: str, count: int = 1):
        for row in range(self.depth):
            col = self._hash(item, row)
            self.table[row][col] += count

    def estimate(self, item: str) -> int:
        return min(self.table[row][self._hash(item, row)] for row in range(self.depth))

    def to_flat(self) -> list[int]:
        return [cell for row in self.table for cell in row]

    @classmethod
    def from_flat(cls, flat: list[int], width: int = 256, depth: int = 4) -> 'BloomFilterSketch':
        sketch = cls(width, depth)
        for i in range(depth):
            sketch.table[i] = flat[i * width:(i + 1) * width]
        return sketch

    def add_sketch(self, other: 'BloomFilterSketch'):
        """Merge another sketch (element-wise addition)."""
        for i in range(self.depth):
            for j in range(self.width):
                self.table[i][j] += other.table[i][j]


class SecureAggregationProtocol:
    """
    Simulates secure aggregation using additive secret sharing.
    Each client splits its privatized summary into n shares.
    The server aggregates shares without seeing individual values.
    In a real deployment, this would use cryptographic PRGs or
    homomorphic encryption (e.g., CKKS via TenSEAL).
    """

    def __init__(self, n_clients: int, n_servers: int = 1):
        self.n_clients = n_clients
        self.n_servers = n_servers

    def split_into_shares(
        self, values: dict[str, float], n_shares: int
    ) -> list[dict[str, float]]:
        """Secret-share each value into n_shares using additive sharing."""
        shares = [{} for _ in range(n_shares)]
        for key, value in values.items():
            random_shares = [secrets.SystemRandom().gauss(0, 0.001) for _ in range(n_shares - 1)]
            last_share = value - sum(random_shares)
            for i in range(n_shares - 1):
                shares[i][key] = random_shares[i]
            shares[n_shares - 1][key] = last_share
        return shares

    def reconstruct(
        self, shares_list: list[dict[str, float]]
    ) -> dict[str, float]:
        """Reconstruct values by summing shares from all clients."""
        aggregate: dict[str, float] = defaultdict(float)
        for shares in shares_list:
            for key, value in shares.items():
                aggregate[key] += value
        return dict(aggregate)


class FederatedAnalyticsServer:
    """
    Privacy-preserving federated analytics server for security telemetry.
    Orchestrates:
    1. Clients apply Laplace DP noise to local counts
    2. Clients submit privatized summaries (no raw data leaves)
    3. Server securely aggregates privatized summaries
    4. Server computes federation-wide threat insights
    5. Common IOCs detected across multiple orgs trigger threat intel sharing
    Privacy guarantee: (epsilon, delta)-DP for each round
    """

    def __init__(
        self,
        epsilon_per_round: float = 1.0,
        min_clients_for_ioc: int = 3,    # IOC must appear in >= k clients to share
        sketch_width: int = 256
    ):
        self.epsilon = epsilon_per_round
        self.min_clients_for_ioc = min_clients_for_ioc
        self.sketch_width = sketch_width
        self._received_summaries: list[PrivateSummary] = []
        self._dp_mechanism = LaplacePrivacyMechanism(epsilon_per_round)

    def client_privatize(
        self, telemetry: LocalTelemetry
    ) -> PrivateSummary:
        """
        Run on client side: apply DP noise before sending to server.
        Returns a PrivateSummary with noise-added counts and IOC sketch.
        """
        # Add Laplace noise to alert counts
        noisy_alerts = self._dp_mechanism.add_noise_to_dict(telemetry.alert_counts)
        # Clip negative noisy values (post-processing)
        noisy_alerts = {k: max(v, 0) for k, v in noisy_alerts.items()}

        # Add noise to vuln counts
        noisy_vulns = self._dp_mechanism.add_noise_to_dict(telemetry.vulnerability_counts)
        noisy_vulns = {k: max(v, 0) for k, v in noisy_vulns.items()}

        # Build Count-Min Sketch from IOC hashes (no raw hashes sent)
        sketch = BloomFilterSketch(self.sketch_width, 4)
        for ioc_hash in telemetry.threat_indicator_hashes:
            sketch.add(ioc_hash)

        return PrivateSummary(
            client_id=telemetry.client_id,
            noisy_alert_totals=noisy_alerts,
            private_ioc_sketch={
                f'row_{i}_col_{j}': sketch.table[i][j]
                for i in range(4) for j in range(self.sketch_width)
            },
            noisy_vuln_totals=noisy_vulns,
            privacy_budget_used=self.epsilon,
            noise_scale=self._dp_mechanism._scale
        )

    def receive_summary(self, summary: PrivateSummary):
        self._received_summaries.append(summary)

    def _aggregate_sketches(
        self, summaries: list[PrivateSummary]
    ) -> BloomFilterSketch:
        agg_sketch = BloomFilterSketch(self.sketch_width, 4)
        for summary in summaries:
            for i in range(4):
                for j in range(self.sketch_width):
                    key = f'row_{i}_col_{j}'
                    agg_sketch.table[i][j] += summary.private_ioc_sketch.get(key, 0)
        return agg_sketch

    def _compute_confidence_intervals(
        self,
        aggregate: dict[str, float],
        n_clients: int
    ) -> dict[str, tuple[float, float]]:
        """95% CI based on aggregated Laplace noise: +-1.96*sqrt(n)*noise_std."""
        if not self._received_summaries:
            return {}
        noise_std = self._dp_mechanism.noise_std()
        agg_noise_std = math.sqrt(n_clients) * noise_std
        return {
            k: (round(max(v - 1.96 * agg_noise_std, 0), 2), round(v + 1.96 * agg_noise_std, 2))
            for k, v in aggregate.items()
        }

    def aggregate(
        self,
        known_ioc_hashes: Optional[list[str]] = None
    ) -> FederatedInsight:
        """Aggregate all received summaries into a FederatedInsight."""
        if not self._received_summaries:
            raise ValueError('No summaries received')

        n = len(self._received_summaries)

        # Aggregate alert counts
        agg_alerts: dict[str, float] = defaultdict(float)
        for s in self._received_summaries:
            for k, v in s.noisy_alert_totals.items():
                agg_alerts[k] += v
        agg_alerts = {k: round(v, 2) for k, v in agg_alerts.items()}

        # Aggregate vuln counts
        agg_vulns: dict[str, float] = defaultdict(float)
        for s in self._received_summaries:
            for k, v in s.noisy_vuln_totals.items():
                agg_vulns[k] += v
        agg_vulns = {k: round(v, 2) for k, v in agg_vulns.items()}

        # Aggregate IOC sketches and check for common IOCs
        agg_sketch = self._aggregate_sketches(self._received_summaries)
        common_ioc_count = {}
        if known_ioc_hashes:
            for ioc_hash in known_ioc_hashes:
                estimated_count = agg_sketch.estimate(ioc_hash)
                if estimated_count >= self.min_clients_for_ioc:
                    common_ioc_count[ioc_hash[:16]] = estimated_count  # Truncate for privacy

        ci = self._compute_confidence_intervals(agg_alerts, n)

        # Detect anomalous spikes (> 2x expected per client)
        expected_per_client = 10  # Configurable baseline
        anomalies = [
            alert_type for alert_type, total in agg_alerts.items()
            if total / max(n, 1) > expected_per_client * 2
        ]

        threat_intel = {
            'common_iocs_detected': len(common_ioc_count),
            'top_alert_types': sorted(agg_alerts.items(), key=lambda x: -x[1])[:5],
            'top_vulnerabilities': sorted(agg_vulns.items(), key=lambda x: -x[1])[:5],
            'participating_orgs': n
        }

        return FederatedInsight(
            total_participants=n,
            aggregated_alert_counts=agg_alerts,
            common_ioc_count=common_ioc_count,
            aggregated_vuln_counts=agg_vulns,
            privacy_epsilon_per_round=self.epsilon,
            confidence_interval_95=ci,
            threat_intelligence_summary=threat_intel,
            anomaly_alerts=anomalies
        )
