class IOCExtractor:
    """
    Extracts Indicators of Compromise from STIX indicator patterns.
    Supports STIX Pattern Language subset:
    - [ipv4-addr:value = '1.2.3.4']
    - [domain-name:value = 'evil.com']
    - [file:hashes.MD5 = 'abc123']
    - [url:value = 'http://evil.com/path']
    """

    def extract_iocs(
        self, indicator: dict
    ) -> list[dict]:
        pattern = indicator.get('pattern', '')
        iocs = []
        import re
        # IPv4 addresses
        for ip in re.findall(r"ipv4-addr:value\s*=\s*'([^']+)'", pattern):
            iocs.append({'type': 'ipv4', 'value': ip, 'indicator_id': indicator.get('id')})
        # Domain names
        for domain in re.findall(r"domain-name:value\s*=\s*'([^']+)'", pattern):
            iocs.append({'type': 'domain', 'value': domain, 'indicator_id': indicator.get('id')})
        # URLs
        for url in re.findall(r"url:value\s*=\s*'([^']+)'", pattern):
            iocs.append({'type': 'url', 'value': url, 'indicator_id': indicator.get('id')})
        # File hashes MD5
        for h in re.findall(r"file:hashes\.MD5\s*=\s*'([^']+)'", pattern):
            iocs.append({'type': 'md5', 'value': h.lower(), 'indicator_id': indicator.get('id')})
        # File hashes SHA256
        for h in re.findall(r"file:hashes\.SHA-256\s*=\s*'([^']+)'", pattern):
            iocs.append({'type': 'sha256', 'value': h.lower(), 'indicator_id': indicator.get('id')})
        # Email addresses
        for email in re.findall(r"email-message:from_ref\.value\s*=\s*'([^']+)'", pattern):
            iocs.append({'type': 'email', 'value': email, 'indicator_id': indicator.get('id')})
        return iocs


class KnowledgeGraph:
    """
    In-memory directed labeled knowledge graph for STIX objects and relationships.
    Nodes: STIX domain objects (malware, threat actors, indicators, etc.)
    Edges: STIX relationship objects
    Supports multi-hop traversal for threat actor -> TTP -> target pivoting.
    """

    def __init__(self):
        self._nodes: dict[str, STIXObject] = {}
        self._edges: dict[str, ThreatRelationship] = {}
        self._adj: dict[str, list[str]] = defaultdict(list)   # source -> [rel_id]
        self._rev_adj: dict[str, list[str]] = defaultdict(list)  # target -> [rel_id]
        self._type_index: dict[str, list[str]] = defaultdict(list)  # type -> [obj_id]
        self._name_index: dict[str, str] = {}  # name.lower() -> obj_id

    def add_node(self, obj: STIXObject):
        self._nodes[obj.id] = obj
        self._type_index[obj.type].append(obj.id)
        if obj.name:
            self._name_index[obj.name.lower()] = obj.id

    def add_edge(self, rel: ThreatRelationship):
        self._edges[rel.id] = rel
        self._adj[rel.source_ref].append(rel.id)
        self._rev_adj[rel.target_ref].append(rel.id)

    def get_node(
        self, node_id: str
    ) -> Optional[STIXObject]:
        return self._nodes.get(node_id)

    def get_by_name(
        self, name: str
    ) -> Optional[STIXObject]:
        node_id = self._name_index.get(name.lower())
        return self._nodes.get(node_id) if node_id else None

    def get_by_type(
        self, obj_type: str
    ) -> list[STIXObject]:
        return [self._nodes[i] for i in self._type_index.get(obj_type, []) if i in self._nodes]

    def neighbors(
        self, node_id: str, direction: str = 'outbound'
    ) -> list[tuple[ThreatRelationship, STIXObject]]:
        """Returns (relationship, neighbor_object) pairs."""
        result = []
        if direction in ('outbound', 'both'):
            for rel_id in self._adj.get(node_id, []):
                rel = self._edges.get(rel_id)
                if rel and rel.target_ref in self._nodes:
                    result.append((rel, self._nodes[rel.target_ref]))
        if direction in ('inbound', 'both'):
            for rel_id in self._rev_adj.get(node_id, []):
                rel = self._edges.get(rel_id)
                if rel and rel.source_ref in self._nodes:
                    result.append((rel, self._nodes[rel.source_ref]))
        return result

    def bfs(
        self, start_id: str, max_hops: int = 2,
        rel_type_filter: Optional[set[str]] = None
    ) -> tuple[list[STIXObject], list[ThreatRelationship]]:
        """BFS traversal up to max_hops from start_id."""
        visited_nodes: set[str] = {start_id}
        visited_rels: set[str] = set()
        queue = [(start_id, 0)]
        result_nodes: list[STIXObject] = []
        result_rels: list[ThreatRelationship] = []
        while queue:
            current_id, depth = queue.pop(0)
            if depth >= max_hops:
                continue
            for rel, neighbor in self.neighbors(current_id, 'both'):
                if rel_type_filter and rel.relationship_type not in rel_type_filter:
                    continue
                if rel.id not in visited_rels:
                    visited_rels.add(rel.id)
                    result_rels.append(rel)
                if neighbor.id not in visited_nodes:
                    visited_nodes.add(neighbor.id)
                    result_nodes.append(neighbor)
                    queue.append((neighbor.id, depth + 1))
        return result_nodes, result_rels


class STIXBundleIngester:
    """Parses STIX 2.1 bundles and populates the knowledge graph."""

    def __init__(self, graph: KnowledgeGraph, ioc_extractor: IOCExtractor):
        self._graph = graph
        self._ioc_extractor = ioc_extractor
        self._ioc_index: dict[str, list[dict]] = defaultdict(list)  # value -> [ioc dicts]

    def ingest_bundle(
        self, bundle: dict
    ) -> dict[str, int]:
        stats = defaultdict(int)
        objects = bundle.get('objects', [])
        for obj in objects:
            obj_type = obj.get('type', '')
            if obj_type == 'relationship':
                rel = ThreatRelationship(
                    id=obj.get('id', ''),
                    relationship_type=obj.get('relationship_type', ''),
                    source_ref=obj.get('source_ref', ''),
                    target_ref=obj.get('target_ref', ''),
                    description=obj.get('description'),
                    start_time=obj.get('start_time'),
                    stop_time=obj.get('stop_time'),
                    confidence=obj.get('confidence', 50)
                )
                self._graph.add_edge(rel)
                stats['relationships'] += 1
            elif obj_type == 'bundle':
                sub_stats = self.ingest_bundle(obj)
                for k, v in sub_stats.items():
                    stats[k] += v
            else:
                stix_obj = STIXObject(
                    id=obj.get('id', ''),
                    type=obj_type,
                    spec_version=obj.get('spec_version', '2.1'),
                    created=obj.get('created', ''),
                    modified=obj.get('modified', ''),
                    name=obj.get('name'),
                    description=obj.get('description'),
                    labels=obj.get('labels', []),
                    confidence=obj.get('confidence', 50),
                    raw=obj
                )
                self._graph.add_node(stix_obj)
                stats[obj_type] += 1
                # Extract IOCs from indicators
                if obj_type == 'indicator':
                    for ioc in self._ioc_extractor.extract_iocs(obj):
                        self._ioc_index[ioc['value'].lower()].append(ioc)
        return dict(stats)

    def lookup_ioc(
        self, value: str
    ) -> list[dict]:
        return self._ioc_index.get(value.lower(), [])


class ThreatIntelligencePlatform:
    """
    Threat Intelligence Platform (TIP) with STIX 2.1 ingestion and knowledge graph.
    Features:
    - Ingest multiple STIX bundles from files or dicts
    - IOC lookup (IP, domain, hash, URL, email)
    - Threat actor TTP profiling
    - Campaign-to-actor attribution
    - Attack pattern to mitigation mapping
    - Multi-hop graph traversal for pivoting
    - Threat score computation
    - MITRE ATT&CK technique extraction
    Outputs structured TIPQueryResult for SOC integration.
    """

    def __init__(self):
        self._graph = KnowledgeGraph()
        self._ioc_extractor = IOCExtractor()
        self._ingester = STIXBundleIngester(self._graph, self._ioc_extractor)
        self._ingest_stats: list[dict] = []

    def ingest_bundle(
        self, bundle: dict
    ) -> dict[str, int]:
        stats = self._ingester.ingest_bundle(bundle)
        self._ingest_stats.append(stats)
        return stats

    def ingest_file(
        self, file_path: str
    ) -> dict[str, int]:
        with open(file_path, 'r') as f:
            bundle = json.load(f)
        return self.ingest_bundle(bundle)

    def _compute_threat_score(
        self, objects: list[STIXObject], relationships: list[ThreatRelationship]
    ) -> float:
        if not objects:
            return 0.0
        confidences = [o.confidence for o in objects if o.confidence]
        avg_conf = sum(confidences) / len(confidences) if confidences else 50
        # Boost score for high-value types
        high_value = {'malware', 'threat-actor', 'attack-pattern', 'intrusion-set'}
        type_boost = sum(10 for o in objects if o.type in high_value)
        rel_boost = len(relationships) * 2
        return min(avg_conf + type_boost + rel_boost, 100.0)

    def _extract_mitre_techniques(
        self, objects: list[STIXObject]
    ) -> list[str]:
        techniques = []
        for obj in objects:
            if obj.type == 'attack-pattern':
                raw = obj.raw
                ext_refs = raw.get('external_references', [])
                for ref in ext_refs:
                    if ref.get('source_name') == 'mitre-attack':
                        ext_id = ref.get('external_id', '')
                        if ext_id.startswith('T'):
                            techniques.append(ext_id)
        return list(set(techniques))

    def query(
        self, tip_query: TIPQuery
    ) -> TIPQueryResult:
        matched: list[STIXObject] = []
        ioc_matches: list[dict] = []
        rels: list[ThreatRelationship] = []
        related: list[STIXObject] = []

        if tip_query.query_type == 'ioc_lookup':
            ioc_matches = self._ingester.lookup_ioc(tip_query.query_value)
            for ioc in ioc_matches:
                ind = self._graph.get_node(ioc['indicator_id'])
                if ind and ind not in matched:
                    matched.append(ind)

        elif tip_query.query_type == 'actor_ttps':
            actor = self._graph.get_by_name(tip_query.query_value)
            if actor:
                matched = [actor]
                related, rels = self._graph.bfs(
                    actor.id, max_hops=tip_query.max_hops,
                    rel_type_filter={'uses', 'attributed-to'}
                )

        elif tip_query.query_type == 'campaign_actors':
            campaign = self._graph.get_by_name(tip_query.query_value)
            if campaign:
                matched = [campaign]
                related, rels = self._graph.bfs(
                    campaign.id, max_hops=tip_query.max_hops,
                    rel_type_filter={'attributed-to', 'uses'}
                )

        elif tip_query.query_type == 'actor_targets':
            actor = self._graph.get_by_name(tip_query.query_value)
            if actor:
                matched = [actor]
                related, rels = self._graph.bfs(
                    actor.id, max_hops=tip_query.max_hops,
                    rel_type_filter={'targets'}
                )

        elif tip_query.query_type == 'mitigations':
            # Find attack pattern and then related mitigations
            ap = self._graph.get_by_name(tip_query.query_value)
            if not ap:
                aps = self._graph.get_by_type('attack-pattern')
                ap = next((a for a in aps if tip_query.query_value.upper() in
                           str(a.raw.get('external_references', ''))), None)
            if ap:
                matched = [ap]
                related, rels = self._graph.bfs(
                    ap.id, max_hops=1,
                    rel_type_filter={'mitigates'}
                )

        all_objects = matched + related
        threat_score = self._compute_threat_score(all_objects, rels)
        mitre_techniques = self._extract_mitre_techniques(all_objects)

        # Collect mitigations
        mitigations = [
            o.name or o.description or o.id
            for o in related if o.type == 'course-of-action'
        ]

        n_matched = len(matched)
        n_related = len(related)
        summary = (
            f'Query [{tip_query.query_type}] for "{tip_query.query_value}": '
            f'{n_matched} direct match(es), {n_related} related object(s), '
            f'{len(rels)} relationship(s), threat score {threat_score:.1f}/100, '
            f'{len(mitre_techniques)} MITRE technique(s) identified.'
        )

        return TIPQueryResult(
            query=tip_query,
            matched_objects=matched,
            relationships=rels,
            related_objects=related,
            ioc_matches=ioc_matches,
            threat_score=round(threat_score, 2),
            mitre_techniques=mitre_techniques,
            recommended_mitigations=mitigations,
            summary=summary
        )

    def get_platform_stats(self) -> dict:
        total_by_type = defaultdict(int)
        for stats in self._ingest_stats:
            for k, v in stats.items():
                total_by_type[k] += v
        return {
            'total_bundles_ingested': len(self._ingest_stats),
            'total_objects_by_type': dict(total_by_type),
