import time
import jwt
import hashlib
import json
from datetime import datetime, timedelta
from collections import defaultdict, deque
from typing import Dict, Optional, Tuple
from dataclasses import dataclass, field
import re
import statistics

@dataclass
class APIRequest:
    request_id: str
    timestamp: float
    client_ip: str
    user_id: Optional[str]
    method: str
    path: str
    headers: Dict[str, str]
    body_size: int
    token: Optional[str] = None

@dataclass
class GatewayDecision:
    allowed: bool
    reason: str
    threat_score: float
    action: str  # allow, rate_limit, block, challenge


class JWTValidator:
    def __init__(self, secret_key: str, algorithm: str = "HS256"):
        self.secret_key = secret_key
        self.algorithm = algorithm
        self.revoked_tokens = set()

    def validate(self, token: str) -> Tuple[bool, Optional[dict], str]:
        try:
            payload = jwt.decode(
                token, self.secret_key, algorithms=[self.algorithm],
                options={"verify_exp": True, "verify_iat": True}
            )
            jti = payload.get("jti", "")
            if jti in self.revoked_tokens:
                return False, None, "TOKEN_REVOKED"
            return True, payload, "OK"
        except jwt.ExpiredSignatureError:
            return False, None, "TOKEN_EXPIRED"
        except jwt.InvalidTokenError as e:
            return False, None, f"TOKEN_INVALID:{str(e)}"

    def revoke(self, jti: str):
        self.revoked_tokens.add(jti)


class RateLimiter:
    def __init__(self, requests_per_minute: int = 60, burst: int = 10):
        self.rpm = requests_per_minute
        self.burst = burst
        self.windows: Dict[str, deque] = defaultdict(deque)
        self.blocked_until: Dict[str, float] = {}

    def is_allowed(self, key: str) -> Tuple[bool, str]:
        now = time.time()
        if key in self.blocked_until and now < self.blocked_until[key]:
            return False, f"RATE_LIMITED until {datetime.fromtimestamp(self.blocked_until[key])}"
        window = self.windows[key]
        cutoff = now - 60
        while window and window[0] < cutoff:
            window.popleft()
        if len(window) >= self.rpm:
            self.blocked_until[key] = now + 300  # 5 min block
            return False, "RATE_LIMIT_EXCEEDED"
        window.append(now)
        return True, "OK"


class RequestAnomalyDetector:
    """
    Detects anomalous API request patterns indicating attacks:
    - Rapid endpoint enumeration
    - Unusual payload sizes
    - Suspicious path patterns (SQLi, path traversal, LFI)
    - Abnormal request timing
    """
    def __init__(self):
        self.ip_paths: Dict[str, deque] = defaultdict(lambda: deque(maxlen=100))
        self.ip_body_sizes: Dict[str, deque] = defaultdict(lambda: deque(maxlen=50))
        self.ATTACK_PATTERNS = [
            (re.compile(r"('|--|;|\bOR\b|\bAND\b|UNION|SELECT|INSERT|DROP)", re.I), "SQL_INJECTION", 0.8),
            (re.compile(r"(\.\./|\.\.\\\/|%2e%2e)", re.I), "PATH_TRAVERSAL", 0.7),
            (re.compile(r"(<script|javascript:|onerror=|onload=)", re.I), "XSS", 0.75),
            (re.compile(r"(etc/passwd|/etc/shadow|/proc/self)", re.I), "LFI", 0.9),
            (re.compile(r"(;|\||&&|`|\$\()", re.I), "CMD_INJECTION", 0.85),
        ]

    def check_path_patterns(self, path: str) -> Tuple[float, str]:
        for pattern, attack_type, score in self.ATTACK_PATTERNS:
            if pattern.search(path):
                return score, attack_type
        return 0.0, "CLEAN"

    def check_enumeration(self, client_ip: str, path: str) -> float:
        history = self.ip_paths[client_ip]
        history.append(path)
        if len(history) < 10:
            return 0.0
        unique_paths = len(set(list(history)[-20:]))
        enumeration_score = unique_paths / 20.0
        return enumeration_score if enumeration_score > 0.8 else 0.0

    def check_payload_anomaly(self, client_ip: str, body_size: int) -> float:
        history = self.ip_body_sizes[client_ip]
        history.append(body_size)
        if len(history) < 5:
            return 0.0
        sizes = list(history)
        mean = statistics.mean(sizes)
        if mean == 0:
            return 0.0
        stdev = statistics.stdev(sizes) if len(sizes) > 1 else 0
        if stdev > 0 and (body_size - mean) / stdev > 3:
            return 0.6  # Z-score > 3 sigma
        if body_size > 1_000_000:  # 1MB
            return 0.7
        return 0.0

    def score(self, request: APIRequest) -> Tuple[float, str]:
        path_score, attack_type = self.check_path_patterns(request.path)
        enum_score = self.check_enumeration(request.client_ip, request.path)
        payload_score = self.check_payload_anomaly(request.client_ip, request.body_size)
        total = min(1.0, max(path_score, enum_score, payload_score))
        reason = attack_type if path_score > 0 else ("ENUMERATION" if enum_score > 0 else "PAYLOAD_ANOMALY")
        return total, reason


class APISecurityGateway:
    def __init__(self, jwt_secret: str):
        self.jwt_validator = JWTValidator(jwt_secret)
        self.rate_limiter = RateLimiter(requests_per_minute=60)
        self.anomaly_detector = RequestAnomalyDetector()
        self.blocked_ips: Dict[str, float] = {}
        self.stats = defaultdict(int)

    def process_request(self, request: APIRequest) -> GatewayDecision:
        # Check IP block list
        if request.client_ip in self.blocked_ips:
            if time.time() < self.blocked_ips[request.client_ip]:
                self.stats["blocked"] += 1
                return GatewayDecision(False, "IP_BLOCKED", 1.0, "block")

        # JWT validation (for protected endpoints)
        if not request.path.startswith("/public/"):
            if not request.token:
                return GatewayDecision(False, "NO_TOKEN", 0.5, "block")
            valid, payload, reason = self.jwt_validator.validate(request.token)
            if not valid:
                self.stats["auth_failures"] += 1
                return GatewayDecision(False, reason, 0.6, "block")
            request.user_id = payload.get("sub")

        # Rate limiting
        rl_key = request.client_ip
        allowed, rl_reason = self.rate_limiter.is_allowed(rl_key)
        if not allowed:
            self.stats["rate_limited"] += 1
            return GatewayDecision(False, rl_reason, 0.7, "rate_limit")

        # Anomaly detection
        threat_score, threat_reason = self.anomaly_detector.score(request)
        if threat_score >= 0.8:
            self.blocked_ips[request.client_ip] = time.time() + 3600  # 1hr block
            self.stats["threat_blocked"] += 1
            return GatewayDecision(False, f"THREAT:{threat_reason}", threat_score, "block")
        elif threat_score >= 0.5:
            self.stats["challenged"] += 1
            return GatewayDecision(False, f"SUSPICIOUS:{threat_reason}", threat_score, "challenge")

        self.stats["allowed"] += 1
        return GatewayDecision(True, "OK", threat_score, "allow")

    def report(self):
        print("\n=== API Gateway Security Report ===")
        for k, v in self.stats.items():
            print(f"  {k}: {v}")
        print(f"  blocked_ips: {len(self.blocked_ips)}")


if __name__ == "__main__":
    SECRET = "super-secret-key-for-demo-only"
    gateway = APISecurityGateway(SECRET)

    # Create valid token
    token = jwt.encode({"sub": "user123", "jti": "abc", "exp": datetime.utcnow() + timedelta(hours=1)}, SECRET, algorithm="HS256")

    test_requests = [
        APIRequest("r1", time.time(), "10.0.0.1", None, "GET", "/api/data", {}, 0, token),
        APIRequest("r2", time.time(), "10.0.0.2", None, "GET", "/api/users?id=1 OR 1=1", {}, 0, token),
        APIRequest("r3", time.time(), "10.0.0.3", None, "GET", "/public/health", {}, 0, None),
        APIRequest("r4", time.time(), "10.0.0.4", None, "POST", "/api/upload", {}, 2_000_000, token),
        APIRequest("r5", time.time(), "10.0.0.5", None, "GET", "/api/data", {}, 0, None),
    ]
    for req in test_requests:
        decision = gateway.process_request(req)
        print(f"[{req.request_id}] {req.path} -> {decision.action.upper()} | {decision.reason} | score={decision.threat_score:.2f}")

    gateway.report()
