import re
import os
import time
import logging
import functools
import subprocess
from dataclasses import dataclass, field
from typing import Callable, Dict, List, Optional, Any
from datetime import datetime
from enum import Enum

class AttackType(Enum):
    SQL_INJECTION = "sql_injection"
    COMMAND_INJECTION = "command_injection"
    PATH_TRAVERSAL = "path_traversal"
    XSS = "xss"
    LDAP_INJECTION = "ldap_injection"
    XML_INJECTION = "xml_injection"

class RASPAction(Enum):
    BLOCK = "block"
    LOG = "log"
    ALERT = "alert"

@dataclass
class RASPEvent:
    timestamp: str
    attack_type: AttackType
    severity: str
    input_value: str
    function_name: str
    action_taken: RASPAction
    blocked: bool
    request_id: Optional[str] = None
    stack_hint: Optional[str] = None


class RASPDetector:
    """
    Runtime Application Self-Protection for Python.
    Instruments DB queries, OS commands, and file operations
    to detect and block injection attacks in real-time.
    Usage: wrap DB execute(), os.system(), open() with RASP guards.
    """
    SQL_PATTERNS = [
        re.compile(r"(\b(UNION|SELECT|INSERT|UPDATE|DELETE|DROP|ALTER|CREATE|EXEC)\b)", re.I),
        re.compile(r"('\s*OR\s*'?\d|'\s*OR\s*1\s*=\s*1)", re.I),
        re.compile(r"(--|;\s*--|/\*.*?\*/)"),
        re.compile(r"(\bxp_cmdshell\b|\bSYSTEM_USER\b|\bDATABASE\(\))", re.I),
        re.compile(r"(SLEEP\(|BENCHMARK\(|WAITFOR DELAY)", re.I),
    ]
    CMD_PATTERNS = [
        re.compile(r"([;&|`]|\$\(|\$\{)"),
        re.compile(r"\b(cat|wget|curl|nc|netcat|python|perl|bash|sh|cmd|powershell)\b", re.I),
        re.compile(r"(\.\./|/etc/passwd|/etc/shadow|cmd\.exe)"),
        re.compile(r"(>|>>|<|\|)\s*\S"),
    ]
    PATH_PATTERNS = [
        re.compile(r"(\.\./|\.\.\\|\.\./|%2e%2e)", re.I),
        re.compile(r"(/etc/passwd|/etc/shadow|/proc/self|/var/www)"),
        re.compile(r"(\\windows\\|system32|win\.ini)", re.I),
        re.compile(r"(%00|\x00)"),  # null byte injection
    ]
    XSS_PATTERNS = [
        re.compile(r"(<script|</script|javascript:|onerror=|onload=|<iframe)", re.I),
        re.compile(r"(document\.cookie|document\.write|window\.location)", re.I),
    ]
    LDAP_PATTERNS = [
        re.compile(r"([)(|*\\]|\\00)"),
    ]

    def __init__(self, mode: RASPAction = RASPAction.BLOCK, log_file: str = "/tmp/rasp_events.log"):
        self.mode = mode
        self.events: List[RASPEvent] = []
        logging.basicConfig(filename=log_file, level=logging.WARNING,
                            format='%(asctime)s %(message)s')
        self.logger = logging.getLogger("RASP")
        self.stats: Dict[str, int] = {t.value: 0 for t in AttackType}
        self.request_context: Optional[str] = None

    def set_request_context(self, request_id: str):
        self.request_context = request_id

    def _detect(self, value: str, attack_type: AttackType) -> bool:
        patterns_map = {
            AttackType.SQL_INJECTION: self.SQL_PATTERNS,
            AttackType.COMMAND_INJECTION: self.CMD_PATTERNS,
            AttackType.PATH_TRAVERSAL: self.PATH_PATTERNS,
            AttackType.XSS: self.XSS_PATTERNS,
            AttackType.LDAP_INJECTION: self.LDAP_PATTERNS,
        }
        patterns = patterns_map.get(attack_type, [])
        return any(p.search(str(value)) for p in patterns)

    def _handle(self, value: str, attack_type: AttackType,
                 fn_name: str, severity: str = "HIGH") -> bool:
        event = RASPEvent(
            timestamp=datetime.utcnow().isoformat() + "Z",
            attack_type=attack_type,
            severity=severity,
            input_value=str(value)[:200],
            function_name=fn_name,
            action_taken=self.mode,
            blocked=self.mode == RASPAction.BLOCK,
            request_id=self.request_context
        )
        self.events.append(event)
        self.stats[attack_type.value] += 1
        log_msg = (f"RASP [{event.action_taken.value.upper()}] {attack_type.value} "
                   f"in {fn_name}: {str(value)[:80]}")
        self.logger.warning(log_msg)
        print(f"[RASP] {log_msg}")
        if self.mode == RASPAction.BLOCK:
            raise SecurityException(f"RASP: {attack_type.value} blocked in {fn_name}")
        return True

    def check_sql(self, query: str, fn_name: str = "db_execute") -> str:
        if self._detect(query, AttackType.SQL_INJECTION):
            self._handle(query, AttackType.SQL_INJECTION, fn_name, "CRITICAL")
        return query

    def check_command(self, cmd: Any, fn_name: str = "os_execute") -> Any:
        cmd_str = cmd if isinstance(cmd, str) else ' '.join(str(c) for c in cmd)
        if self._detect(cmd_str, AttackType.COMMAND_INJECTION):
            self._handle(cmd_str, AttackType.COMMAND_INJECTION, fn_name, "CRITICAL")
        return cmd

    def check_path(self, path: str, fn_name: str = "file_open",
                    allowed_base: Optional[str] = None) -> str:
        if self._detect(path, AttackType.PATH_TRAVERSAL):
            self._handle(path, AttackType.PATH_TRAVERSAL, fn_name, "HIGH")
        # Canonicalize and enforce base path
        if allowed_base:
            real_path = os.path.realpath(os.path.join(allowed_base, path.lstrip('/')))
            real_base = os.path.realpath(allowed_base)
            if not real_path.startswith(real_base):
                self._handle(path, AttackType.PATH_TRAVERSAL, fn_name + "_escape", "CRITICAL")
        return path

    def check_xss(self, value: str, fn_name: str = "render_output") -> str:
        if self._detect(value, AttackType.XSS):
            self._handle(value, AttackType.XSS, fn_name, "MEDIUM")
        return value

    # --- Decorators ---
    def protect_db(self, fn: Callable) -> Callable:
        @functools.wraps(fn)
        def wrapper(query, *args, **kwargs):
            self.check_sql(str(query), fn.__name__)
            return fn(query, *args, **kwargs)
        return wrapper

    def protect_cmd(self, fn: Callable) -> Callable:
        @functools.wraps(fn)
        def wrapper(cmd, *args, **kwargs):
            self.check_command(cmd, fn.__name__)
            return fn(cmd, *args, **kwargs)
        return wrapper

    def protect_file(self, allowed_base: str = "/var/app/data") -> Callable:
        def decorator(fn: Callable) -> Callable:
            @functools.wraps(fn)
            def wrapper(path, *args, **kwargs):
                self.check_path(str(path), fn.__name__, allowed_base)
                return fn(path, *args, **kwargs)
            return wrapper
        return decorator

    def stats_report(self):
        print("\n=== RASP Runtime Statistics ===")
        print(f"Mode: {self.mode.value} | Total events: {len(self.events)}")
        for attack_type, count in self.stats.items():
            if count > 0:
                print(f"  {attack_type}: {count} detections")
        if self.events:
            print("\nRecent events:")
            for e in self.events[-5:]:
                print(f"  [{e.severity}] {e.attack_type.value} in {e.function_name}: "
                      f"{e.input_value[:60]}")


class SecurityException(Exception):
    pass


# Example integration
rasp = RASPDetector(mode=RASPAction.BLOCK)

@rasp.protect_db
def execute_query(query: str, params: tuple = ()):
    """Simulated DB query (RASP-protected)."""
    print(f"  [DB] Executing: {query} with {params}")
    return [{"result": "data"}]

@rasp.protect_cmd
def run_command(cmd: str):
    """Simulated OS command (RASP-protected)."""
    print(f"  [OS] Running: {cmd}")
    return "output"


if __name__ == "__main__":
    print("=== RASP Demo ===")
    rasp.set_request_context("REQ-001")
    # Safe queries
    try:
        execute_query("SELECT name FROM users WHERE id = ?", (42,))
        print("Safe query: OK")
    except SecurityException as e:
        print(f"Blocked: {e}")
    # SQL injection attempt
    try:
        execute_query("SELECT * FROM users WHERE name = 'admin' OR 1=1--")
    except SecurityException as e:
        print(f"Blocked SQLi: {e}")
    # Command injection attempt
    try:
        run_command("ls /var/log; cat /etc/passwd")
    except SecurityException as e:
        print(f"Blocked CMDi: {e}")
    # Path traversal
    try:
        rasp.check_path("../../etc/passwd", "file_read", "/var/app/data")
    except SecurityException as e:
        print(f"Blocked path traversal: {e}")
    # Safe path
    try:
        rasp.check_path("reports/q1.csv", "file_read", "/var/app/data")
        print("Safe path: OK")
    except SecurityException as e:
        print(f"Blocked: {e}")
    rasp.stats_report()
```

