import json
import re
import hashlib
from dataclasses import dataclass, field
from typing import List, Dict, Optional
from enum import Enum

class Severity(Enum):
    CRITICAL = "CRITICAL"
    HIGH = "HIGH"
    MEDIUM = "MEDIUM"
    LOW = "LOW"
    INFO = "INFO"

@dataclass
class Finding:
    rule_id: str
    severity: Severity
    title: str
    description: str
    resource: str
    remediation: str
    cve: Optional[str] = None
    cvss_score: float = 0.0

@dataclass
class ScanResult:
    target: str
    scan_type: str
    findings: List[Finding] = field(default_factory=list)
    passed_checks: int = 0
    failed_checks: int = 0

    def summary(self) -> Dict:
        by_sev = {s.value: 0 for s in Severity}
        for f in self.findings:
            by_sev[f.severity.value] += 1
        return {
            "target": self.target,
            "scan_type": self.scan_type,
            "total_findings": len(self.findings),
            "by_severity": by_sev,
            "passed_checks": self.passed_checks,
            "risk_score": self._risk_score(),
        }

    def _risk_score(self) -> float:
        weights = {Severity.CRITICAL: 10, Severity.HIGH: 7,
                   Severity.MEDIUM: 4, Severity.LOW: 1, Severity.INFO: 0}
        return min(100, sum(weights[f.severity] for f in self.findings))


class DockerfileScanner:
    """Scans Dockerfile for security misconfigurations."""

    DANGEROUS_CAPABILITIES = [
        "NET_ADMIN", "SYS_ADMIN", "SYS_PTRACE", "ALL"
    ]
    SENSITIVE_ENV_PATTERNS = [
        r'(?i)(password|secret|key|token|api_key|private)\s*=\s*\S+',
        r'(?i)AWS_SECRET', r'(?i)GITHUB_TOKEN',
    ]

    def scan(self, dockerfile_content: str, image_name: str = "Dockerfile") -> ScanResult:
        result = ScanResult(target=image_name, scan_type="dockerfile")
        lines = dockerfile_content.strip().split("\n")
        checks = [
            self._check_root_user,
            self._check_latest_tag,
            self._check_sensitive_env,
            self._check_add_vs_copy,
            self._check_curl_pipe_bash,
            self._check_no_healthcheck,
            self._check_privileged,
            self._check_secrets_in_run,
        ]
        for check in checks:
            finding = check(dockerfile_content, lines)
            if finding:
                result.findings.append(finding)
                result.failed_checks += 1
            else:
                result.passed_checks += 1
        return result

    def _check_root_user(self, content, lines) -> Optional[Finding]:
        has_user = any(l.strip().upper().startswith("USER ") and
                       not l.strip().upper().startswith("USER ROOT") and
                       not l.strip().upper().startswith("USER 0")
                       for l in lines)
        runs_as_root = not any(l.strip().upper().startswith("USER ") for l in lines)
        explicit_root = any(re.match(r'^USER\s+(root|0)\s*$', l.strip(), re.I)
                            for l in lines)
        if runs_as_root or explicit_root:
            return Finding(
                rule_id="DF001", severity=Severity.HIGH,
                title="Container runs as root",
                description="No non-root USER directive found. Container runs as root.",
                resource="Dockerfile",
                remediation="Add 'USER nonroot' or create a dedicated user: RUN useradd -r appuser && USER appuser"
            )
        return None

    def _check_latest_tag(self, content, lines) -> Optional[Finding]:
        for line in lines:
            if re.match(r'^FROM\s+\S+:latest', line.strip(), re.I) or \
               re.match(r'^FROM\s+[^:]+$', line.strip(), re.I):
                return Finding(
                    rule_id="DF002", severity=Severity.MEDIUM,
                    title="Image uses 'latest' or unversioned tag",
                    description="Unpinned base images can pull in vulnerable versions.",
                    resource=line.strip(),
                    remediation="Pin to a specific digest: FROM ubuntu:22.04@sha256:<hash>"
                )
        return None

    def _check_sensitive_env(self, content, lines) -> Optional[Finding]:
        for line in lines:
            if line.strip().upper().startswith(("ENV ", "ARG ")):
                for pattern in self.SENSITIVE_ENV_PATTERNS:
                    if re.search(pattern, line):
                        return Finding(
                            rule_id="DF003", severity=Severity.CRITICAL,
                            title="Sensitive data in ENV/ARG directive",
                            description=f"Potential secret found in: {line.strip()}",
                            resource=line.strip(),
                            remediation="Use Docker secrets or build-time secret mounts: --secret id=mysecret"
                        )
        return None

    def _check_add_vs_copy(self, content, lines) -> Optional[Finding]:
        for line in lines:
            if line.strip().upper().startswith("ADD ") and \
               not re.search(r'\.tar\.', line):
                return Finding(
                    rule_id="DF004", severity=Severity.LOW,
                    title="ADD instruction used instead of COPY",
                    description="ADD can auto-extract archives and fetch URLs, increasing attack surface.",
                    resource=line.strip(),
                    remediation="Replace ADD with COPY for local files. Use curl/wget explicitly for URLs."
                )
        return None

    def _check_curl_pipe_bash(self, content, lines) -> Optional[Finding]:
        for line in lines:
            if re.search(r'curl.*\|.*sh|wget.*\|.*sh|curl.*\|.*bash', line, re.I):
                return Finding(
                    rule_id="DF005", severity=Severity.HIGH,
                    title="curl|bash pattern detected",
                    description="Piping curl output to shell is dangerous — allows code execution.",
                    resource=line.strip(),
                    remediation="Download, verify checksum, then execute separately."
                )
        return None

    def _check_no_healthcheck(self, content, lines) -> Optional[Finding]:
        if not any(l.strip().upper().startswith("HEALTHCHECK") for l in lines):
            return Finding(
                rule_id="DF006", severity=Severity.LOW,
                title="No HEALTHCHECK defined",
                description="Without a HEALTHCHECK, orchestrators cannot detect unhealthy containers.",
                resource="Dockerfile",
                remediation="Add: HEALTHCHECK --interval=30s CMD curl -f http://localhost/health || exit 1"
            )
        return None

    def _check_privileged(self, content, lines) -> Optional[Finding]:
        if re.search(r'--privileged', content, re.I):
            return Finding(
                rule_id="DF007", severity=Severity.CRITICAL,
                title="Privileged mode detected",
                description="--privileged grants all kernel capabilities, equivalent to root on host.",
                resource="Dockerfile",
                remediation="Remove --privileged. Use specific capabilities: --cap-add=NET_BIND_SERVICE"
            )
        return None

    def _check_secrets_in_run(self, content, lines) -> Optional[Finding]:
        for line in lines:
            if line.strip().upper().startswith("RUN "):
                if re.search(r'(password|secret|token|key)\s*=\s*\S+', line, re.I):
                    return Finding(
                        rule_id="DF008", severity=Severity.CRITICAL,
                        title="Secret embedded in RUN command",
                        description="Secrets in RUN commands persist in image layers.",
                        resource=line.strip()[:80],
                        remediation="Use BuildKit secret mounts: RUN --mount=type=secret,id=mykey"
                    )
        return None


class KubernetesManifestScanner:
    """Scans Kubernetes YAML manifests for security misconfigurations."""

    def scan(self, manifest: Dict, resource_name: str = "k8s-manifest") -> ScanResult:
        result = ScanResult(target=resource_name, scan_type="kubernetes")
        kind = manifest.get("kind", "")
        spec = manifest.get("spec", {})
        checks = [
            self._check_privileged_container,
            self._check_run_as_root,
            self._check_host_network,
            self._check_host_pid,
            self._check_resource_limits,
            self._check_read_only_root_fs,
            self._check_allow_privilege_escalation,
            self._check_network_policy,
        ]
        for check in checks:
            finding = check(manifest, kind, spec)
            if finding:
                result.findings.append(finding)
                result.failed_checks += 1
            else:
                result.passed_checks += 1
        return result

    def _get_containers(self, spec) -> List[Dict]:
        containers = []
        pod_spec = spec.get("template", {}).get("spec", spec)
        containers.extend(pod_spec.get("containers", []))
        containers.extend(pod_spec.get("initContainers", []))
        return containers

    def _check_privileged_container(self, manifest, kind, spec) -> Optional[Finding]:
        for c in self._get_containers(spec):
            sc = c.get("securityContext", {})
            if sc.get("privileged", False):
                return Finding(
                    rule_id="K8S001", severity=Severity.CRITICAL,
                    title=f"Container '{c.get('name')}' runs in privileged mode",
                    description="Privileged containers have full host system access.",
                    resource=c.get("name", "unknown"),
                    remediation="Set securityContext.privileged: false"
                )
        return None

    def _check_run_as_root(self, manifest, kind, spec) -> Optional[Finding]:
        pod_spec = spec.get("template", {}).get("spec", spec)
        pod_sc = pod_spec.get("securityContext", {})
        if not pod_sc.get("runAsNonRoot", False) and \
           pod_sc.get("runAsUser", 0) == 0:
            return Finding(
                rule_id="K8S002", severity=Severity.HIGH,
                title="Pod may run as root",
                description="runAsNonRoot is not set or runAsUser is 0.",
                resource=manifest.get("metadata", {}).get("name", "pod"),
                remediation="Set securityContext.runAsNonRoot: true and runAsUser: 1000"
            )
        return None

    def _check_host_network(self, manifest, kind, spec) -> Optional[Finding]:
        pod_spec = spec.get("template", {}).get("spec", spec)
        if pod_spec.get("hostNetwork", False):
            return Finding(
                rule_id="K8S003", severity=Severity.HIGH,
                title="Pod uses host network namespace",
                description="hostNetwork: true exposes the pod to the host network stack.",
                resource=manifest.get("metadata", {}).get("name", "pod"),
                remediation="Remove hostNetwork or set to false. Use proper Service/Ingress."
            )
        return None

    def _check_host_pid(self, manifest, kind, spec) -> Optional[Finding]:
        pod_spec = spec.get("template", {}).get("spec", spec)
        if pod_spec.get("hostPID", False):
            return Finding(
                rule_id="K8S004", severity=Severity.HIGH,
                title="Pod uses host PID namespace",
                description="hostPID: true allows the pod to see all host processes.",
                resource=manifest.get("metadata", {}).get("name", "pod"),
                remediation="Remove hostPID or set to false."
            )
        return None

    def _check_resource_limits(self, manifest, kind, spec) -> Optional[Finding]:
        for c in self._get_containers(spec):
            resources = c.get("resources", {})
            limits = resources.get("limits", {})
            if not limits.get("cpu") or not limits.get("memory"):
                return Finding(
                    rule_id="K8S005", severity=Severity.MEDIUM,
                    title=f"Container '{c.get('name')}' missing resource limits",
                    description="No CPU/memory limits allows resource exhaustion (DoS).",
                    resource=c.get("name", "unknown"),
                    remediation="Add resources.limits.cpu and resources.limits.memory"
                )
        return None

    def _check_read_only_root_fs(self, manifest, kind, spec) -> Optional[Finding]:
        for c in self._get_containers(spec):
            sc = c.get("securityContext", {})
            if not sc.get("readOnlyRootFilesystem", False):
                return Finding(
                    rule_id="K8S006", severity=Severity.MEDIUM,
                    title=f"Container '{c.get('name')}' has writable root filesystem",
                    description="Writable root filesystem allows attackers to modify container files.",
                    resource=c.get("name", "unknown"),
                    remediation="Set securityContext.readOnlyRootFilesystem: true"
                )
        return None

    def _check_allow_privilege_escalation(self, manifest, kind, spec) -> Optional[Finding]:
        for c in self._get_containers(spec):
            sc = c.get("securityContext", {})
            if sc.get("allowPrivilegeEscalation", True):
                return Finding(
                    rule_id="K8S007", severity=Severity.HIGH,
                    title=f"Container '{c.get('name')}' allows privilege escalation",
                    description="allowPrivilegeEscalation not set to false.",
                    resource=c.get("name", "unknown"),
                    remediation="Set securityContext.allowPrivilegeEscalation: false"
                )
        return None

    def _check_network_policy(self, manifest, kind, spec) -> Optional[Finding]:
        # Flag if this is a Deployment/StatefulSet with no mention of NetworkPolicy
        if kind in ("Deployment", "StatefulSet", "DaemonSet"):
            labels = manifest.get("metadata", {}).get("labels", {})
            # Simple heuristic: warn to check NetworkPolicy
            return Finding(
                rule_id="K8S008", severity=Severity.INFO,
                title=f"{kind} may lack NetworkPolicy",
                description="Verify a NetworkPolicy restricts ingress/egress for this workload.",
                resource=manifest.get("metadata", {}).get("name", kind),
                remediation="Create NetworkPolicy with explicit ingress/egress rules."
            )
        return None


class ContainerSecurityOrchestrator:
    """Orchestrates scanning of Dockerfiles and K8s manifests."""

    def __init__(self):
        self.dockerfile_scanner = DockerfileScanner()
        self.k8s_scanner = KubernetesManifestScanner()
        self.results: List[ScanResult] = []

    def scan_dockerfile(self, content: str, name: str = "Dockerfile") -> ScanResult:
        result = self.dockerfile_scanner.scan(content, name)
        self.results.append(result)
        return result

    def scan_k8s_manifest(self, manifest: Dict, name: str = "") -> ScanResult:
        name = name or manifest.get("metadata", {}).get("name", "unknown")
        result = self.k8s_scanner.scan(manifest, name)
        self.results.append(result)
        return result

    def report(self) -> Dict:
        total_critical = sum(
            sum(1 for f in r.findings if f.severity == Severity.CRITICAL)
            for r in self.results
        )
        return {
            "scans": len(self.results),
            "total_critical": total_critical,
            "results": [r.summary() for r in self.results],
            "compliance": "FAIL" if total_critical > 0 else "PASS",
        }


if __name__ == "__main__":
    orchestrator = ContainerSecurityOrchestrator()

    # Scan a vulnerable Dockerfile
