import json
import hashlib
import re
from dataclasses import dataclass, field
from typing import List, Dict, Optional, Callable
from enum import Enum
from datetime import datetime

class GateStatus(Enum):
    PASS = "PASS"
    FAIL = "FAIL"
    WARN = "WARN"
    SKIP = "SKIP"

class RiskLevel(Enum):
    CRITICAL = 4
    HIGH = 3
    MEDIUM = 2
    LOW = 1
    NONE = 0

@dataclass
class GateResult:
    gate_name: str
    stage: str
    status: GateStatus
    risk_level: RiskLevel
    score: float           # 0-100
    findings: List[str]
    blocked: bool
    duration_ms: int
    metadata: Dict = field(default_factory=dict)

@dataclass
class PipelineContext:
    repo: str
    branch: str
    commit_sha: str
    author: str
    changed_files: List[str]
    pr_title: str = ""
    environment: str = "staging"  # staging | production
    bypass_reason: Optional[str] = None


class SecurityGate:
    """Base class for a security gate check."""
    name: str = "base_gate"
    stage: str = "build"     # commit | build | test | deploy
    blocking: bool = True
    risk_threshold: RiskLevel = RiskLevel.HIGH

    def run(self, context: PipelineContext, artifacts: Dict) -> GateResult:
        raise NotImplementedError


class SecretScanGate(SecurityGate):
    name = "secret_scan"
    stage = "commit"
    blocking = True

    SECRET_PATTERNS = [
        (r'(?i)(aws_secret_access_key|aws_access_key_id)\s*=\s*[A-Za-z0-9/+=]{20,}', "AWS Credential"),
        (r'(?i)(github_token|gh_token)\s*=\s*ghp_[A-Za-z0-9]{36}', "GitHub Token"),
        (r'(?i)(password|passwd|pwd)\s*=\s*[^\s\'"]{8,}', "Hardcoded Password"),
        (r'(?i)(api_key|apikey|api-key)\s*=\s*[A-Za-z0-9_-]{16,}', "API Key"),
        (r'-----BEGIN (RSA|EC|OPENSSH) PRIVATE KEY-----', "Private Key"),
        (r'(?i)bearer\s+[A-Za-z0-9._-]{20,}', "Bearer Token"),
    ]

    def run(self, context: PipelineContext, artifacts: Dict) -> GateResult:
        import time; t = time.time()
        findings = []
        source_code = artifacts.get("source_code", {})
        for filepath, content in source_code.items():
            for pattern, label in self.SECRET_PATTERNS:
                matches = re.findall(pattern, content)
                if matches:
                    findings.append(f"[{label}] in {filepath}: {str(matches[0])[:40]}...")
        status = GateStatus.FAIL if findings else GateStatus.PASS
        risk = RiskLevel.CRITICAL if findings else RiskLevel.NONE
        return GateResult(
            gate_name=self.name, stage=self.stage, status=status,
            risk_level=risk, score=0.0 if findings else 100.0,
            findings=findings, blocked=bool(findings),
            duration_ms=int((time.time() - t) * 1000),
        )


class DependencyVulnerabilityGate(SecurityGate):
    name = "dependency_scan"
    stage = "build"
    blocking = True

    def run(self, context: PipelineContext, artifacts: Dict) -> GateResult:
        import time; t = time.time()
        findings = []
        dependencies = artifacts.get("dependencies", {})
        vuln_db = artifacts.get("vuln_db", {})  # CVE lookup: pkg -> [{cve, severity, fixed}]
        critical_count = 0
        high_count = 0
        for pkg, version in dependencies.items():
            vulns = vuln_db.get(pkg, [])
            for vuln in vulns:
                if self._version_affected(version, vuln.get("affected_versions", [])):
                    sev = vuln.get("severity", "MEDIUM")
                    cve = vuln.get("cve", "CVE-UNKNOWN")
                    fixed = vuln.get("fixed_in", "?")
                    findings.append(f"{cve} [{sev}] in {pkg}@{version} (fixed: {fixed})")
                    if sev == "CRITICAL": critical_count += 1
                    elif sev == "HIGH": high_count += 1
        blocked = critical_count > 0 or high_count > 2
        score = max(0, 100 - critical_count * 30 - high_count * 10)
        risk = (RiskLevel.CRITICAL if critical_count else
                RiskLevel.HIGH if high_count else
                RiskLevel.MEDIUM if findings else RiskLevel.NONE)
        return GateResult(
            gate_name=self.name, stage=self.stage,
            status=GateStatus.FAIL if blocked else (GateStatus.WARN if findings else GateStatus.PASS),
            risk_level=risk, score=score, findings=findings, blocked=blocked,
            duration_ms=int((time.time() - t) * 1000),
            metadata={"critical": critical_count, "high": high_count},
        )

    def _version_affected(self, version: str, affected: List[str]) -> bool:
        # Simplified: check if version string appears in affected list
        return any(version == v or version.startswith(v.rstrip('x').rstrip('.'))
                   for v in affected)


class SastGate(SecurityGate):
    """Static Application Security Testing gate."""
    name = "sast"
    stage = "build"
    blocking = True

    VULN_PATTERNS = {
        "SQL Injection": [
            r'(?i)execute\s*\(.*\+.*\)',
            r'(?i)cursor\.execute\([^%]*%\s*\(',
            r'(?i)raw_query\s*=\s*[f\'"]+.*\{',
        ],
        "XSS": [
            r'(?i)innerHTML\s*=\s*.*\+',
            r'(?i)document\.write\(',
        ],
        "Path Traversal": [
            r'(?i)open\(.*\+.*\)',
            r'(?i)os\.path\.join.*user_input',
        ],
        "Command Injection": [
            r'(?i)subprocess\.call.*shell=True.*\+',
            r'(?i)os\.system\(.*\+',
        ],
        "Insecure Deserialization": [
            r'(?i)pickle\.loads?\(.*user',
            r'(?i)yaml\.load\([^L]',
        ],
    }

    def run(self, context: PipelineContext, artifacts: Dict) -> GateResult:
        import time; t = time.time()
        findings = []
        source_code = artifacts.get("source_code", {})
        for filepath, content in source_code.items():
            if not any(filepath.endswith(ext) for ext in [".py", ".js", ".java"]):
                continue
            for vuln_type, patterns in self.VULN_PATTERNS.items():
                for pattern in patterns:
                    for match in re.finditer(pattern, content):
                        line = content[:match.start()].count('\n') + 1
                        findings.append(f"[{vuln_type}] {filepath}:{line}: {content[match.start():match.end()][:60]}")
        high_count = len(findings)
        blocked = high_count > 0
        score = max(0, 100 - high_count * 20)
        return GateResult(
            gate_name=self.name, stage=self.stage,
            status=GateStatus.FAIL if blocked else GateStatus.PASS,
            risk_level=RiskLevel.HIGH if high_count > 0 else RiskLevel.NONE,
            score=score, findings=findings, blocked=blocked,
            duration_ms=int((time.time() - t) * 1000),
        )


class IaCSecurityGate(SecurityGate):
    """Infrastructure as Code (Terraform/CloudFormation) security gate."""
    name = "iac_security"
    stage = "test"
    blocking = True

    def run(self, context: PipelineContext, artifacts: Dict) -> GateResult:
        import time; t = time.time()
        findings = []
        iac_configs = artifacts.get("iac_configs", {})
        for filename, content in iac_configs.items():
            if "0.0.0.0/0" in content and 'ingress' in content:
                findings.append(f"[CRITICAL] {filename}: Security group allows all inbound traffic (0.0.0.0/0)")
            if re.search(r'encrypted\s*=\s*false', content):
                findings.append(f"[HIGH] {filename}: Encryption disabled")
            if re.search(r'publicly_accessible\s*=\s*true', content):
                findings.append(f"[HIGH] {filename}: Resource publicly accessible")
            if re.search(r'skip_final_snapshot\s*=\s*true', content):
                findings.append(f"[MEDIUM] {filename}: DB final snapshot skipped")
            if re.search(r'deletion_protection\s*=\s*false', content):
                findings.append(f"[MEDIUM] {filename}: Deletion protection disabled")
        critical = sum(1 for f in findings if 'CRITICAL' in f)
        blocked = critical > 0 or len(findings) > 3
        score = max(0, 100 - critical * 30 - len(findings) * 10)
        return GateResult(
            gate_name=self.name, stage=self.stage,
            status=GateStatus.FAIL if blocked else (GateStatus.WARN if findings else GateStatus.PASS),
            risk_level=RiskLevel.CRITICAL if critical else (RiskLevel.HIGH if findings else RiskLevel.NONE),
            score=score, findings=findings, blocked=blocked,
            duration_ms=int((time.time() - t) * 1000),
        )


class ContainerScanGate(SecurityGate):
    name = "container_scan"
    stage = "test"
    blocking = True

    def run(self, context: PipelineContext, artifacts: Dict) -> GateResult:
        import time; t = time.time()
        findings = []
        image_info = artifacts.get("container_image", {})
        if image_info.get("base_image_tag") == "latest":
            findings.append("[MEDIUM] Base image uses 'latest' tag - not reproducible")
        if image_info.get("runs_as_root", True):
            findings.append("[HIGH] Container runs as root (no USER directive)")
        critical_cves = image_info.get("critical_cves", 0)
        high_cves = image_info.get("high_cves", 0)
        if critical_cves:
            findings.append(f"[CRITICAL] {critical_cves} CRITICAL CVEs in base image")
        if high_cves:
            findings.append(f"[HIGH] {high_cves} HIGH CVEs in base image")
        blocked = critical_cves > 0 or (image_info.get("runs_as_root", True) and context.environment == "production")
        score = max(0, 100 - critical_cves * 40 - high_cves * 10 - len(findings) * 5)
        return GateResult(
            gate_name=self.name, stage=self.stage,
            status=GateStatus.FAIL if blocked else (GateStatus.WARN if findings else GateStatus.PASS),
            risk_level=RiskLevel.CRITICAL if critical_cves else (RiskLevel.HIGH if high_cves else RiskLevel.MEDIUM),
            score=score, findings=findings, blocked=blocked,
            duration_ms=int((time.time() - t) * 1000),
        )


class DevSecOpsPipeline:
    """
    Orchestrates all security gates across CI/CD stages.
    Enforces risk thresholds and deployment decisions.
    """
    STAGES = ["commit", "build", "test", "deploy"]

    def __init__(self, environment: str = "staging"):
        self.gates: List[SecurityGate] = [
            SecretScanGate(),
            DependencyVulnerabilityGate(),
            SastGate(),
            IaCSecurityGate(),
            ContainerScanGate(),
        ]
        self.environment = environment
        self.results: List[GateResult] = []

    def run(self, context: PipelineContext, artifacts: Dict) -> Dict:
        self.results = []
        pipeline_blocked = False
        gate_by_stage = {stage: [] for stage in self.STAGES}
        for gate in self.gates:
            gate_by_stage[gate.stage].append(gate)
        for stage in self.STAGES:
            print(f"\n[STAGE: {stage.upper()}]")
            for gate in gate_by_stage[stage]:
                result = gate.run(context, artifacts)
                self.results.append(result)
                status_icon = {GateStatus.PASS: "✓", GateStatus.FAIL: "✗",
                               GateStatus.WARN: "⚠", GateStatus.SKIP: "-"}
                print(f"  {status_icon.get(result.status, '?')} {gate.name}: "
                      f"{result.status.value} (score: {result.score:.0f}) [{result.duration_ms}ms]")
                for f in result.findings[:3]:
                    print(f"    → {f}")
                if result.blocked and gate.blocking:
                    pipeline_blocked = True
                    print(f"  PIPELINE BLOCKED by {gate.name}")
        return self._decision(pipeline_blocked, context)

    def _decision(self, blocked: bool, context: PipelineContext) -> Dict:
        # Production deployments are stricter
        any_warn = any(r.status == GateStatus.WARN for r in self.results)
        overall_score = sum(r.score for r in self.results) / max(len(self.results), 1)
        decision = "BLOCKED" if blocked else (
            "CONDITIONAL" if any_warn else "APPROVED"
        )
        if context.environment == "production" and any_warn:
            decision = "BLOCKED"
        print(f"\n{'='*50}")
        print(f"DEPLOYMENT DECISION: {decision}")
        print(f"Overall Risk Score: {overall_score:.1f}/100")
        print(f"Environment: {context.environment}")
        return {
            "decision": decision,
            "overall_score": round(overall_score, 1),
            "blocked_by": [r.gate_name for r in self.results if r.blocked],
            "gate_results": [
                {"gate": r.gate_name, "status": r.status.value,
                 "score": r.score, "findings": len(r.findings)}
                for r in self.results
            ],
        }


