import numpy as np
from dataclasses import dataclass
from typing import List, Dict, Optional, Tuple
from collections import Counter
from enum import Enum

class AttackType(Enum):
    FGSM = 'FGSM'
    PGD = 'PGD'
    SQUARE = 'Square'
    UNKNOWN = 'Unknown'

@dataclass
class AMLDetection:
    is_adversarial: bool
    confidence: float
    attack_type: AttackType
    defense_applied: str
    evidence: List[str]


class PerturbationDetector:
    def __init__(self, threshold_linf: float = 0.1, threshold_l2: float = 2.0):
        self.threshold_linf = threshold_linf
        self.threshold_l2 = threshold_l2

    def stats(self, x: np.ndarray) -> Dict:
        flat = x.flatten()
        mean, std = float(np.mean(flat)), float(np.std(flat))
        kurtosis = float(np.mean(((flat - mean) / max(std, 1e-8)) ** 4)) - 3
        dx = np.diff(x if x.ndim == 2 else x.mean(axis=-1), axis=1)
        dy = np.diff(x if x.ndim == 2 else x.mean(axis=-1), axis=0) if x.ndim >= 2 else dx
        return {'mean': mean, 'std': std, 'kurtosis': kurtosis,
                'hf_energy': float(np.mean(dx**2) + np.mean(dy**2))}

    def detect(self, x: np.ndarray, x_clean: Optional[np.ndarray] = None,
                baseline: Optional[Dict] = None) -> Tuple[bool, float, List[str]]:
        evidence = []
        if x_clean is not None:
            linf = float(np.max(np.abs(x - x_clean)))
            l2 = float(np.linalg.norm(x - x_clean))
            if linf > self.threshold_linf: evidence.append(f'L-inf {linf:.3f} > {self.threshold_linf}')
            if l2 > self.threshold_l2: evidence.append(f'L2 {l2:.2f} > {self.threshold_l2}')
        s = self.stats(x)
        if baseline:
            if abs(s['std'] - baseline.get('std', 0.3)) > 0.15:
                evidence.append(f'Std anomaly: {s["std"]:.3f} vs {baseline["std"]:.3f}')
            ratio = s['hf_energy'] / max(baseline.get('hf_energy', 0.01), 1e-8)
            if ratio > 3.0: evidence.append(f'High-freq energy {ratio:.1f}x baseline')
        if abs(s['kurtosis']) > 5.0: evidence.append(f'Kurtosis {s["kurtosis"]:.1f}')
        if not evidence: return False, 0.1, []
        conf = min(0.99, 0.5 + 0.1 * len(evidence))
        return True, conf, evidence


class InputDefense:
    def bit_depth_reduce(self, x: np.ndarray, bits: int = 4) -> np.ndarray:
        levels = 2 ** bits
        return np.round(x * levels) / levels

    def smooth(self, x: np.ndarray) -> np.ndarray:
        k = np.ones((3, 3)) / 9.0
        if x.ndim == 3:
            return np.stack([self._conv2d(x[:,:,c], k) for c in range(x.shape[2])], axis=2)
        return self._conv2d(x, k)

    def _conv2d(self, x: np.ndarray, k: np.ndarray) -> np.ndarray:
        h, w, kh, kw = x.shape[0], x.shape[1], k.shape[0], k.shape[1]
        p = np.pad(x, ((kh//2, kh//2), (kw//2, kw//2)), mode='reflect')
        r = np.zeros_like(x)
        for i in range(h):
            for j in range(w):
                r[i, j] = np.sum(p[i:i+kh, j:j+kw] * k)
        return r

    def feature_squeeze(self, x: np.ndarray) -> np.ndarray:
        return self.smooth(self.bit_depth_reduce(x))


class AdversarialSimulator:
    def fgsm(self, x: np.ndarray, eps: float = 0.03) -> np.ndarray:
        return np.clip(x + np.sign(np.random.randn(*x.shape)) * eps, 0, 1)

    def pgd(self, x: np.ndarray, eps: float = 0.03, alpha: float = 0.007, steps: int = 10) -> np.ndarray:
        xa = x.copy()
        for _ in range(steps):
            xa = np.clip(xa + np.sign(np.random.randn(*x.shape)) * alpha, x - eps, x + eps)
            xa = np.clip(xa, 0, 1)
        return xa

    def square(self, x: np.ndarray, eps: float = 0.05, q: int = 20) -> np.ndarray:
        xa = x.copy()
        h, w = x.shape[:2]
        for _ in range(q // 4):
            s = max(2, int(eps * min(h, w) * 5))
            i, j = np.random.randint(0, h-s), np.random.randint(0, w-s)
            xa[i:i+s, j:j+s] = np.clip(xa[i:i+s, j:j+s] + np.random.choice([-eps, eps]), 0, 1)
        return xa


class AdversarialDefenseSystem:
    def __init__(self):
        self.detector = PerturbationDetector()
        self.defense = InputDefense()
        self.simulator = AdversarialSimulator()
        self._baseline: Optional[Dict] = None

    def calibrate(self, clean_samples: List[np.ndarray]):
        all_stats = [self.detector.stats(x) for x in clean_samples]
        self._baseline = {k: float(np.mean([s[k] for s in all_stats])) for k in all_stats[0]}
        print(f'[DEFENSE] Calibrated: std={self._baseline["std"]:.3f}, hf={self._baseline["hf_energy"]:.4f}')

    def process(self, x: np.ndarray, classify_fn=None) -> Dict:
        is_adv, conf, evidence = self.detector.detect(x, baseline=self._baseline)
        if is_adv:
            x_def = self.defense.feature_squeeze(x)
            attack_type = AttackType.FGSM if conf > 0.85 else AttackType.PGD if conf > 0.7 else AttackType.SQUARE
            print(f'[DEFENSE] ADV detected ({conf:.0%}) -> {attack_type.value} | Applied: feature_squeeze')
        else:
            x_def = x
            attack_type = AttackType.UNKNOWN
        label = classify_fn(x_def) if classify_fn else 'unknown'
        return {'label': label, 'is_adversarial': is_adv, 'confidence': round(conf, 3),
                'attack_type': attack_type.value, 'evidence': evidence[:3]}

    def evaluate(self, clean_samples: List[np.ndarray], attack_fn, n: int = 20) -> Dict:
        self.calibrate(clean_samples)
        fp = sum(1 for x in clean_samples[:n] if self.detector.detect(x, baseline=self._baseline)[0])
        tp = sum(1 for x in clean_samples[:n]
                 if self.detector.detect(attack_fn(x), x_clean=x, baseline=self._baseline)[0])
        tpr, fpr = tp/n, fp/n
        return {'detection_rate': round(tpr, 3), 'false_positive_rate': round(fpr, 3),
                'f1': round(2*tpr*(1-fpr)/max(tpr+(1-fpr), 1e-8), 3), 'n': n}


if __name__ == '__main__':
    np.random.seed(42)
    sys = AdversarialDefenseSystem()
    sim = AdversarialSimulator()
    clean = [np.random.uniform(0.2, 0.8, (28, 28)) for _ in range(30)]
    sys.calibrate(clean)
    model = lambda x: 'malware' if np.mean(x) > 0.5 else 'benign'
    for name, x_adv in [('FGSM', sim.fgsm(clean[0], 0.05)),
                         ('PGD', sim.pgd(clean[0], 0.03, steps=10)),
                         ('Square', sim.square(clean[0], 0.05))]:
        r = sys.process(x_adv, model)
        print(f'{name}: label={r["label"]} adversarial={r["is_adversarial"]} ({r["attack_type"]})')
    ev = sys.evaluate(clean, lambda x: sim.fgsm(x, 0.05))
    print(f"\nEval: DR={ev['detection_rate']:.0%} FPR={ev['false_positive_rate']:.0%} F1={ev['f1']:.3f}")
