def _make_finding(rule: 'CSPMRule', resource: Dict, resource_id_key: str,
                   desc_extra: str = '', is_public: bool = False) -> CSPMFinding:
    rid = resource.get(resource_id_key, 'unknown')
    return CSPMFinding(
        finding_id=f'CSPM-{rule.rule_id}-{rid[:20]}',
        rule_id=rule.rule_id, title=rule.title,
        severity=rule.severity, resource_type=rule.resource_type,
        resource_id=rid, resource_arn=resource.get('arn', ''),
        region=resource.get('region', 'unknown'),
        description=f'{rule.description}. {desc_extra}'.strip(),
        remediation=rule.remediation,
        compliance=rule.compliance,
        risk_score=_risk_score(rule.severity, is_public),
        is_public=is_public,
    )


def _risk_score(severity: Severity, is_public: bool) -> float:
    base = {Severity.CRITICAL: 90, Severity.HIGH: 70,
            Severity.MEDIUM: 45, Severity.LOW: 20, Severity.INFO: 5}
    score = base[severity]
    if is_public: score = min(100, score + 15)
    return float(score)


def check_s3_public_access(resource: Dict, rule: CSPMRule) -> Optional[CSPMFinding]:
    if not resource.get('block_public_access') or resource.get('acl') == 'public-read':
        is_pub = resource.get('acl') == 'public-read'
        return _make_finding(rule, resource, 'name',
                              f'ACL={resource.get("acl")}, block_public={resource.get("block_public_access")}',
                              is_public=is_pub)
    return None

def check_s3_encryption(resource: Dict, rule: CSPMRule) -> Optional[CSPMFinding]:
    if not resource.get('encryption'):
        return _make_finding(rule, resource, 'name', 'No default encryption configured')
    return None

def check_s3_logging(resource: Dict, rule: CSPMRule) -> Optional[CSPMFinding]:
    if not resource.get('logging'):
        return _make_finding(rule, resource, 'name', 'Access logging disabled')
    return None

def check_sg_ssh_open(resource: Dict, rule: CSPMRule) -> Optional[CSPMFinding]:
    for rule_ingress in resource.get('ingress_rules', []):
        if rule_ingress.get('port') == 22 and rule_ingress.get('cidr') in ('0.0.0.0/0', '::/0'):
            return _make_finding(rule, resource, 'group_id',
                                  'SSH (22) open to 0.0.0.0/0', is_public=True)
