}


class CSPMScanner:
    def scan(self, resources: Dict) -> Dict:
        findings = []
        for res_type, res_list in resources.items():
            rules = RESOURCE_RULE_MAP.get(res_type, [])
            for resource in res_list:
                for rule in rules:
                    finding = rule.check_fn(resource, rule)
                    if finding:
                        findings.append(finding)
        findings.sort(key=lambda f: -f.risk_score)
        compliance_violations = defaultdict(list)
        for f in findings:
            for c in f.compliance:
                compliance_violations[c].append(f.finding_id)
        return {
            'total_findings': len(findings),
            'by_severity': {
                sev.name: sum(1 for f in findings if f.severity == sev)
                for sev in Severity if sev != Severity.INFO
            },
            'compliance_violations': dict(compliance_violations),
            'public_exposures': sum(1 for f in findings if f.is_public),
            'findings': [
                {'id': f.finding_id, 'severity': f.severity.name,
                 'resource': f'{f.resource_type}/{f.resource_id}',
                 'title': f.title, 'risk_score': f.risk_score,
                 'remediation': f.remediation, 'compliance': f.compliance}
                for f in findings
            ],
        }


