import json
import re
from dataclasses import dataclass, field
from typing import List, Dict, Optional, Any, Callable
from datetime import datetime, timedelta
from enum import Enum
from collections import defaultdict

class DataSource(Enum):
    SYSLOG = 'syslog'
    NETFLOW = 'netflow'
    EDR = 'edr'
    DNS = 'dns'
    PROXY = 'proxy'
    AUTH = 'auth'
    CLOUD_TRAIL = 'cloudtrail'

@dataclass
class QueryResult:
    query_id: str
    query: str
    executed_at: str
    duration_ms: float
    total_rows: int
    returned_rows: int
    columns: List[str]
    rows: List[Dict]
    data_sources_queried: List[str]
    errors: List[str] = field(default_factory=list)

@dataclass
class TelemetryEvent:
    event_id: str
    source: DataSource
    timestamp: datetime
    host: str
    user: Optional[str]
    event_type: str
    data: Dict[str, Any]


class InMemorySecurityDataLake:
    """
    In-memory security data lake with SQL-like query capabilities.
    Supports filtering, aggregation, joins, and time-windowed queries
    over heterogeneous security telemetry.
    """
    def __init__(self):
        self._tables: Dict[str, List[Dict]] = defaultdict(list)
        self._schema: Dict[str, List[str]] = {}
        self._query_counter = 0

    def ingest(self, source: DataSource, events: List[Dict]):
        table = source.value
        if table not in self._tables:
            self._tables[table] = []
            if events:
                self._schema[table] = list(events[0].keys())
        self._tables[table].extend(events)

    def ingest_event(self, event: TelemetryEvent):
        record = {'event_id': event.event_id, 'timestamp': event.timestamp.isoformat(),
                  'host': event.host, 'user': event.user or '',
                  'event_type': event.event_type, **event.data}
        self.ingest(event.source, [record])

    def query(self, dsl: Dict) -> QueryResult:
        """Execute a structured query DSL against the data lake."""
        import time
        start = time.time()
        self._query_counter += 1
        qid = f'Q-{self._query_counter:06d}'
        errors = []
        try:
            rows = self._execute(dsl, errors)
        except Exception as e:
            rows = []
            errors.append(str(e))
        duration = (time.time() - start) * 1000
        limit = dsl.get('limit', 100)
        columns = list(rows[0].keys()) if rows else dsl.get('select', ['*'])
        return QueryResult(
            query_id=qid, query=json.dumps(dsl),
            executed_at=datetime.utcnow().isoformat(),
            duration_ms=round(duration, 2),
            total_rows=len(rows),
            returned_rows=min(len(rows), limit),
            columns=columns,
            rows=rows[:limit],
            data_sources_queried=dsl.get('from', []) if isinstance(dsl.get('from'), list)
                                  else [dsl.get('from', '')],
            errors=errors,
        )

    def _execute(self, dsl: Dict, errors: List) -> List[Dict]:
        # FROM: which tables
        sources = dsl.get('from', [])
        if isinstance(sources, str):
            sources = [sources]
        # Load rows
        rows = []
        for src in sources:
            src_rows = self._tables.get(src, [])
            for row in src_rows:
                rows.append({'_source': src, **row})
        # TIME FILTER
        if 'time_window' in dsl:
            rows = self._filter_time(rows, dsl['time_window'])
        # WHERE
        if 'where' in dsl:
            rows = self._filter_where(rows, dsl['where'])
        # GROUP BY + aggregate
        if 'group_by' in dsl and 'aggregate' in dsl:
            rows = self._group_aggregate(rows, dsl['group_by'], dsl['aggregate'])
        # HAVING (post-aggregation filter)
        if 'having' in dsl:
            rows = self._filter_where(rows, dsl['having'])
        # ORDER BY
        if 'order_by' in dsl:
            col, direction = dsl['order_by'].get('column', ''), dsl['order_by'].get('direction', 'asc')
            rows.sort(key=lambda r: r.get(col, ''), reverse=(direction == 'desc'))
        # SELECT projection
        if 'select' in dsl and dsl['select'] != ['*']:
            rows = [{k: r.get(k) for k in dsl['select']} for r in rows]
        return rows

    def _filter_time(self, rows: List[Dict], window: Dict) -> List[Dict]:
        start_str = window.get('start')
        end_str = window.get('end')
        last_n = window.get('last_minutes')
        if last_n:
            cutoff = datetime.utcnow() - timedelta(minutes=last_n)
            start_str = cutoff.isoformat()
        result = []
        for row in rows:
            ts_str = row.get('timestamp', '')
            if not ts_str:
                result.append(row)
                continue
            try:
                ts = datetime.fromisoformat(ts_str)
                if start_str and ts < datetime.fromisoformat(start_str):
                    continue
                if end_str and ts > datetime.fromisoformat(end_str):
                    continue
                result.append(row)
            except ValueError:
                result.append(row)
        return result

    def _filter_where(self, rows: List[Dict], conditions: List[Dict]) -> List[Dict]:
        result = []
        for row in rows:
            if all(self._eval_condition(row, cond) for cond in conditions):
                result.append(row)
        return result

    def _eval_condition(self, row: Dict, cond: Dict) -> bool:
        field_name = cond.get('field', '')
        op = cond.get('op', '==')
        value = cond.get('value')
        row_val = row.get(field_name)
        if row_val is None:
            return False
        if op == '==' or op == '=':
            return str(row_val).lower() == str(value).lower()
        elif op == '!=':
            return str(row_val).lower() != str(value).lower()
        elif op == '>':
            return float(row_val) > float(value)
        elif op == '>=':
            return float(row_val) >= float(value)
        elif op == '<':
            return float(row_val) < float(value)
        elif op == '<=':
            return float(row_val) <= float(value)
        elif op == 'contains':
            return str(value).lower() in str(row_val).lower()
        elif op == 'startswith':
            return str(row_val).lower().startswith(str(value).lower())
        elif op == 'regex':
            return bool(re.search(str(value), str(row_val), re.IGNORECASE))
        elif op == 'in':
            return str(row_val).lower() in [str(v).lower() for v in (value or [])]
        return False

    def _group_aggregate(self, rows: List[Dict], group_by: List[str],
                          aggregates: List[Dict]) -> List[Dict]:
        groups: Dict[tuple, List[Dict]] = defaultdict(list)
        for row in rows:
            key = tuple(row.get(g, '') for g in group_by)
            groups[key].append(row)
        result = []
        for key, group_rows in groups.items():
            record = {g: k for g, k in zip(group_by, key)}
            for agg in aggregates:
                agg_fn = agg.get('fn', 'count')
                agg_field = agg.get('field', '')
                agg_alias = agg.get('alias', f'{agg_fn}_{agg_field}')
                vals = [row.get(agg_field) for row in group_rows if row.get(agg_field) is not None]
                if agg_fn == 'count':
                    record[agg_alias] = len(group_rows)
                elif agg_fn == 'count_distinct':
                    record[agg_alias] = len(set(str(v) for v in vals))
                elif agg_fn == 'sum' and vals:
                    record[agg_alias] = sum(float(v) for v in vals)
                elif agg_fn == 'avg' and vals:
                    record[agg_alias] = sum(float(v) for v in vals) / len(vals)
                elif agg_fn == 'max' and vals:
                    record[agg_alias] = max(vals)
                elif agg_fn == 'min' and vals:
                    record[agg_alias] = min(vals)
                elif agg_fn == 'collect':
                    record[agg_alias] = list(set(str(v) for v in vals))[:20]
                else:
                    record[agg_alias] = 0
            result.append(record)
        return result

    def describe(self) -> Dict:
        return {
            'tables': {t: {'rows': len(rows), 'columns': self._schema.get(t, [])}
                       for t, rows in self._tables.items()}
        }


class ThreatHuntingQueryLibrary:
