class PlaybookStepType(Enum):
    ENRICH = 'enrich'
    CONTAIN = 'contain'
    INVESTIGATE = 'investigate'
    NOTIFY = 'notify'
    REMEDIATE = 'remediate'
    CONDITIONAL = 'conditional'

class StepStatus(Enum):
    PENDING = 'pending'
    RUNNING = 'running'
    SUCCESS = 'success'
    FAILED = 'failed'
    SKIPPED = 'skipped'

class IncidentStatus(Enum):
    OPEN = 'open'
    IN_PROGRESS = 'in_progress'
    CONTAINED = 'contained'
    RESOLVED = 'resolved'
    CLOSED = 'closed'

@dataclass
class PlaybookStep:
    step_id: str
    name: str
    step_type: PlaybookStepType
    action: str          # action identifier
    params: Dict         # action parameters
    on_success: Optional[str] = None    # next step_id
    on_failure: Optional[str] = None    # fallback step_id
    timeout_sec: int = 30
    condition: Optional[Dict] = None    # {field, op, value}
    required: bool = True

@dataclass
class PlaybookExecution:
    execution_id: str
    playbook_name: str
    incident_id: str
    started_at: str
    completed_at: Optional[str]
    status: IncidentStatus
    steps_executed: List[Dict]
    context: Dict       # shared context populated during execution
    total_actions: int = 0
    failed_actions: int = 0

@dataclass
class Incident:
    incident_id: str
    title: str
    severity: str
    source: str
    affected_hosts: List[str]
    affected_users: List[str]
    iocs: List[str]
    status: IncidentStatus = IncidentStatus.OPEN
    created_at: str = ''
