    def __init__(self):
        self._actions: Dict[str, Callable] = {}
        self._register_defaults()

    def register(self, name: str, fn: Callable):
        self._actions[name] = fn

    def execute(self, action: str, params: Dict, context: Dict) -> Dict:
        if action not in self._actions:
            return {'success': False, 'error': f'Unknown action: {action}', 'data': {}}
        try:
            result = self._actions[action](params, context)
            return {'success': True, 'error': None, 'data': result}
        except Exception as e:
            return {'success': False, 'error': str(e), 'data': {}}

    def _register_defaults(self):
        self._actions.update({
            'threat_intel_lookup': self._threat_intel_lookup,
            'block_ip_firewall': self._block_ip,
            'block_domain_dns': self._block_domain,
            'isolate_host_edr': self._isolate_host,
            'disable_user_account': self._disable_user,
            'force_password_reset': self._force_password_reset,
            'collect_memory_dump': self._collect_memory,
            'quarantine_file': self._quarantine_file,
            'send_slack_alert': self._notify_slack,
            'create_jira_ticket': self._create_ticket,
            'run_yara_scan': self._yara_scan,
            'check_vuln_scanner': self._check_vuln,
            'revoke_sessions': self._revoke_sessions,
        })

