class SOARPlaybookExecutor:
    def __init__(self):
        self.registry = SOARActionRegistry()
        self._executions: Dict[str, PlaybookExecution] = {}
        self._exec_counter = 0

    def execute_playbook(self, playbook_name: str, incident: Incident) -> PlaybookExecution:
        steps = PLAYBOOK_REGISTRY.get(playbook_name, [])
        if not steps:
            raise ValueError(f'Unknown playbook: {playbook_name}')
        self._exec_counter += 1
        exec_id = f'EXEC-{self._exec_counter:06d}'
        ctx = {
            'incident_id': incident.incident_id,
            'affected_hosts': incident.affected_hosts,
            'affected_users': incident.affected_users,
            'attacker_ip': next((i for i in incident.iocs if re.match(r'^\d+\.\d+\.', i)), ''),
            'c2_domain': next((i for i in incident.iocs if '.' in i and not re.match(r'^\d', i)), ''),
            'malware_hash': next((i for i in incident.iocs if len(i) in (32, 64)), ''),
            'primary_ioc': incident.iocs[0] if incident.iocs else '',
            'incident_summary': f'{incident.severity} incident: {incident.title}',
        }
        execution = PlaybookExecution(
            execution_id=exec_id, playbook_name=playbook_name,
            incident_id=incident.incident_id,
            started_at=datetime.utcnow().isoformat(),
            completed_at=None, status=IncidentStatus.IN_PROGRESS,
            steps_executed=[], context=ctx,
        )
        self._executions[exec_id] = execution
        incident.status = IncidentStatus.IN_PROGRESS
        incident.playbook_executions.append(exec_id)
        # Build step index
        step_index = {s.step_id: s for s in steps}
        current_id = steps[0].step_id if steps else None
        while current_id and current_id in step_index:
            step = step_index[current_id]
            start = time.time()
            print(f'  [{step.step_type.value.upper()}] {step.name}...')
            result = self.registry.execute(step.action, step.params, ctx)
            duration = round((time.time() - start) * 1000, 1)
            status = StepStatus.SUCCESS if result['success'] else StepStatus.FAILED
            execution.total_actions += 1
            if not result['success']:
                execution.failed_actions += 1
            # Merge result data into context
            if result['success'] and result.get('data'):
                ctx.update({f'{step.step_id}_{k}': v for k, v in result['data'].items()})
            execution.steps_executed.append({
                'step_id': step.step_id,
                'name': step.name,
                'type': step.step_type.value,
                'status': status.value,
                'result': result['data'] if result['success'] else {'error': result['error']},
                'duration_ms': duration,
            })
            incident.timeline.append({
                'timestamp': datetime.utcnow().isoformat(),
                'event': f'{step.name}: {status.value}',
            })
            # Next step
            if result['success']:
                current_id = step.on_success
            else:
                current_id = step.on_failure
                if step.required and not step.on_failure:
                    print(f'  CRITICAL: Required step {step.step_id} failed - aborting')
                    break
        execution.completed_at = datetime.utcnow().isoformat()
        execution.status = (IncidentStatus.CONTAINED if execution.failed_actions == 0
                             else IncidentStatus.IN_PROGRESS)
        incident.status = execution.status
        return execution

    def get_execution_report(self, exec_id: str) -> Dict:
        exc = self._executions.get(exec_id)
        if not exc: return {'error': 'Not found'}
        return {
            'execution_id': exec_id, 'playbook': exc.playbook_name,
            'incident': exc.incident_id, 'status': exc.status.value,
            'started': exc.started_at, 'completed': exc.completed_at,
            'total_steps': exc.total_actions, 'failed_steps': exc.failed_actions,
            'success_rate': round((exc.total_actions - exc.failed_actions) / max(exc.total_actions, 1), 2),
            'steps': exc.steps_executed,
        }


